-- Poems batch 115
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ba55139b-a72b-4415-86e3-ef47e8e30cc0','江樓吹笛飲酒大醉中作','陸游','宋','宋诗','song-poetry','','[]','世言九州外，復言大九州。',140,'全唐诗/poet.song.128000.json','["世言九州外，復言大九州。", "此言果不虛，僅可容吾愁。", "許愁亦當有許酒，吾酒釀盡銀河流。", "酌之萬斛玻瓈舟，酣宴五城十二樓。", "天爲碧羅幕，月作白玉鈎。", "織女織慶雲，裁成五色裘。", "披裘對酒難爲客，長揖北辰相獻酬。", "一飲五百年，一醉三千秋。", "却駕白鳯驂斑虬，下與麻姑戲玄洲。", "錦江吹笛餘一念，再過劍南應小留。"]'),
('90ebd67e-999f-467d-a14b-a029e258dfa5','晚登子城','陸游','宋','宋诗','song-poetry','','[]','江頭作雪雪未成，北風吹雲如有營。',160,'全唐诗/poet.song.128000.json','["江頭作雪雪未成，北風吹雲如有營。", "驅車出門何所詣，一放吾目登高城。", "城中繁雄十萬户，朱門甲第何崢嶸。", "錦機玉工不知數，深夜窮巷聞吹笙。", "國家自從失河北，烟塵漠漠暗兩京。", "胡行如鬼南至海，寸地尺天皆苦兵。", "老吳將軍獨護蜀，坐使井絡無欃槍。", "名都壯邑數千里，至今不聞戎馬聲。", "安危自古有倚仗，相持黙黙非敵情。", "棘門覇上勿兒戲，犬羊豈憚渝齊盟。"]'),
('ef371b24-884e-4237-ae0a-508d94ced226','夙興出謁','陸游','宋','宋诗','song-poetry','','[]','嗜酒狂無敵，居家懶有餘。',48,'全唐诗/poet.song.128000.json','["嗜酒狂無敵，居家懶有餘。", "苦寒愁手版，美睡付肩輿。", "覔句吟哦慣，逢人省識疏。", "亦知歸去好，無地著蝸廬。"]'),
('4a79e27f-5273-4c1f-85b0-4fa455fd649f','十一月三日過升仙橋作三首  其一','陸游','宋','宋诗','song-poetry','','[]','早過升仙不暇炊，橋邊買餅療朝饑。',32,'全唐诗/poet.song.128000.json','["早過升仙不暇炊，橋邊買餅療朝饑。", "紛紜滿座誰能識，大似新豐獨酌時。"]'),
('260055fc-a816-44da-9a2f-aba8947e9144','十一月三日過升仙橋作三首  其二','陸游','宋','宋诗','song-poetry','','[]','熨手金鞭天馬駒，冰河雪谷笑談無。',32,'全唐诗/poet.song.128000.json','["熨手金鞭天馬駒，冰河雪谷笑談無。", "只言燕趙多奇士，豈必書生盡腐儒。"]'),
('f0d4e926-6cbd-4ae5-a8a2-ae2fef2c4951','十一月三日過升仙橋作三首  其三','陸游','宋','宋诗','song-poetry','','[]','橋邊沙水緑蒲老，原上烟蕪黄犢閑。',32,'全唐诗/poet.song.128000.json','["橋邊沙水緑蒲老，原上烟蕪黄犢閑。", "老子真成興不淺，憑鞍歸夢遶家山。"]'),
('698149b9-701c-409b-8620-ec9b94eb062c','遣興','陸游','宋','宋诗','song-poetry','','[]','蓬壺舊隱已微茫，浪迹紅塵樂未央。',64,'全唐诗/poet.song.128000.json','["蓬壺舊隱已微茫，浪迹紅塵樂未央。", "縱酒山南千日醉，看花劍外十年狂。", "新詩刻燭驚詞客，駿馬追風戲鞠塲。", "要是世間男子事，不宜臺省競飛翔。"]'),
('ee2e3332-5bd8-49b8-a3b4-1261608f3017','草堂拜少陵遺像','陸游','宋','宋诗','song-poetry','','[]','清江抱孤村，杜子昔所館。',96,'全唐诗/poet.song.128000.json','["清江抱孤村，杜子昔所館。", "虛堂塵不掃，小徑門可欵。", "公詩豈紙上，遺句處處滿。", "人皆欲拾取，志大才苦短。", "計公客此時，一飽得亦罕。", "阨窮端有自，寜獨坐房琯。", "至今壁間像，朱綬意蕭散。", "長安貂蟬多，死去誰復算。"]'),
('1115b63a-a832-4d7b-8a0c-32a79a5aa838','青羊宮小飲贈道士','陸游','宋','宋诗','song-poetry','','[]','青羊道士竹爲家，也種玄都觀裏花。',64,'全唐诗/poet.song.128000.json','["青羊道士竹爲家，也種玄都觀裏花。", "微雨晴時看鶴舞，小窗幽處聽蜂衙。", "藥罏宿火熒熒暖，醉袖迎風獵獵斜。", "老我一官真漫浪，會來分子淡生涯。"]'),
('e7d32856-4cc3-47c1-890a-15274d1f5351','夜寒二首  其一','陸游','宋','宋诗','song-poetry','','[]','清夜焚香讀楚詞，寒侵貂褐嘆吾衰。',32,'全唐诗/poet.song.128000.json','["清夜焚香讀楚詞，寒侵貂褐嘆吾衰。", "輕冰滿研風聲急，忽記山陰夜雪時。"]'),
('3d15ec99-51ca-4353-8168-c2fee15b2118','夜寒二首  其二','陸游','宋','宋诗','song-poetry','','[]','斗帳重茵香霧重，膏梁那可共功名。',32,'全唐诗/poet.song.128000.json','["斗帳重茵香霧重，膏梁那可共功名。", "三更騎報河冰合，鐵馬何人從我行。"]'),
('30f5eddd-5db8-4d63-9456-5656e5b2f642','書懷','陸游','宋','宋诗','song-poetry','','[]','武擔山上望京都，誰記黄公舊酒壚。',64,'全唐诗/poet.song.128000.json','["武擔山上望京都，誰記黄公舊酒壚。", "宿負本宜輸左校，寛恩猶聽補東隅。", "一官漫浪行将老，萬卷縱横只自愚。", "甫里松陵在何許，古人投劾爲蓴鱸。"]'),
('456f4389-cf49-4c29-989a-bb42ccfbef01','記夢二首  其一','陸游','宋','宋诗','song-poetry','','[]','烏巾白紵憶當年，抵死尋春不自憐。',32,'全唐诗/poet.song.128000.json','["烏巾白紵憶當年，抵死尋春不自憐。", "憔悴劍南雙鬢改，夢中猶上暗門船。"]'),
('2dcd72e0-7a77-45b2-9023-1acb552c0f67','記夢二首  其二','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','團臍霜蠏四腮鱸，樽俎芳鮮十載無。',32,'全唐诗/poet.song.128000.json','["團臍霜蠏四腮鱸，樽俎芳鮮十載無。", "塞月征塵身萬里，夢魂也復醉西湖。"]'),
('e9b27f88-9f3e-4bbe-9d1b-66ea10879a10','醉中出西門偶書','陸游','宋','宋诗','song-poetry','','[]','古寺閑房閉寂寥，幾年躭酒負公朝。',64,'全唐诗/poet.song.128000.json','["古寺閑房閉寂寥，幾年躭酒負公朝。", "青山是處可埋骨，白髮向人羞折腰。", "末路自悲終老蜀，少年常願從征遼。", "醉來挾箭西郊去，極目寒蕪雉兔驕。"]'),
('845ac292-2686-4abc-b913-e9fdae059704','訪客不遇','陸游','宋','宋诗','song-poetry','','[]','風急斜吹帽，泥深亂濺衣。',48,'全唐诗/poet.song.128000.json','["風急斜吹帽，泥深亂濺衣。", "杜門常畏罵，訪客却空歸。", "老馬舉蹄懶，枯槐無葉飛。", "馳驅幾時了，散髮憶苔磯。"]'),
('04a3b798-2ed1-4bbb-a7fc-07d01afd2ef2','劍客行','陸游','宋','宋诗','song-poetry','','[]','世無知劍人，太阿混凡鐵。',144,'全唐诗/poet.song.128000.json','["世無知劍人，太阿混凡鐵。", "至寶棄泥沙，光景終不滅。", "一朝斬長鯨，海水赤三月。", "隠見天地間，變化豈易測。", "國家未滅冦，臣子同此責。", "浪迹潜山海，歲晚得劍客。", "酒酣脫匕首，白刅明霜雪。", "夜半報讐歸，斑斑腥带血。", "細讐何足問，大恥同憤切。", "臣位雖卑賤，臣身可屠裂。", "誓當函胡首，再拜奏北闕。", "逃去變姓名，山中餐玉屑。"]'),
('7ad6a59b-9e06-4e16-bdfa-c9dc5430cc7d','故蜀别苑在成都西南十五六里梅至多有兩大樹夭矯若龍相傳謂之梅龍予初至蜀嘗爲作詩自此歲常訪之今復賦一首丁酉十一月也','陸游','宋','宋诗','song-poetry','','[]','昔年曾賦西郊梅，茫茫去日如飛埃。',160,'全唐诗/poet.song.128000.json','["昔年曾賦西郊梅，茫茫去日如飛埃。", "即今衰病百事懶，陳迹未忘猶一來。", "蜀王故苑犁已遍，散落尚有千雪堆。", "珠樓玉殿一夢破，烟蕪牧笛遺民哀。", "兩龍卧穩不飛去，鱗甲脫落生莓苔。", "精神最遇雪月見，氣力苦戰冰霜開。", "羈臣放士耿獨立，淑姬靜女知誰媒。", "摧傷雖多意愈厲，直與天地爭春囬。", "蒼然老氣壓桃杏，笑我白髮心尚孩。", "微風故爲作嫵媚，一片吹入黄金罍。"]'),
('14045fac-4388-4b9d-8445-1d9d4ed1820e','閑意','陸游','宋','宋诗','song-poetry','','[]','柴門雖設不曾開，爲怕人行損緑苔。',64,'全唐诗/poet.song.128000.json','["柴門雖設不曾開，爲怕人行損緑苔。", "妍日漸催春意動，好風時捲市聲來。", "學經妻問生疏字，嘗酒兒斟瀲灧杯。", "安得小園寛半畆，黄梅緑李一時栽。"]'),
('4c0a1cd3-2479-4e4b-841c-b83ebc0a7bf5','飲罷夜歸','陸游','宋','宋诗','song-poetry','','[]','老病畏多酌，退閑愁夜行。',48,'全唐诗/poet.song.128000.json','["老病畏多酌，退閑愁夜行。", "市燈踈欲盡，樓月澹初生。", "露冷莎蛩咽，天寒塞雁征。", "歸來差自喜，擁被聴疏更。"]'),
('29f65b5c-a347-42b8-aa86-70a6e576d411','江亭冬望','陸游','宋','宋诗','song-poetry','','[]','霜落江清水見魚，偶然徙倚草堂孤。',64,'全唐诗/poet.song.128000.json','["霜落江清水見魚，偶然徙倚草堂孤。", "雪天黯淡常如晚，烟樹微茫直欲無。", "下澤乘車終碌碌，上方請劍漫區區。", "擬将疏逸消豪氣，尋罷酒徒尋獵徒。"]'),
('311e0a61-6c68-428e-9116-6f775871cc9f','大風登城','陸游','宋','宋诗','song-poetry','','[]','風從北來不可當，街中横笛人馬僵。',96,'全唐诗/poet.song.128000.json','["風從北來不可當，街中横笛人馬僵。", "西家女兒午未粧，帳底爐紅愁下床。", "東家喚客宴畫堂，兩行玉指調絲簧。", "錦繡四合如垣墻，微風不動金猊香。", "我獨登城望大荒，勇欲爲國平河湟。", "才踈志大不自量，西家東家笑我狂。"]'),
('c00f30ea-1158-4a5d-810a-a9f54e93c25d','書雨','陸游','宋','宋诗','song-poetry','','[]','仲冬候始寒，丙夜天正黑。',96,'全唐诗/poet.song.128000.json','["仲冬候始寒，丙夜天正黑。", "雨來挾風助，吼擊不遺力。", "聲如拔高山，勢若伐強國。", "初憂老柏折，遂恐石筍踣。", "乾坤本無心，百神各効職。", "蛟龍鬭歲暮，豪横理莫測。", "農功幸已成，龍怒亦會息。", "屋漏何足言，袖手姑默默。"]'),
('38efacb7-617f-42ad-b044-1df3818bcba3','一笑','陸游','宋','宋诗','song-poetry','','[]','半醉微吟不怕寒，江邊一笑覺天寛。',64,'全唐诗/poet.song.128000.json','["半醉微吟不怕寒，江邊一笑覺天寛。", "莫愁艇子急衝雨，何遜梅花頻倚闌。", "萬事任從皮外去，百年聊作夢中觀。", "放翁縱老狂猶在，倒盡金壺燭未殘。"]'),
('9b458575-9cb9-412f-997b-658c4fd6d67e','歲晚懷鏡湖舊隱慨然有作','陸游','宋','宋诗','song-poetry','','[]','公府還家鬢未秋，鏡湖南畔決歸休。',64,'全唐诗/poet.song.128000.json','["公府還家鬢未秋，鏡湖南畔決歸休。", "讀書精舍豈輕出，采藥名山成遠遊。", "白墮興來猶小醉，青精才足又何求。", "俗間毁譽惟堪笑，常隘韓公咎斗牛。"]'),
('961939a1-1486-4a30-9e33-b34d7c7127d0','華髮','陸游','宋','宋诗','song-poetry','','[]','華髮蕭蕭老蜀關，倦飛可笑不知還。',64,'全唐诗/poet.song.128000.json','["華髮蕭蕭老蜀關，倦飛可笑不知還。", "人生只似駒過隙，世事莫驚雷破山。", "光景半銷樽酒裏，英豪或隱博徒間。", "車帷閉置真何樂，書劍飄然未厭閑。"]'),
('6dfdcf6b-3c1f-4f9f-b323-69c2e50aeb76','嘆息','陸游','宋','宋诗','song-poetry','','[]','國家圖籙合中興，嘆息吾寜粥飯僧。',64,'全唐诗/poet.song.128000.json','["國家圖籙合中興，嘆息吾寜粥飯僧。", "賣劍買牛衰可笑，壊裳爲袴老猶能。", "曉過射圃雲藏壘，夜讀兵書雨灑燈。", "安得龍媒八千騎，要令窮冦畏飛騰。"]'),
('86843d48-c271-4988-a065-96b246db86ae','冬至','陸游','宋','宋诗','song-poetry','','[]','歲月難禁節物催，天涯回首意悲哀。',64,'全唐诗/poet.song.128000.json','["歲月難禁節物催，天涯回首意悲哀。", "十年人向三巴老，一夜陽從九地來。", "上馬出門愁斂版，還家留客强傳杯。", "探春漫道江梅早，盤裏酥花又鬭開。"]'),
('23699ab8-3129-42cd-bd42-612bc8b3b76a','城南尋梅得絕句四首  其一','陸游','宋','宋诗','song-poetry','','[]','老子今年懶賦詩，風光料理鬢成絲。',32,'全唐诗/poet.song.128000.json','["老子今年懶賦詩，風光料理鬢成絲。", "青羊宮裏春來早，初見梅花第一枝。"]'),
('0dfa5052-eaf6-4be6-9687-d67af685f5b6','城南尋梅得絕句四首  其二','陸游','宋','宋诗','song-poetry','','[]','黯淡江天雪欲飛，竹籬數掩傍苔磯。',32,'全唐诗/poet.song.128000.json','["黯淡江天雪欲飛，竹籬數掩傍苔磯。", "清愁滿眼無人說，折得梅花作伴歸。"]'),
('3afdc8ba-aceb-4057-a48c-d5cc0195f401','城南尋梅得絕句四首  其三','陸游','宋','宋诗','song-poetry','','[]','青烟漠漠暗西村，問訊梅花置一尊。',32,'全唐诗/poet.song.128000.json','["青烟漠漠暗西村，問訊梅花置一尊。", "冷淡生涯元不惡，却嫌歌吹合江園。"]'),
('003377c9-c0d7-4b00-a64d-45611e29b182','城南尋梅得絕句四首  其四','陸游','宋','宋诗','song-poetry','','[]','籬邊細路竹間庵，一段風流擅劍南。',32,'全唐诗/poet.song.128000.json','["籬邊細路竹間庵，一段風流擅劍南。", "吾國以香爲佛事，客來試向鼻端參。"]'),
('e682d4d0-5114-4fd9-8866-98f8fa86ad96','書嘆','陸游','宋','宋诗','song-poetry','','[]','曆盡危塗井與參，鬢毛飽受雪霜侵。',64,'全唐诗/poet.song.128000.json','["曆盡危塗井與參，鬢毛飽受雪霜侵。", "平生不可俗子眼，後世誰知吾輩心。", "河洛方行胡正朔，山林虛度醉光陰。", "浩歌未闋先投枕，衰病常憂感慨深。"]'),
('cb11e076-3fce-4685-831a-a23b50f15aa3','感興二首  其一','陸游','宋','宋诗','song-poetry','','[]','少小遇喪亂，妄意憂元元。',120,'全唐诗/poet.song.128000.json','["少小遇喪亂，妄意憂元元。", "忍饑卧空山，著書十萬言。", "賊亮負函貸，江北烟塵昏。", "奏記本兵府，大事得具論。", "請治故臣罪，深絕衰亂根。", "言疏卒見棄，袂有血泪痕。", "爾來十五年，殘虜尚遊魂。", "遺民痛胥溺，何由雪煩寃。", "我髮日益白，病骸寜久存。", "常恐先狗馬，不見清中原。"]'),
('65261011-2613-48b3-94ba-5300ca7e02f7','感興二首  其二','陸游','宋','宋诗','song-poetry','','[]','高帝王蜀漢，天下豈易圖。',120,'全唐诗/poet.song.128000.json','["高帝王蜀漢，天下豈易圖。", "幡然用其鋒，項羽不支梧。", "嗟余昔從戎，久戍南鄭墟。", "登高望夕烽，只尺咸陽都。", "群胡本無政，剽奪常自如。", "民窮訴蒼天，日夜思來蘇。", "連年況枯旱，關輔尤空虛。", "安得節制帥，弓刀肅馳驅。", "父老上牛酒，善意不可孤。", "諸将能辦此，機會無時無。"]'),
('c72efa2f-d7f3-41c3-9dae-877152250232','暮冬夜宴','陸游','宋','宋诗','song-poetry','','[]','官機錦茵金蹙鳯，舞娃釵墮雙鬟重。',96,'全唐诗/poet.song.128000.json','["官機錦茵金蹙鳯，舞娃釵墮雙鬟重。", "寶爐三尺香吐霧，畫燭如椽風不動。", "主人愛客情無已，箏聲未斷歌聲起。", "亦知百歲等朝露，便恐一歡成覆水。", "爐紅酒緑春爲回，坐上梅花連夜開。", "堂前只尺異氣候，冰合平池霜壓階。"]'),
('412c4d42-11da-478f-abb4-7d2ca43556ff','枕上','陸游','宋','宋诗','song-poetry','','[]','枕上三更雨，天涯萬里遊。',48,'全唐诗/poet.song.128000.json','["枕上三更雨，天涯萬里遊。", "蟲聲憎好夢，燈影伴孤愁。", "報國計安出，滅胡心未休。", "明年起飛將，更試北平秋。"]'),
('f006a9cf-76cf-41bb-bd4b-86ca16fac63e','謁石犀廟','陸游','宋','宋诗','song-poetry','','[]','閑過石犀祠，登堂一嘆欷。',48,'全唐诗/poet.song.128000.json','["閑過石犀祠，登堂一嘆欷。", "江回陵谷變，碑斷市朝非。", "荒圃連寒壟，斜陽映夕霏。", "興亡俱昨夢，惆悵跨驢歸。"]'),
('735bd53a-6ae9-4e1f-ad41-fcae554fb72f','江上散步尋梅偶得三絕句  其一','陸游','宋','宋诗','song-poetry','','[]','小園風月不多寛，一樹梅花開未殘。',32,'全唐诗/poet.song.128000.json','["小園風月不多寛，一樹梅花開未殘。", "剥啄敲門嫌特地，緩拖藤杖隔籬看。"]'),
('17b404e0-55ea-4a49-84a5-358f80c14056','江上散步尋梅偶得三絕句  其二','陸游','宋','宋诗','song-poetry','','[]','鐘殘小院欲銷魂，漠漠幽香伴月痕。',32,'全唐诗/poet.song.128000.json','["鐘殘小院欲銷魂，漠漠幽香伴月痕。", "江上人家應勝此，明朝更出小南門。"]'),
('a6257c73-fb14-448f-9510-2f6c1d80e096','江上散步尋梅偶得三絕句  其三','陸游','宋','宋诗','song-poetry','','[]','小南門外野人家，短短踈籬繚白沙。',32,'全唐诗/poet.song.128000.json','["小南門外野人家，短短踈籬繚白沙。", "紅稻不須鸚鵡啄，清霜催放兩三花。"]'),
('3ecd1512-6082-444d-b580-71849287db94','漣漪亭賞梅','陸游','宋','宋诗','song-poetry','','[]','判爲梅花倒玉巵，故山幽夢憶疏籬。',64,'全唐诗/poet.song.128000.json','["判爲梅花倒玉巵，故山幽夢憶疏籬。", "寫真妙絕横窗影，徹骨清寒蘸水枝。", "苦節雪中逢漢使，高標澤畔見湘纍。", "詩成怯爲花拈出，萬斛塵襟我自知。"]'),
('1f010322-f314-4eca-ae5c-b790df5106c3','芳華樓賞梅','陸游','宋','宋诗','song-poetry','','[]','素娥竊藥不奔月，化作江梅寄幽絕。',128,'全唐诗/poet.song.128000.json','["素娥竊藥不奔月，化作江梅寄幽絕。", "天工丹粉不敢施，雪洗風吹見真色。", "出籬藏塢香細細，臨水隔烟情脉脉。", "一春花信二十四，縱有此香無此格。", "放翁年來百事墮，唯見梅花愁欲破。", "金壺倒置春滿屋，寶髻斜簪光照坐。", "百榼淋漓玉斚飛，萬人辟易銀鞍過。", "不惟豪横壓清癯，聊爲詩人洗寒餓。"]'),
('a8b74505-4804-4bad-a0a8-4bb8c56a9875','浣花賞梅','陸游','宋','宋诗','song-poetry','','[]','老子人間自在身，插梅不惜損烏巾。',64,'全唐诗/poet.song.128000.json','["老子人間自在身，插梅不惜損烏巾。", "春回積雪層冰裏，香動荒山野水濱。", "带月一枝低弄影，背風千片遠隨人。", "石家樓上貪吹笛，肯放朝朝玉樹新。"]'),
('fa4f4e82-3149-448f-83a7-a40467a9d902','蜀院賞梅','陸游','宋','宋诗','song-poetry','','[]','十里温香撲馬來，江頭還見去年梅。',64,'全唐诗/poet.song.128000.json','["十里温香撲馬來，江頭還見去年梅。", "喜開剩欲邀明月，愁落先教掃緑苔。", "跌宕放翁新醉墨，凄凉廢苑舊歌臺。", "盛衰自古無窮事，莫向昆明嘆劫灰。"]'),
('31979de0-59b0-40ec-84e5-ba49779a71a0','大醉梅花下走筆賦此','陸游','宋','宋诗','song-poetry','','[]','閉門坐嘆息，不飲輒千日。',144,'全唐诗/poet.song.128000.json','["閉門坐嘆息，不飲輒千日。", "忽然酒興生，一醉須一石。", "檐頭花易老，旗亭酒常窄。", "出郊索一笑，放浪謝形役。", "把酒梅花下，不覺日既夕。", "花香襲襟袂，歌聲上空碧。", "我亦落烏巾，倚樹吹玉笛。", "人間奇事少，頗謂三勍敵。", "酒闌江月上，珠樹挂寒壁。", "便疑從此僊，朝市長掃迹。", "醉歸亂一水，頓與異境隔。", "終當騎梅龍，海上看春色。"]'),
('d85ecb66-971e-4130-b32d-22266670b8c6','之廣都憩鐵像院','陸游','宋','宋诗','song-poetry','','[]','歲暮天苦寒，風雨復乘之。',120,'全唐诗/poet.song.128000.json','["歲暮天苦寒，風雨復乘之。", "道邊得古寺，欣然具晨炊。", "瘦樹立中庭，斷蔓絡短籬。", "小僧爲設爐，童子燒槁枝。", "坐令手足柔，髭間失冰澌。", "敬禮龕中像，盡讀廡下碑。", "少年志四方，故里了不思。", "晚知行路難，更覺遊子悲。", "一官始巴僰，剡曲歸何時。", "置之勿復道，爛醉忘天涯。"]'),
('c2fc89a2-cff8-4025-a6a5-eee542378508','廣都江上作','陸游','宋','宋诗','song-poetry','','[]','微波不揺江，纎雲不行天。',72,'全唐诗/poet.song.128000.json','["微波不揺江，纎雲不行天。", "我來倚杖立，天水相澄鮮。", "平遠望不盡，日落自生烟。", "梅花耿獨立，雪樹明前川。", "好風吹我衣，春色已粲然。", "東村聞酒美，買醉上漁船。"]'),
('1a3e54ea-1823-4bdf-ab47-d0f10acf367d','宿龍華山中寂然無一人方丈前梅花盛開月下獨觀至中夜','陸游','宋','宋诗','song-poetry','','[]','梅花如高人，枯槁道愈尊。',96,'全唐诗/poet.song.128000.json','["梅花如高人，枯槁道愈尊。", "君看在空谷，豈比倚市門。", "我來整冠佩，潔齋三沐熏。", "亦思醉其下，燕媠恐凟君。", "敬抱緑綺琴，玄酒挹古罇。", "月明流水間，一洗世濁昏。", "摸冩香與影，計君已厭聞。", "老我少傑思，尚喜非陳言。"]'),
('d6d4f177-e903-46e0-9b52-d6bcd4af78d2','次韵張季長正字梅花','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倚橋臨水似催詩，戲伴鵝黄上柳絲。',64,'全唐诗/poet.song.128000.json','["倚橋臨水似催詩，戲伴鵝黄上柳絲。", "萬里西湖驚斷夢，二年東閣憶幽期。", "揷瓶直欲連全樹，簪帽憑誰揀好枝。", "一味凄凉君勿嘆，平生初不願春知。"]'),
('a78573a6-f71a-4813-9bcc-0ee4c26c3253','次韵季長見示','陸游','宋','宋诗','song-poetry','','[]','倚遍南樓十二欄，長歌相屬寓悲歡。',64,'全唐诗/poet.song.128000.json','["倚遍南樓十二欄，長歌相屬寓悲歡。", "空懷鐵馬横戈意，未試冰河墮指寒。", "成敗極知無定勢，是非元自要徐觀。", "中原阻絕王師老，那敢山林一枕安。"]'),
('b64b4ca7-8b1c-4d1c-9712-cffd1a70cbce','廣都道中呈季長','陸游','宋','宋诗','song-poetry','','[]','天上石渠郎，能來伴楚狂。',48,'全唐诗/poet.song.128000.json','["天上石渠郎，能來伴楚狂。", "風霜朝竝轡，燈火夜連床。", "江水不勝緑，梅花無賴香。", "劇談那得住，出處要平章。"]'),
('1819c90b-ce69-475e-8286-4003f81561c9','看梅歸馬上戲作五首  其一','陸游','宋','宋诗','song-poetry','','[]','平明南出笮橋門，走馬歸來趁未昏。',32,'全唐诗/poet.song.128000.json','["平明南出笮橋門，走馬歸來趁未昏。", "漸老更知閑有味，一冬强半在梅村。"]'),
('3511b379-cc1a-4f48-8754-d7d1792a5478','看梅歸馬上戲作五首  其二','陸游','宋','宋诗','song-poetry','','[]','本爲梅花判痛飲，却嗅梅香消宿酲。',32,'全唐诗/poet.song.128000.json','["本爲梅花判痛飲，却嗅梅香消宿酲。", "日欲落時始上馬，青羊宮前聞發更。"]'),
('a31f0a29-377b-4ccb-8a08-f06f19183789','看梅歸馬上戲作五首  其三','陸游','宋','宋诗','song-poetry','','[]','一點不雜桃李春，一水隔斷車馬塵。',32,'全唐诗/poet.song.128000.json','["一點不雜桃李春，一水隔斷車馬塵。", "恨不來爲清夜飲，月中香露濕烏巾。"]'),
('ad741f6a-09a2-471a-8d23-68bedd1d7737','看梅歸馬上戲作五首  其四','陸游','宋','宋诗','song-poetry','','[]','江路疏籬已過清，月中霜冷若爲情。',32,'全唐诗/poet.song.128000.json','["江路疏籬已過清，月中霜冷若爲情。", "不如折向金壺貯，畫燭銀燈看到明。"]'),
('17ecb765-f7a4-4a8a-a5c2-cb75725602ed','看梅歸馬上戲作五首  其五','陸游','宋','宋诗','song-poetry','','[]','江郊車馬滿斜暉，爭趁南城未闔扉。',32,'全唐诗/poet.song.128000.json','["江郊車馬滿斜暉，爭趁南城未闔扉。", "要識梅花無盡藏，人人襟袖带香歸。"]'),
('c79fab9b-f153-4aaf-b5f0-504982d64638','别後寄季長','陸游','宋','宋诗','song-poetry','','[]','俗子俗到骨，一揖已溷人。',144,'全唐诗/poet.song.128000.json','["俗子俗到骨，一揖已溷人。", "不知此曹面，何處得許塵。", "我非作崖塹，汝自不可親。", "道途逢使君，令我生精神。", "頓增江山麗，更覺風月新。", "對床得晤語，傾倒夜達晨。", "亟起忘縛絝，小醉或墮巾。", "繚出錦城南，問訊江梅春。", "煎茶憩野店，喚船截烟津。", "凄凉吊廢苑，蕭散誇閑身。", "暮歸度略彴，月出水鱗鱗。", "思君去已遠，此會何由頻。"]'),
('50761aec-247b-40ce-8e9a-f379929dfc1b','中夜對月小酌','陸游','宋','宋诗','song-poetry','','[]','今夕復何夕，素月流清輝。',84,'全唐诗/poet.song.128000.json','["今夕復何夕，素月流清輝。", "徘徊入我堂，化作白玉墀。", "栖鳥滿高樹，空庭結烟霏。", "可憐如許景，早眠人不知。", "我幸與周旋，一醉那得辭。", "整我接羅巾，斟我翡翠巵。", "清愁不可耐，三嗅梅花枝。"]'),
('c301b3d3-900a-4e96-9168-fb6034fca64d','客愁','陸游','宋','宋诗','song-poetry','','[]','騎馬出門無所詣，端居正爾客愁侵。',64,'全唐诗/poet.song.128000.json','["騎馬出門無所詣，端居正爾客愁侵。", "蒼顔白髮入衰境，黄卷青燈空苦心。", "天下極知須雋傑，書生何恨死山林。", "消磨未盡胸中事，梁甫時時尚一吟。"]'),
('b731dcda-764f-4eb9-8ce8-cbd84a957433','詩酒','陸游','宋','宋诗','song-poetry','','[]','酒隠凌晨醉，詩狂徹旦歌。',48,'全唐诗/poet.song.128000.json','["酒隠凌晨醉，詩狂徹旦歌。", "憫憐蝸左角，嘲笑螘南柯。", "風月隨長笛，江湖入短蓑。", "平生會心處，最向漆園多。"]'),
('4a3f5146-9974-49b5-be9c-721fb657041a','道室夜意','陸游','宋','宋诗','song-poetry','','[]','寒泉潄酒醒，午夜誦仙經。',48,'全唐诗/poet.song.128000.json','["寒泉潄酒醒，午夜誦仙經。", "茶鼎聲號蚓，香盤火度螢。", "齋心守玄牝，閉目得黄寜。", "寄語山中友，因人送茯苓。"]'),
('9cfc7fbf-bb95-4ad3-9a2d-9b54266a14ba','道室晨起','陸游','宋','宋诗','song-poetry','','[]','紙帳晨光透，山爐宿火燃。',48,'全唐诗/poet.song.128000.json','["紙帳晨光透，山爐宿火燃。", "雞鳴猶喔喔，鴉起已翩翩。", "形槁寒巖木，心凝古澗泉。", "何須更臨鏡，斷是一癯僊。"]'),
('9172f583-5b00-4d16-9188-0c541265423c','城南王氏荘尋梅','陸游','宋','宋诗','song-poetry','','[]','涸池積槁葉，茆屋圍疏籬。',72,'全唐诗/poet.song.128000.json','["涸池積槁葉，茆屋圍疏籬。", "可憐庭中梅，開盡無人知。", "寂莫終自香，孤貞見幽姿。", "雪點滿緑苔，零落尚爾奇。", "我來不須晴，微雨正相宜。", "臨風兩愁絕，日暮倚笻枝。"]'),
('1a0cb27b-08e2-4aad-8f54-129f328f4fc2','遊萬里橋南劉氏小園','陸游','宋','宋诗','song-poetry','','[]','佳園寂無人，滿地梅花香。',96,'全唐诗/poet.song.128000.json','["佳園寂無人，滿地梅花香。", "閑來曳拄杖，臘月日已長。", "朱橋架江面，欄影揺波光。", "奇哉小垂虹，夢破鱸魚鄉。", "汀鷺一點白，烟柳千絲黄。", "便欲喚釣舟，散髮歌滄浪。", "可憐隔岸人，車馬日夜忙。", "我歸門復掩，寂曆挂斜陽。"]'),
('bdcd62dc-a36a-4b6a-8e30-41782bade884','過筰橋道中龍祠小留','陸游','宋','宋诗','song-poetry','','[]','江邊龍廟何年作，白浪花中插朱閣。',64,'全唐诗/poet.song.128000.json','["江邊龍廟何年作，白浪花中插朱閣。", "朝暾漸上宿霧收，春氣已動晨霜薄。", "我來倚欄一悵然，蘆花滿空如柳綿。", "安得身爲雙白鷺，飛上灘頭却飛去。"]'),
('c90f6a26-71d0-4eb7-8e6a-1b5aa784c16b','道上見梅花','陸游','宋','宋诗','song-poetry','','[]','載酒房湖風日美，探梅喜折一枝新。',32,'全唐诗/poet.song.128000.json','["載酒房湖風日美，探梅喜折一枝新。", "今朝忽向街頭見，萬蕚千跗俗却春。"]'),
('df39d93d-1a5b-4fc5-8e79-bb6202b001c3','倚樓','陸游','宋','宋诗','song-poetry','','[]','減盡朱顔白髮新，高樓徙倚黙傷神。',64,'全唐诗/poet.song.128000.json','["減盡朱顔白髮新，高樓徙倚黙傷神。", "未酬馬上功名願，已是人間老大身。", "太史周南方卧疾，拾遺劍外又逢春。", "一杯且爲江山助，百萬呼盧迹已陳。"]'),
('df42d0ad-abac-4b94-99e9-72e070b0f8d6','寄王季夷','陸游','宋','宋诗','song-poetry','','[]','平生吾子最知心，巴隴飄零歲月侵。',64,'全唐诗/poet.song.128000.json','["平生吾子最知心，巴隴飄零歲月侵。", "萬里喜聞身尚健，五更惟有夢相尋。", "插花意氣狂如昨，中酒情懷病至今。", "共約暮年須强飯，天台廬阜要登臨。"]'),
('24609708-1353-4215-b2a7-878ae3b6f631','丁酉除夕','陸游','宋','宋诗','song-poetry','','[]','浮生過五十，光景如飛鴻。',96,'全唐诗/poet.song.128000.json','["浮生過五十，光景如飛鴻。", "寒暑俛仰間，四序忽已終。", "殊方感飄泊，晚境嗟龍鍾。", "桃符與爆竹，懶復隨兒童。", "不寐非守歲，燕坐夜過中。", "氣定神自凝，海日何瞳曨。", "豈惟三彭逃，坐覺六入空。", "徂年勿惆悵，閲世方無窮。"]'),
('a870de8b-e7b1-4c35-be10-009b0d66798e','正月二日晨出大東門是日府公宴移忠院','陸游','宋','宋诗','song-poetry','','[]','成都春事早，開歲已暄妍。',48,'全唐诗/poet.song.128000.json','["成都春事早，開歲已暄妍。", "藍尾傳杯後，遨頭出郭前。", "爭門金騕褭，滿野繡輜軿。", "白髮花邊醉，何妨似少年。"]'),
('5ff6498e-7420-4c58-99fc-e7b5fe70dd4f','小飲落梅下戲作送梅一首','陸游','宋','宋诗','song-poetry','','[]','零落梅花不自由，斷腸容易付東流。',64,'全唐诗/poet.song.128000.json','["零落梅花不自由，斷腸容易付東流。", "與人又作經年别，問月應知此夜愁。", "已是狂風卷平野，更禁横笛起危樓。", "何時小雪山陰路，處處尋香繫釣舟。"]'),
('e677e4c8-9489-4aa1-ac77-00304cb3a9c2','立春','陸游','宋','宋诗','song-poetry','','[]','鬢毛蕭颯寸心灰，生怕新年節物催。',32,'全唐诗/poet.song.128000.json','["鬢毛蕭颯寸心灰，生怕新年節物催。", "幸是身閑朝睡美，忽聞鼓吹打春回。"]'),
('7cd693ad-1858-4932-bcbe-783571398192','初春出遊戲作','陸游','宋','宋诗','song-poetry','','[]','緑窗百舌喚春眠，問柳尋花意已便。',64,'全唐诗/poet.song.128000.json','["緑窗百舌喚春眠，問柳尋花意已便。", "京洛化衣無夢去，邯鄲觀伎有詩傳。", "銅壺閣下閑欹帽，石鏡坊前戲墜鞭。", "酒隠人間君勿誚，定勝山澤作臞僊。"]'),
('44627a8f-6904-4e92-8126-6e8692d768b6','初春遣興三首  其一','陸游','宋','宋诗','song-poetry','','[]','爛熟思來怕熱官，退飛心地喜輕安。',64,'全唐诗/poet.song.128000.json','["爛熟思來怕熱官，退飛心地喜輕安。", "捨魚正可取熊掌，食肉何須知馬肝。", "放眼柳梢初暗動，褪花梅子已微酸。", "典衣剩作江頭醉，莫謂天涯苦鮮歡。"]'),
('d778a7b0-5187-4001-a0ce-e0f4b8b8cf13','初春遣興三首  其二','陸游','宋','宋诗','song-poetry','','[]','大隱悠悠未棄官，俸錢雖薄却心安。',64,'全唐诗/poet.song.128000.json','["大隱悠悠未棄官，俸錢雖薄却心安。", "人方得意矜蝸角，天豈使予爲鼠肝。", "佳日劇棋忘旅恨，短衣馳射壓儒酸。", "小桃楊柳爭時節，載酒江頭罄一歡。"]'),
('d5f0870f-aba5-4f84-82b8-dbbd84723713','初春遣興三首  其三','陸游','宋','宋诗','song-poetry','','[]','白髮凄凉故史官，十年身不到長安。',64,'全唐诗/poet.song.128000.json','["白髮凄凉故史官，十年身不到長安。", "即今天末吊形影，何日上前傾肺肝。", "孤憤書成詞激烈，五噫歌罷意辛酸。", "此懷欲說無人共，安得相擕素所歡。"]'),
('7e64e558-c540-409b-a435-02710158bf1a','予年十六始識葉晦叔於西湖上後二十七年晦叔之弟聲叔來爲臨卭守相遇於成都晦叔沒久矣訪其遺文略無在者乃賦此詩','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故人零落久山丘，誰記京華第一流。',64,'全唐诗/poet.song.128000.json','["故人零落久山丘，誰記京華第一流。", "曹霸揮毫空萬馬，庖丁投刃解千牛。", "相逢夢境何勞記，追想清言未免愁。", "雷電取将遺稿盡，他年虛有茂陵求。"]'),
('775112ef-ba97-4f13-8f56-cef7f6bee7d2','初春探花有作','陸游','宋','宋诗','song-poetry','','[]','燈山昨夢嘆匆匆，便恐新春過眼空。',64,'全唐诗/poet.song.128000.json','["燈山昨夢嘆匆匆，便恐新春過眼空。", "千縷未揺官柳緑，一梢初放海棠紅。", "金羈絡馬閑遊處，彩筆題詩半醉中。", "流落天涯何足道，年年常策探花功。"]'),
('6ab55f96-fbd0-493a-8371-cc5a7b8a2908','遊諸葛武侯書臺','陸游','宋','宋诗','song-poetry','','[]','沔陽道中草離離，卧龍往矣空遺祠。',96,'全唐诗/poet.song.128000.json','["沔陽道中草離離，卧龍往矣空遺祠。", "當時典午稱猾賊，氣喪不敢當王師。", "定軍山前寒食路，至今人祠丞相墓。", "松風想像梁甫吟，尚憶幡然答三顧。", "出師一表千載無，遠比管樂蓋有餘。", "世上俗儒寜辦此，高堂當日讀何書。"]'),
('4bbe635e-028f-4405-87f4-183715861f0b','觀花','陸游','宋','宋诗','song-poetry','','[]','我遊西川醉千塲，萬花成圍柳著行。',96,'全唐诗/poet.song.128000.json','["我遊西川醉千塲，萬花成圍柳著行。", "紅錦地衣舞霓裳，翠裙繡袂天寶粧。", "清歌一發無留觴，嫋嫋餘聲縈杏梁。", "黄金絡馬照路光，自護羃䍦觀海棠。", "搜奇選勝日夜忙，不惟燕宮碧雞坊。", "暮歸奚奴負錦囊，路人爭看放翁狂。"]'),
('f7ae44ec-45b0-44ae-942c-9ef33fb73ab0','張園觀海棠','陸游','宋','宋诗','song-poetry','','[]','朝陽照城樓，春容極明媚。',96,'全唐诗/poet.song.128000.json','["朝陽照城樓，春容極明媚。", "走馬蜀錦園，名花動人意。", "嚴粧漢宮曉，一笑初破睡。", "定知夜宴歡，酒入妖骨醉。", "低鬟羞不語，困眼嬌欲閉。", "雖豔無俗姿，太息真富貴。", "結束吾方歸，此别知幾歲。", "黄昏亷纎雨，千點裛紅泪。"]'),
('24448f1a-08d9-4314-99db-8b7cba53b7c7','月夕','陸游','宋','宋诗','song-poetry','','[]','醉從東郭歸，散髮臨前楹。',72,'全唐诗/poet.song.128000.json','["醉從東郭歸，散髮臨前楹。", "呼僮淨掃地，勿使黦月明。", "庭空卧松影，簷逈送鐸聲。", "鐘斷心境寂，露下毛髮清。", "出門碧霧合，九陌無人行。", "坐令錦官城，化作白玉京。"]'),
('b74d7b9f-94f6-41b7-82b0-9628ea4055ae','夜飲即事','陸游','宋','宋诗','song-poetry','','[]','天涯久客我何堪，聊喜燈前得縱談。',64,'全唐诗/poet.song.128000.json','["天涯久客我何堪，聊喜燈前得縱談。", "磊落金盤薦糖蟹，纎柔玉指破霜柑。", "燭圍寶馬人将起，花墜紗巾酒正酣。", "更作茶甌清絕夢，小窗横幅畫江南。"]'),
('bce27921-74b0-4c46-9de1-a6408464ce34','夜宴賞海棠醉書','陸游','宋','宋诗','song-poetry','','[]','便便癡腹本來寛，不是天涯强作歡。',64,'全唐诗/poet.song.128000.json','["便便癡腹本來寛，不是天涯强作歡。", "燕子來時新社雨，海棠開後却春寒。", "醉誇落紙詩千首，歌費纒頭錦百端。", "深院不聞傳夜漏，忽驚蠟泪已堆盤。"]'),
('279ff523-a8f3-43a8-a339-3b8952596d1e','二月十六日賞海棠','陸游','宋','宋诗','song-poetry','','[]','常年春半花事竟，今年春半花始盛。',128,'全唐诗/poet.song.128000.json','["常年春半花事竟，今年春半花始盛。", "衰翁不減少年狂，走馬直與飛蝶競。", "妍華有露洗愈明，纖弱無風揺不定。", "莫放飄零作紅雨，剩看倩笑臨粧鏡。", "溪梅枯槁墮巖谷，山杏輕浮真妾媵。", "欲誇絕艶不勝說，縱欠濃香何足病。", "華燈銀燭揺花光，翠杓金舩豪酒興。", "夜闌感事獨悽然，繁枝空折誰堪贈。"]'),
('ec6e7c20-3547-4ac0-a68f-06fae5216eff','即席','陸游','宋','宋诗','song-poetry','','[]','觧鞅名園眼倍明，殷勤翠袖勸飛觥。',64,'全唐诗/poet.song.128000.json','["觧鞅名園眼倍明，殷勤翠袖勸飛觥。", "海棠紅杏欲無色，蛺蝶黄鸝俱有情。", "去日不留春漸老，歸舟已具客將行。", "倦遊短鬢無多緑，生怕尊前唱渭城。"]'),
('b5e7e879-c70c-42de-ae34-d6aa3302ce87','東歸有日書懷','陸游','宋','宋诗','song-poetry','','[]','萬里橋邊白版扉，三年高卧謝塵鞿。',64,'全唐诗/poet.song.128000.json','["萬里橋邊白版扉，三年高卧謝塵鞿。", "半窗竹影棋僧去，滿棹蘋風釣伴歸。", "看鏡已添新雪鬢，聴雞重拂舊朝衣。", "故人零落今無幾，華表空悲老令威。"]'),
('fe74c516-085a-469d-a32a-ea45553931aa','眉州披風榭拜東坡先生遺像','陸游','宋','宋诗','song-poetry','','[]','蜿蜒回顧山有情，平鋪十里江無聲。',130,'全唐诗/poet.song.128000.json','["蜿蜒回顧山有情，平鋪十里江無聲。", "孕奇蓄秀當此地，鬱然千載詩書城。", "高臺老仙誰所寫，仰視眉宇空崢嶸。", "百年醉魂吹不醒，飄飄風袖笻枝横。", "爾來逢迎厭俗子，龍章鳯姿我眼明。", "北扉南海均夢耳，謫墮本自白玉京。", "惜哉畫史未造極，不作散髮騎長鯨。", "故鄉歸來要有日，安得春江變酒從公傾。"]'),
('3f89c6ee-c16c-49ec-8e81-587e0d1121a7','訪青神尉廨借景亭蓋山谷先生舊遊也','陸游','宋','宋诗','song-poetry','','[]','造朝下白帝，吊古遊青神。',108,'全唐诗/poet.song.128000.json','["造朝下白帝，吊古遊青神。", "城頭三間屋，聊得岸我巾。", "元祐太史公，世寧有斯人。", "瘴烟侵玉骨，老作宜州民。", "至今杖屨地，來者猶酸辛。", "密竹翦已空，喬木亦半薪。", "陂池獨渺然，中有鷗鷺馴。", "人生能自足，一尉可終身。", "三嘆下城去，捩柂春江津。"]'),
('3f1c680c-7596-478f-bf6b-2d22bd345ac4','舟過玉津','陸游','宋','宋诗','song-poetry','','[]','玻瓈江上送殘春，疊鼓催颿過玉津。',64,'全唐诗/poet.song.128000.json','["玻瓈江上送殘春，疊鼓催颿過玉津。", "蜀苑鶯花初破夢，巴山風月又關身。", "幅巾久已忘朝幘，短劍惟思隱市塵。", "莫倚諸公容此老，西曹那許吐車茵。"]'),
('7f0e09c9-4631-4fed-a541-b70548559d1e','叙州三首  其一','陸游','宋','宋诗','song-poetry','','[]','畫船衝雨入戎州，縹緲山横杜若洲。',32,'全唐诗/poet.song.128000.json','["畫船衝雨入戎州，縹緲山横杜若洲。", "須信時平邊堠靜，傳烽夜夜到西樓。"]'),
('e51aa09a-9d41-4766-8e53-4be33ba42ed4','叙州三首  其二','陸游','宋','宋诗','song-poetry','','[]','文章何辠觸雷霆，風雨南谿自醉醒。',32,'全唐诗/poet.song.128000.json','["文章何辠觸雷霆，風雨南谿自醉醒。", "八十年間遺老盡，壊堂無壁草青青。"]'),
('acabbdad-dfce-458e-ae68-93c0f04e8666','叙州三首  其三','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','楚柂吳檣又遠遊，浣花行樂夢西州。',32,'全唐诗/poet.song.128000.json','["楚柂吳檣又遠遊，浣花行樂夢西州。", "千尋鐵鎻還堪恨，空鎖長江不鎖愁。"]'),
('ec402477-c983-4054-95cc-2d060f62d8f9','瀘州使君巖在城南一里深三丈有泉出其左音中律呂木龍巖相距亦里許黄太史所嘗遊憩也','陸游','宋','宋诗','song-poetry','','[]','雲間刁斗過邊州，沙際丘亭艤客舟。',64,'全唐诗/poet.song.128000.json','["雲間刁斗過邊州，沙際丘亭艤客舟。", "漲水方憂三峽嶮，短笻猶作兩巖遊。", "蛟龍矯矯拏雲起，琴筑泠泠繞榻流。", "未死人生誰料得，會來攜客試茶甌。"]'),
('c7d77e7d-b441-4a31-bbc4-17ed2ca571ed','南定樓遇急雨','陸游','宋','宋诗','song-poetry','','[]','行遍梁州到益州，今年又作度瀘遊。',64,'全唐诗/poet.song.128000.json','["行遍梁州到益州，今年又作度瀘遊。", "江山重複爭供眼，風雨縱横亂入樓。", "人語朱離逢峒獠，棹歌欸乃下吳舟。", "天涯住穩歸心懶，登覽茫然却欲愁。"]'),
('73af2298-0338-4439-971e-53c1b039f0f1','夜泊合江縣月中小舟謁西凉王祠','陸游','宋','宋诗','song-poetry','','[]','懸瀑雪飛舞，奇峰玉嶙峋。',96,'全唐诗/poet.song.128000.json','["懸瀑雪飛舞，奇峰玉嶙峋。", "揺碎一江月，來謁西凉神。", "我雖不識神，知是山水人。", "不敢持笏來，裋褐整幅巾。", "出我囊中香，羞我南谿蘋。", "杯湛玻瓈春，盤横水精鱗。", "出門意惝怳，烟波浩無津。", "安得結茆地，與神永爲鄰。"]'),
('e017a675-57c3-41a2-8378-bc6fb9275a7f','風順舟行甚疾戲書','陸游','宋','宋诗','song-poetry','','[]','昔者遠戍南山邊，軍中無事酒如川。',64,'全唐诗/poet.song.128000.json','["昔者遠戍南山邊，軍中無事酒如川。", "呼盧喝雉連暮夜，擊兔伐狐窮歲年。", "壯士春蕪卧白骨，老夫晨鏡悲華顛。", "可憐使氣尚未减，打鼓順流千斛船。"]'),
('697ba0d5-93f1-4d9b-9391-093dc687e698','舟中對月','陸游','宋','宋诗','song-poetry','','[]','百壺載酒遊凌雲，醉中揮袖别故人。',96,'全唐诗/poet.song.128000.json','["百壺載酒遊凌雲，醉中揮袖别故人。", "依依向我不忍别，誰似峨嵋半輪月。", "月窺船窗挂凄冷，欲到渝州酒初醒。", "江空裊裊釣絲風，人靜翩翩葛巾影。", "哦詩不睡月滿船，清寒入骨我欲仙。", "人間更漏不到處，時有沙禽背船去。"]'),
('c87e471c-e9d0-4e18-b654-7a311902169e','漁翁','陸游','宋','宋诗','song-poetry','','[]','江頭漁家結茆廬，青山當門畫不如。',64,'全唐诗/poet.song.128000.json','["江頭漁家結茆廬，青山當門畫不如。", "江烟淡淡雨疏疏，老翁破浪行捕魚。", "恨渠生來不讀書，江山如此一句無。", "我亦衰遲慚筆力，共對江山三嘆息。"]'),
('0c293383-e4d0-4c24-8b59-55eb6ace08a2','涪州道中','陸游','宋','宋诗','song-poetry','','[]','遠客喜歸路，清遊逾昔聞。',48,'全唐诗/poet.song.128000.json','["遠客喜歸路，清遊逾昔聞。", "雨添山翠重，舟壓浪花分。", "洛叟經名世，張侯勇冠軍。", "懷人不可覿，袖手對爐熏。"]'),
('68deb0bc-808f-4338-b4ba-e993324b7e99','涪州','陸游','宋','宋诗','song-poetry','','[]','古壘西偏曉繫舟，倚欄搔首思悠悠。',64,'全唐诗/poet.song.128000.json','["古壘西偏曉繫舟，倚欄搔首思悠悠。", "欲營丹竈竟無地，不見荔枝空遠遊。", "官道近江多亂石，人家避水半危樓。", "使君不用勤留客，瘴雨蠻雲我欲愁。"]'),
('e424e19e-45d0-4add-a09d-daedef3b86ee','北巖','陸游','宋','宋诗','song-poetry','','[]','艤舩涪州岸，攜兒北巖遊。',120,'全唐诗/poet.song.128000.json','["艤舩涪州岸，攜兒北巖遊。", "揺檝横大江，褰裳躡高樓。", "雨昏山半失，江漲地欲浮。", "老矣寧再來，爲作竟日留。", "烏帽程丈人，閉戸本好修。", "駭機一朝發，議罪至竄投。", "黨禁久不解，戰塵暗神州。", "修怨以稔禍，哀哉誰始謀。", "小人無遠略，所懷在私讎。", "後來其鑑兹，賦詩識巖幽。"]'),
('9146c9fe-2371-4a33-893d-5c5600ea8137','平都山','陸游','宋','宋诗','song-poetry','','[]','名山近江步，蠟屐得閑行。',72,'全唐诗/poet.song.128000.json','["名山近江步，蠟屐得閑行。", "奔鹿衝人過，藏丹徹夜明。", "唐碑多斷蝕，梁殿半欹傾。", "洞口雲常湧，簷牙柏再榮。", "行逢負籠客，臥聽送船聲。", "乞我誅茆地，靈苖得共烹。"]'),
('bfc39a14-70bf-41c6-94b9-02219348eda7','忠州禹廟','陸游','宋','宋诗','song-poetry','','[]','古郡巴蠻國，空山夏禹祠。',48,'全唐诗/poet.song.128000.json','["古郡巴蠻國，空山夏禹祠。", "鴉歸暗庭柏，巫拜薦江蘺。", "草蔓青緣壁，苔痕紫滿碑。", "欲歸頻悵望，回棹夕陽時。"]'),
('c08fbfa3-7783-4c67-a457-babb12b413ee','忠州醉歸舟中作','陸游','宋','宋诗','song-poetry','','[]','耿耿船窗燈火明，東樓飲罷恰三更。',64,'全唐诗/poet.song.128000.json','["耿耿船窗燈火明，東樓飲罷恰三更。", "不堪酒渴兼消渴，起聽江聲雜雨聲。", "垂首道塗悲驥老，滿懷風露覺蟬清。", "蘭亭禹廟山如畫，安得飄然送此生。"]'),
('fcf1946a-6c4e-446f-b217-0bd8737c21ed','雨中遊東坡','陸游','宋','宋诗','song-poetry','','[]','木蓮花下竹枝歌，歡意無多感慨多。',32,'全唐诗/poet.song.128000.json','["木蓮花下竹枝歌，歡意無多感慨多。", "更恐他年有遺恨，曉來衝雨上東坡。"]'),
('d12f6b5f-4bae-4a9b-93ba-7dade0e3ff02','龍興寺吊少陵先生寓居','陸游','宋','宋诗','song-poetry','','["\u51ed\u540a", "\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143", "\u611f\u6168"]','中原草草失承平，戍火胡塵到兩京。',32,'全唐诗/poet.song.128000.json','["中原草草失承平，戍火胡塵到兩京。", "扈蹕老臣身萬里，天寒來此聽江聲。"]'),
('54d9c72b-fcfb-4f7a-9753-24efa8bad853','遊萬州岑公洞','陸游','宋','宋诗','song-poetry','','[]','大業征遼發閭左，軍興書檄煎膏火。',96,'全唐诗/poet.song.128000.json','["大業征遼發閭左，軍興書檄煎膏火。", "此時也復有閑人，自引巖泉拾山果。", "後六百歲吾來遊，洞中正夏凄如秋。", "乳石床平可坐卧，水作珠簾月作鈎。", "十年神遊八極表，浮名坐覺秋豪小。", "試問岑公迎我不，鶴飛忽下青松抄。"]'),
('dabe6f02-0e10-404d-9821-d3343576ccda','萬州放船過下巖小留','陸游','宋','宋诗','song-poetry','','[]','畫船四月滿旗風，飲散匆匆鷁首東。',64,'全唐诗/poet.song.128000.json','["畫船四月滿旗風，飲散匆匆鷁首東。", "醉裏偏憐江水緑，意中已想荔枝紅。", "斷碑零落莓苔遍，幽澗淙潺略彴通。", "一疋寧無好東絹，憑誰畫此碧玲瓏。"]'),
('ca2c2f8b-cb92-4acb-a48b-da4082febce5','白帝泊舟','陸游','宋','宋诗','song-poetry','','[]','客路閑無事，津亭爽有餘。',48,'全唐诗/poet.song.128000.json','["客路閑無事，津亭爽有餘。", "峽江春漲減，瀼岸夜燈疏。", "老矣孤舟裏，依然十載初。", "倦遊思税駕，更覺愛吾廬。"]'),
('cd04002c-3585-4055-831e-bff9cfcdcc74','醉中下瞿唐峽中流觀石壁飛泉','陸游','宋','宋诗','song-poetry','','[]','吾舟十丈如青蛟，乘風翔舞從天下。',98,'全唐诗/poet.song.128000.json','["吾舟十丈如青蛟，乘風翔舞從天下。", "江流觸地白鹽動，灔澦浮波真一馬。", "主人滿酌白玉杯，旗下畫鼓如春雷。", "回頭已失瀼西市，奇哉一削千仞之蒼崖。", "蒼崖中裂銀河飛，空裏萬斛傾珠璣。", "醉面正須迎亂點，京塵未許化征衣。"]'),
('4f068ebc-2c02-49dc-93a8-429ac2b526c8','暮次秭歸','陸游','宋','宋诗','song-poetry','','[]','朝披南陵雲，夕揖建平樹。',96,'全唐诗/poet.song.128000.json','["朝披南陵雲，夕揖建平樹。", "啼鴉隨客檣，落日滿孤戍。", "惡灘不可說，石芒森如鋸。", "浪花一丈白，吹沫入窗戸。", "是身初非我，底處著憂怖。", "酒酣一枕睡，過盡鮫鰐怒。", "欣然推枕起，曵杖散予步。", "殷勤沙際柳，記我維舟處。"]'),
('c69bf5de-89ad-4249-b55e-e3aab11b2f36','歸州重五','陸游','宋','宋诗','song-poetry','','[]','鬬舸紅旗滿急湍，船窗睡起亦閑看。',32,'全唐诗/poet.song.128000.json','["鬬舸紅旗滿急湍，船窗睡起亦閑看。", "屈平鄉國逢重五，不比常年角黍盤。"]'),
('74d98c73-002d-483f-ab68-a878a1e645e7','屈平廟','陸游','宋','宋诗','song-poetry','','[]','委命仇讎事可知，章華荆棘國人悲。',32,'全唐诗/poet.song.128000.json','["委命仇讎事可知，章華荆棘國人悲。", "恨公無壽如金石，不見秦嬰係頸時。"]'),
('5616693b-db1f-4c4b-9323-b0bd0dd34e82','楚城','陸游','宋','宋诗','song-poetry','','[]','江上荒城猿鳥悲，隔江便是屈原祠。',32,'全唐诗/poet.song.128000.json','["江上荒城猿鳥悲，隔江便是屈原祠。", "一千五百年間事，只有灘聲似舊時。"]'),
('29a67aea-c81f-4bcf-a2f6-162d3482b5c0','新灘舟中作','陸游','宋','宋诗','song-poetry','','[]','江路桃花浪已生，新灘穩過失崢嶸。',64,'全唐诗/poet.song.128000.json','["江路桃花浪已生，新灘穩過失崢嶸。", "九年行半九州地，三峽歸無三日程。", "繫纜便增笻杖興，倚窗時聽棹歌聲。", "衰遲未覺詩情减，又擘吳牋賦楚城。"]'),
('464541ec-e7cf-4b52-8e64-17dbfae18d56','舟出下牢關','陸游','宋','宋诗','song-poetry','','[]','大舸凌驚濤，飛度青玉峽。',72,'全唐诗/poet.song.128000.json','["大舸凌驚濤，飛度青玉峽。", "虚壁雲濛濛，陰洞風颯颯。", "拂天松蓋偃，入水山脚插。", "炎曦忽摧破，亭午手忘箑。", "懸知今夜喜，月白宿沙夾。", "曠哉七澤遊，盟鷗不須歃。"]'),
('51a806e9-5787-4c3b-8ec3-1a8ef7742bd2','峽口夜坐','陸游','宋','宋诗','song-poetry','','[]','三峽至此窮，兩壁猶峭立。',72,'全唐诗/poet.song.128000.json','["三峽至此窮，兩壁猶峭立。", "估船無時行，婦盎有夜汲。", "風生樹影動，月碎水流急。", "草根綴微露，螢火飛熠熠。", "吾行已四旬，纔抵楚西邑。", "浩歌散鬱陶，還舟覺衣濕。"]'),
('2ec9a361-0031-4088-b262-7bf35f02d168','峽州甘泉寺','陸游','宋','宋诗','song-poetry','','[]','江上甘泉寺，登臨擅一州。',48,'全唐诗/poet.song.128000.json','["江上甘泉寺，登臨擅一州。", "山亭喜無恙，老子得重遊。", "灘急常疑雨，林深欲借秋。", "歸途更清絕，倚杖喚漁舟。"]'),
('053b4986-9aad-4f4d-adab-be9aae8d3379','峽州東山','陸游','宋','宋诗','song-poetry','','[]','十年不踏東山路，今日重爲放浪行。',64,'全唐诗/poet.song.128000.json','["十年不踏東山路，今日重爲放浪行。", "老矣判無黄鵠舉，歸哉惟有白鷗盟。", "新秧刺水農家樂，修竹環溪客眼明。", "已駕巾車仍小駐，綠蘿亭下聽鶯聲。"]'),
('4dfcb3d5-37b6-4c69-980e-40c516dfbe7a','江上觀月','陸游','宋','宋诗','song-poetry','','[]','暗浪衝舟鞺鞳聲，夷陵城下正三更。',64,'全唐诗/poet.song.128000.json','["暗浪衝舟鞺鞳聲，夷陵城下正三更。", "十分傾酒禁風力，一點無雲祟月明。", "久坐不知衣露濕，浩歌時有水禽驚。", "詩成莫駕長鯨去，自是虚皇白玉京。"]'),
('03124e03-d31b-4774-9c35-ac48ae10e897','初發夷陵','陸游','宋','宋诗','song-poetry','','[]','雷動江邊鼓吹雄，百灘過盡失途窮。',64,'全唐诗/poet.song.128000.json','["雷動江邊鼓吹雄，百灘過盡失途窮。", "山平水遠蒼茫外，地闢天開指顧中。", "俊鶻横飛遥掠岸，大魚騰出欲凌空。", "今朝喜處君知否，三丈黄旗舞便風。"]'),
('bb36ccca-3cba-4766-a5f7-3c9c91132192','舟中夜坐','陸游','宋','宋诗','song-poetry','','[]','風露浩無際，星河淡欲傾。',48,'全唐诗/poet.song.128000.json','["風露浩無際，星河淡欲傾。", "遙知竝船客，聞我詠詩聲。", "水鳥横江去，漁舟背月行。", "神清不成寐，隱几待窗明。"]'),
('dfce59db-1cf2-418b-b46b-776f3ebb9805','初到荆州','陸游','宋','宋诗','song-poetry','','[]','萬里泛仙槎，歸來鬢未華。',48,'全唐诗/poet.song.128000.json','["萬里泛仙槎，歸來鬢未華。", "蕭蕭沙市雨，淡淡渚宮花。", "斷岸添新漲，高城咽晚笳。", "船窗一樽酒，半醉落烏紗。"]'),
('e8cdaac9-ffa3-4a53-b047-68b760c161ce','醉歸','陸游','宋','宋诗','song-poetry','','[]','持酒江頭到夕霏，愁城頓覺解重圍。',64,'全唐诗/poet.song.128000.json','["持酒江頭到夕霏，愁城頓覺解重圍。", "澄波宜月移船看，醉面便風走馬歸。", "末路已驚添白髮，故人頻報上黄扉。", "彊隨官簿真成懶，乞我吳松舊釣磯。"]'),
('90e50a46-f520-4293-9402-e84c1f2cb293','出遊','陸游','宋','宋诗','song-poetry','','[]','萬里崎嶇蜀道歸，荆州非復壯遊時。',64,'全唐诗/poet.song.128000.json','["萬里崎嶇蜀道歸，荆州非復壯遊時。", "行吟自怪詩情减，坐睡人驚酒量衰。", "卷地風號雲夢澤，黏天草映伏波祠。", "一枝藤杖平生事，擊鼓開帆未恨遲。"]'),
('fdfd661a-d69d-4eb8-a598-dda1ea666d95','大堤','陸游','宋','宋诗','song-poetry','','[]','日晚大堤行，莽然千里平。',48,'全唐诗/poet.song.128000.json','["日晚大堤行，莽然千里平。", "天低垂曠野，風壯撼高城。", "列肆居茶估，連營宿戍兵。", "纍纍北門堠，泪盡望神京。"]'),
('246d2893-c3f2-4416-912d-9991663a82c3','阻風','陸游','宋','宋诗','song-poetry','','[]','沙市三日風，萬鼓鳴船頭。',72,'全唐诗/poet.song.128000.json','["沙市三日風，萬鼓鳴船頭。", "欲去不得發，卧對青燈幽。", "聽兒誦離騷，可以散我愁。", "微言入孤夢，怳與屈宋遊。", "睡起銅瓶響，欣然喚茶甌。", "吾道無淹速，風伯非所尤。"]'),
('e421d6d7-d47e-411f-beba-fecc712ea10e','初發荆州','陸游','宋','宋诗','song-poetry','','[]','淋漓牛酒起檣干，健櫓飛如插羽翰。',64,'全唐诗/poet.song.128000.json','["淋漓牛酒起檣干，健櫓飛如插羽翰。", "破浪乘風千里快，開頭擊鼓萬人看。", "鵲聲不斷朝陽出，旗脚微舒宿雨乾。", "堪笑塵埃洛陽客，素衣如墨據征鞍。"]'),
('69e07c70-8147-452f-91ec-f6355ea4add1','泊公安縣','陸游','宋','宋诗','song-poetry','','[]','秦關蜀道何遼哉，公安渡頭今始回。',64,'全唐诗/poet.song.128000.json','["秦關蜀道何遼哉，公安渡頭今始回。", "無窮江水與天接，不斷海風吹月來。", "船窗簾捲螢火閙，沙渚露下蘋花開。", "少年許國忽衰老，心折柁樓長笛哀。"]'),
('aa8a5fad-1d87-4aeb-b236-e2ef8fe3b7f7','劉郎浦夜賦','陸游','宋','宋诗','song-poetry','','[]','平生遠遊心，睥睨萬里窄。',72,'全唐诗/poet.song.128000.json','["平生遠遊心，睥睨萬里窄。", "今年下三巴，放浪浮七澤。", "菰蒲無遠近，但覺風索索。", "浪高星辰濕，天碧河漢白。", "十年散醉髮，未易著朝幘。", "守符倘可乞，來作瀟湘客。"]'),
('32858669-301c-4ef0-82cf-211037c097b3','小雨極凉舟中熟睡至夕','陸游','宋','宋诗','song-poetry','','[]','舟中一雨掃飛蠅，半脱綸巾卧翠藤。',32,'全唐诗/poet.song.128000.json','["舟中一雨掃飛蠅，半脱綸巾卧翠藤。", "清夢初回窗日晚，數聲柔櫓下巴陵。"]'),
('2c21dcc9-8a9b-476d-8e52-7a36f1b46c77','岳陽樓','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','身如病鶴短翅翎，雨雪飄灑號沙汀。',128,'全唐诗/poet.song.128000.json','["身如病鶴短翅翎，雨雪飄灑號沙汀。", "天風忽吹不得住，東下巴峽泛洞庭。", "軒皇張樂雖已矣，此地至今朝百靈。", "雄樓岌嶪鎮吳楚，我來舉手捫天星。", "帆檣纔放已隱隱，雲氣亂入何冥冥。", "黿鼉出没蛟鰐横，浪花遮盡君山青。", "黄衫仙翁喜無恙，袖劍近到城南亭。", "眼前俗子敗人意，安得與翁同醉醒。"]'),
('e4533eec-7211-4812-870a-8584dc519998','再賦一絕','陸游','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','江風吹雨濯征塵，百尺闌干爽氣新。',32,'全唐诗/poet.song.128000.json','["江風吹雨濯征塵，百尺闌干爽氣新。", "不向岳陽樓上醉，定知未可作詩人。"]'),
('2327cead-50af-4908-83aa-c321d4e0f70b','乘大風發巴陵','陸游','宋','宋诗','song-poetry','','[]','雪濺浪方作，翠颭山欲浮。',96,'全唐诗/poet.song.128000.json','["雪濺浪方作，翠颭山欲浮。", "奇哉萬頃湖，著我十丈舟。", "三老請避風，叱去非汝憂。", "神物識忠信，壯士憎滯留。", "擊鼓催挂帆，揮手别岳州。", "仰視群鵠翔，下闖百怪囚。", "衡湘清絕地，恨不從此遊。", "聊須百斛酒，往醉庾公樓。"]'),
('cbe414cb-b267-4b60-b8ae-2c9042577979','通濟口','陸游','宋','宋诗','song-poetry','','[]','朝發嘉魚縣，晚泊通濟口。',56,'全唐诗/poet.song.128000.json','["朝發嘉魚縣，晚泊通濟口。", "睡起喜微凉，船窗一杯酒。", "長魚吹浪聲恐人，巨黿露背浮奫淪。", "今夕風生月復暗，寄語舟人更添纜。"]'),
('ff724acd-a667-4b5d-b743-6d87c1d1db7d','醉書','陸游','宋','宋诗','song-poetry','','[]','青草渡頭波接天，山翁吟嘯自悠然。',64,'全唐诗/poet.song.128000.json','["青草渡頭波接天，山翁吟嘯自悠然。", "朝餐偶過賣魚市，晚泊時逢迎荻船。", "投老未除遊俠氣，平生不作俗人緣。", "一樽酌罷玻璃酒，高枕窗邊聽雨眠。"]'),
('68c6561c-55d5-4179-a245-1e9ae8a5256b','南樓','陸游','宋','宋诗','song-poetry','','[]','十年不把武昌酒，此日闌邊感慨深。',64,'全唐诗/poet.song.128000.json','["十年不把武昌酒，此日闌邊感慨深。", "舟楫紛紛南復北，山川莽莽古猶今。", "登臨壯士興懷地，忠義孤臣許國心。", "倚杖黯然斜照晚，秦吳萬里入長吟。"]'),
('7d53ad0e-9acd-483a-9553-08e1c85bc844','黄鶴樓','陸游','宋','宋诗','song-poetry','','[]','手把仙人緑玉枝，吾行忽及早秋期。',64,'全唐诗/poet.song.128000.json','["手把仙人緑玉枝，吾行忽及早秋期。", "蒼龍闕角歸何晚，黄鶴樓中醉不知。", "江漢交流波渺渺，晋唐遺跡草離離。", "平生最喜聽長笛，裂石穿雲何處吹。"]'),
('89594647-321b-4965-8c7a-71622d797dcb','頭陀寺觀王簡栖碑有感偶餘眉州酒樽獨酌遂醉','陸游','宋','宋诗','song-poetry','','[]','舟車如織喜身閑，獨訪遺碑草棘間。',64,'全唐诗/poet.song.128000.json','["舟車如織喜身閑，獨訪遺碑草棘間。", "世遠空驚閲陵谷，文浮未可敵江山。", "老僧西逝新成塔，舊守東歸正掩關。", "笑我驅馳竟安往，夕陽飛鳥亦知還。"]'),
('682e7ea8-e3e7-4e7f-8623-e628eae0ff5d','夜熱','陸游','宋','宋诗','song-poetry','','[]','觸熱行萬里，煩促詎可論。',72,'全唐诗/poet.song.128000.json','["觸熱行萬里，煩促詎可論。", "泊船鄂州步，終日如炮燔。", "揺扇腕欲脱，揮汗白雨翻。", "推枕再三起，散髮臨前軒。", "秋近更漏長，天旱星宿繁。", "甘澍何時來，太息憂元元。"]'),
('3fafafe9-7a6b-4eb1-a2b4-01804948237f','舟中偶書','陸游','宋','宋诗','song-poetry','','[]','老子西遊萬里回，江行長夏亦佳哉。',64,'全唐诗/poet.song.128000.json','["老子西遊萬里回，江行長夏亦佳哉。", "晝眠初起報茶熟，宿酒半醒聞雨來。", "漢口船開催疉鼓，淮南帆落亞高桅。", "四方本是丈夫事，白首自憐心未灰。"]'),
('8e355b59-569f-48a2-858c-d59946edfbdf','燈下讀書','陸游','宋','宋诗','song-poetry','','[]','少年喜書策，白首意未足。',72,'全唐诗/poet.song.128000.json','["少年喜書策，白首意未足。", "幽窗燈一點，樂處超五欲。", "而况黄州路，小雨漁村宿。", "蕭蕭蒹葭聲，爲我洗暑毒。", "琅然誦經史，少倦兒爲續。", "何必效萊公，長夜醉畫燭。"]'),
('2721b1e6-e11d-4161-9fca-893ae77d85d0','泊三江口','陸游','宋','宋诗','song-poetry','','[]','遲明離武昌，薄暮次黄岡。',72,'全唐诗/poet.song.128000.json','["遲明離武昌，薄暮次黄岡。", "勿言觸熱行，一雨三日凉。", "北窗荻蕭蕭，南窗江茫茫。", "玄雲一池墨，碧綫半篆香。", "尚無車馬塵，况復爭奪場。", "徐行勿挂帆，此樂殊未央。"]'),
('e6f6f3fb-5d21-42f9-b6e6-c9aa1a25474e','自雪堂登四望亭因歴訪蘇公遺跡至安國院','陸游','宋','宋诗','song-poetry','','[]','我醉飛屐登孱顔，拄杖出没風烟間。',128,'全唐诗/poet.song.128000.json','["我醉飛屐登孱顔，拄杖出没風烟間。", "三山葱曨鮫鰐靜，九關肅穆虎豹閑。", "幾年金骨煉緑髓，此日始得窮躋攀。", "老僊歸侍紫皇案，空有野水流淙潺。", "蜿蜒翠阜圍緑野，似嶺非嶺山非山。", "向來龍蛇滿雪壁，雷電下取何時還。", "名花亦已天上去，居人指似題詩處。", "九十一翁不識公，我抱此恨知無窮。"]'),
('b8e15b5b-6fa0-44e4-9fdd-3b348346be07','月下步至臨皋亭','陸游','宋','宋诗','song-poetry','','[]','芒鞵踏松陰，迨此船未發。',72,'全唐诗/poet.song.128000.json','["芒鞵踏松陰，迨此船未發。", "清遊豈無伴，三友風露月。", "山川鬱盤紆，鷗鷺浩滅没。", "當年老先生，想像散醉髮。", "浮生等昨夢，久已埋玉骨。", "吾儕幸彊健，何事拘簪笏。"]'),
('a1f66f08-5a9f-40f3-8561-0797c57a3a9a','發黄州泊巴河遊馬祈寺','陸游','宋','宋诗','song-poetry','','[]','南望武昌山，北望齊安城。',96,'全唐诗/poet.song.128000.json','["南望武昌山，北望齊安城。", "楚江萬頃緑，著我畫舫横。", "雲帆不須挂，鼉鼓不須鳴。", "淡然隱曲几，山水相逢迎。", "疏雨漏薄日，非陰亦非晴。", "晚泊巴河市，小陌聞屐聲。", "紫髯刑馬地，一怒江漢清。", "中原今何如，感我白髮生。"]'),
('39350364-2601-426a-bdb5-b0ca02648979','舟行蘄黄間雨霽得便風有感','陸游','宋','宋诗','song-poetry','','[]','天青雲白十分晴，帆飽舟輕盡日行。',64,'全唐诗/poet.song.128000.json','["天青雲白十分晴，帆飽舟輕盡日行。", "江底魚龍貪晝睡，淮南草木借秋聲。", "好山縹緲何由住，華髮蕭條只自驚。", "莫怪時人笑疏懶，宦情元不似詩情。"]'),
('43a3e9c3-1b69-4ce9-a376-50b6d5c7c9fd','南烹','陸游','宋','宋诗','song-poetry','','[]','十年流落憶南烹，初見鱸魚眼自明。',32,'全唐诗/poet.song.128000.json','["十年流落憶南烹，初見鱸魚眼自明。", "堪笑吾宗輕許可，坐令羊酪僣蓴羮。"]'),
('ec3417d5-fe01-4631-9614-2bfe2c9b60a1','泊蘄口泛月湖中','陸游','宋','宋诗','song-poetry','','[]','炎天倦長路，月夕泛平湖。',48,'全唐诗/poet.song.128000.json','["炎天倦長路，月夕泛平湖。", "晃漾披銀闕，清寒住玉壺。", "釣絲縈藻荇，蓬艇入菰蒲。", "自別蜻蜓浦，斯遊十載無。"]'),
('62e9d0a0-53da-485d-9153-155eb58a0a97','初見廬山','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','從軍憶在梁州日，心擬西征草捷書。',64,'全唐诗/poet.song.128000.json','["從軍憶在梁州日，心擬西征草捷書。", "鐵馬但思經太華，布帆何意拂匡廬。", "計謀落落知誰許，功業悠悠定已疏。", "尚喜東林尋舊社，月明清露濕芙蕖。"]'),
('833d763f-325f-49e8-a716-844bcffb99ff','六月十四日宿東林寺','陸游','宋','宋诗','song-poetry','','[]','看盡江湖千萬峰，不嫌雲夢芥吾胸。',64,'全唐诗/poet.song.128000.json','["看盡江湖千萬峰，不嫌雲夢芥吾胸。", "戲招西塞山前月，來聽東林寺裏鐘。", "遠客豈知今再到，老僧能記昔相逢。", "虚窗熟睡誰驚覺，野碓無人夜自舂。"]'),
('1274ecca-ccd8-41a2-91be-10b86f27f196','舟過小孤有感','陸游','宋','宋诗','song-poetry','','[]','小孤山畔峭帆風，又見烟鬟縹緲中。',64,'全唐诗/poet.song.128000.json','["小孤山畔峭帆風，又見烟鬟縹緲中。", "萬里客經三峽路，千篇詩費十年功。", "未嘗滿箸蒲芽白，先看堆盤鱠縷紅。", "商略人生爲何事，一蓑從此入空濛。"]'),
('3e374c11-ddbb-4376-9501-667a247690d3','雁翅夾口小酌','陸游','宋','宋诗','song-poetry','','[]','墟烟淡將散，江雨細欲無。',72,'全唐诗/poet.song.128000.json','["墟烟淡將散，江雨細欲無。", "回風吹衣襟，晴光滿菰蒲。", "隱几樂此時，清和如夏初。", "犬吠船丁歸，小市得美蔬。", "歡言酌清醥，侑以案上書。", "雖云泊江渚，何異歸林廬。"]'),
('89907c6f-03a1-4b06-abfe-9258d3b11080','長風沙','陸游','宋','宋诗','song-poetry','','[]','江水六月無津涯，驚濤駭浪高吹花。',96,'全唐诗/poet.song.128000.json','["江水六月無津涯，驚濤駭浪高吹花。", "櫓聲已出雁翅浦，荻夾喜入長風沙。", "長風自古三巴路，檣竿參差雜烟樹。", "南船北船各萬里，凄凉小市相依住。", "歌呼雜沓燈火明，黄昏風死浪亦平。", "勞苦舟師剩沽酒，安穩明朝到池口。"]'),
('f0891433-40ea-4d03-869c-b073e9b66037','泛小舟姑孰溪口','陸游','宋','宋诗','song-poetry','','[]','姑溪綠可染，小艇追晚凉。',72,'全唐诗/poet.song.128000.json','["姑溪綠可染，小艇追晚凉。", "棹進破樹影，波動揺星芒。", "荻深漁火明，風遠水草香。", "尚想錦袍公，醉眼隘八荒。", "坡陀青山冢，斷碣臥道旁。", "悵望不可逢，乘雲遊帝鄉。"]'),
('3410bdd5-4d73-4f6b-82ee-a28a0b217c37','明日再遊又賦','陸游','宋','宋诗','song-poetry','','[]','舟中如甑炊，端坐畏暍死。',96,'全唐诗/poet.song.128000.json','["舟中如甑炊，端坐畏暍死。", "未能踏增冰，且復呼艇子。", "纖纖新月低，玉鈎沈野水。", "微風生蘋末，塵抱真一洗。", "可憐黄山塔，突兀暮烟裏。", "依然十年前，看我行萬里。", "兩槳且勿揺，横舟小灘尾。", "得詩偶長吟，宿鷺爲驚起。"]'),
('585e83ca-2731-4f81-9277-358257086b96','過采石有感','陸游','宋','宋诗','song-poetry','','[]','短衣射虎早霜天，嘆息南山又七年。',64,'全唐诗/poet.song.128000.json','["短衣射虎早霜天，嘆息南山又七年。", "唾手每思雙羽箭，快心初見萬樓船。", "平波漫漫看浮馬，高柳陰陰聽亂蟬。", "明日重尋石頭路，醉鞍誰與共聮翩。"]'),
('9e63026d-b978-485b-a4db-82dcde005790','將至金陵先寄獻劉留守','陸游','宋','宋诗','song-poetry','','[]','梁益羈遊道阻長，見公便覺意差彊。',64,'全唐诗/poet.song.128000.json','["梁益羈遊道阻長，見公便覺意差彊。", "别都王氣半空紫，大將牙旗三丈黄。", "江面水軍飛海鶻，帳前羽箭射天狼。", "歸來要了浯溪頌，莫笑狂生老更狂。"]'),
('1bd1a9b0-e951-4086-a3db-5fc6372c56a8','登賞心亭','陸游','宋','宋诗','song-poetry','','[]','蜀棧秦關歲月遒，今年乘興却東遊。',64,'全唐诗/poet.song.128000.json','["蜀棧秦關歲月遒，今年乘興却東遊。", "全家穩下黄牛峽，半醉來尋白鷺洲。", "黯黯江雲瓜步雨，蕭蕭木葉石城秋。", "孤臣老抱憂時意，欲請遷都涕已流。"]'),
('1cee64c2-fac8-4e9c-b39a-937e47177af5','夜泊龍廟回望建康有感','陸游','宋','宋诗','song-poetry','','[]','我醉行水上，身輕如飛烟。',72,'全唐诗/poet.song.128000.json','["我醉行水上，身輕如飛烟。", "魚龍互悲嘯，伴我夜不眠。", "羽扇揮浮雲，月挂牛斗間。", "河漢横復斜，風露方浩然。", "坡陁石頭城，寂莫七百年。", "世事感予懷，竦身入青天。"]'),
('47707a85-62d4-4266-b309-eba3c81e01eb','將至京口','陸游','宋','宋诗','song-poetry','','[]','臥聽金山古寺鐘，三巴昨夢已成空。',64,'全唐诗/poet.song.128000.json','["臥聽金山古寺鐘，三巴昨夢已成空。", "船頭坎坎回帆鼓，旗尾舒舒下水風。", "城角危樓晴靄碧，林間雙塔夕陽紅。", "銅瓶愁汲中𤃩水，不見茶山九十翁。"]'),
('c07c5228-3391-4e0f-9018-b1bb2c5cc24f','荆谿館夜坐','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','河漢無聲天正青，三三五五滿天星。',96,'全唐诗/poet.song.128000.json','["河漢無聲天正青，三三五五滿天星。", "草根冷露黏濕螢，幽人岸巾坐津亭。", "憶下瞿唐浮洞庭，陽臺繫船夢娉婷。", "朱門重重夜不扃，四山猿鳥啼青冥。", "人生無蒂風中萍，幸我夢斷狂已醒。", "繡韉金絡帯萬釘，何如故山鋤茯苓。"]'),
('093a0da6-d756-4e9c-9c35-b59980feafa5','泝谿','陸游','宋','宋诗','song-poetry','','[]','射的峰前禹廟東，短蓬三扇卧衰翁。',64,'全唐诗/poet.song.128000.json','["射的峰前禹廟東，短蓬三扇卧衰翁。", "閑攜清聖濁賢酒，重試朝南暮北風。", "水落痕留紅蓼節，雨來聲滿綠蒲叢。", "衝烟莫作匆匆去，擬看溪丁下釣筒。"]'),
('480425d4-e38a-4dcb-8c35-2baef7d8d6a8','歸雲門','陸游','宋','宋诗','song-poetry','','[]','萬里歸來值歲豐，解裝鄉墅樂無窮。',64,'全唐诗/poet.song.128000.json','["萬里歸來值歲豐，解裝鄉墅樂無窮。", "甑炊飽雨湖菱紫，篾絡迎霜野柿紅。", "壊壁塵埃尋醉墨，孤燈餅餌對鄰翁。", "微官行矣閩山去，又寄千巖夢想中。"]'),
('25bb85db-246b-431b-b42d-ae3f76ad8852','月下自三橋泛湖歸三山','陸游','宋','宋诗','song-poetry','','[]','素璧初升禹廟東，天風爲我送孤蓬。',64,'全唐诗/poet.song.128000.json','["素璧初升禹廟東，天風爲我送孤蓬。", "山横玉海蒼茫外，人在冰壺縹緲中。", "茅舍燈青聞吠犬，蘋汀烟淡見驚鴻。", "白頭尚耐清寒在，安得終年伴釣翁。"]'),
('df46a1e9-8e20-4840-975c-2c06c2b8c074','懷成都十韵','陸游','宋','宋诗','song-poetry','','[]','放翁五十猶豪縱，錦城一覺繁華夢。',160,'全唐诗/poet.song.128000.json','["放翁五十猶豪縱，錦城一覺繁華夢。", "竹葉春醪碧玉壺，桃花駿馬青絲鞚。", "鬭雞南市各分朋，射雉西郊常命中。", "壯士臂立緑絛鷹，佳人袍畫金泥鳯。", "椽燭那知夜漏殘，銀貂不管晨霜重。", "一梢紅破海棠回，數蘂香新早梅動。", "酒徒詩社朝暮忙，日月匆匆迭賓送。", "浮世堪驚老已成，虚名自笑今何用。", "歸來山舍萬事空，卧聽糟床酒鳴瓮。", "北窗風雨耿青燈，舊遊欲說無人共。"]'),
('5dc2db5f-62af-4fe2-a52e-51557beec169','湖村秋曉','陸游','宋','宋诗','song-poetry','','[]','劍閣秦山不計年，却尋剡曲故依然。',64,'全唐诗/poet.song.128000.json','["劍閣秦山不計年，却尋剡曲故依然。", "盡收事業漁舟裏，全付光陰酒榼邊。", "平野曉聞孤唳鶴，澄湖秋浸四垂天。", "九關虎豹君休問，已向人間得地仙。"]'),
('036c4172-7dff-4024-b6f2-051d4e0897e5','夜夢與宇文子友譚德稱會山寺若餞予行者明日黎明得子友書感嘆久之乃作此詩','陸游','宋','宋诗','song-poetry','','[]','夜夢集山寺，二三佳友生。',96,'全唐诗/poet.song.128000.json','["夜夢集山寺，二三佳友生。", "相顧慘不樂，若有千里行。", "在門僕整駕，臨道騅嘶鳴。", "我友顧謂我，天寒戒晨征。", "遲速要當到，徐驅勿貪程。", "丁寧及藥餌，依依有餘情。", "鄰鐘忽驚覺，鴉翻窗欲明。", "作詩謝我友，有使頻寄聲。"]'),
('5edf8fe1-2799-4edb-aa83-776906ac35aa','寒夜','陸游','宋','宋诗','song-poetry','','[]','小隱謝城市，新寒尋褐袍。',48,'全唐诗/poet.song.128000.json','["小隱謝城市，新寒尋褐袍。", "秋燈依壁暗，夜雨挾風豪。", "俗自隨時異，身寧與世鏖。", "殘年更何事，持蟹酌松醪。"]'),
('b1dd6962-e7ab-4dc2-b68b-993b2fd7ec32','偷閑','陸游','宋','宋诗','song-poetry','','[]','老向人間未拂衣，偷閑聊喜息塵機。',64,'全唐诗/poet.song.128000.json','["老向人間未拂衣，偷閑聊喜息塵機。", "丹楓斷岸秋來早，淡日孤村客到稀。", "偶憶雪溪攜鶴去，却從雲肆買蓑歸。", "酒徒莫笑生涯别，久矣淵明悟昨非。"]'),
('e967b353-c0d9-494f-b9bb-d8d141a653f0','冬夜聞雁有感','陸游','宋','宋诗','song-poetry','','[]','從軍昔戍南山邊，傳烽直照東駱谷。',128,'全唐诗/poet.song.128000.json','["從軍昔戍南山邊，傳烽直照東駱谷。", "軍中罷戰壯士閑，細草平郊恣馳逐。", "洮州駿馬金絡頭，梁州毬場日打毬。", "玉杯傳酒和鹿血，女真降虜彈箜篌。", "大呼拔幟思野戰，殺氣當年赤浮面。", "南遊蜀道已低摧，猶據胡床飛百箭。", "豈知蹭蹬還江邊，病臂不復能開弦。", "夜聞雁聲起太息，來時應過桑乾磧。"]'),
('3b3b85ca-92c3-43ab-9fea-e07eca553f58','書懷','陸游','宋','宋诗','song-poetry','','[]','愁向東華蹋軟紅，暫歸舊隱樂無窮。',64,'全唐诗/poet.song.128000.json','["愁向東華蹋軟紅，暫歸舊隱樂無窮。", "石池洗藥涓涓水，漁艇投竿嫋嫋風。", "盡日醉醒菱唱裏，鄰家來往竹陰中。", "何須列戟長安第，四面雲山擁此翁。"]'),
('0d167645-a081-4797-a375-f2c9835ed4e6','湖中暮歸','陸游','宋','宋诗','song-poetry','','[]','弄檝漁舟水濺衣，興闌却傍柳邊歸。',64,'全唐诗/poet.song.128000.json','["弄檝漁舟水濺衣，興闌却傍柳邊歸。", "風平别浦沈新月，日落前村鎖夕霏。", "乍起鷺行横野去，欲栖鴉陣暗天飛。", "詩情自合江湖老，敢恨功名與願違。"]'),
('26b15c61-0f9d-4d2f-90a1-22c382d9f9e1','題齋壁','陸游','宋','宋诗','song-poetry','','[]','葺得湖邊屋數椽，茅齋低小竹窗妍。',64,'全唐诗/poet.song.128000.json','["葺得湖邊屋數椽，茅齋低小竹窗妍。", "墟烟寂歴歸村路，山色蒼寒釀雪天。", "性懶杯盤常偶爾，地偏雞犬亦翛然。", "早知栗里多幽事，虚走人間四十年。"]'),
('1806fd79-d714-4f75-8bd7-2fde34fdffac','新葺門屋','陸游','宋','宋诗','song-poetry','','[]','林棲四壁空，百事從簡易。',96,'全唐诗/poet.song.128000.json','["林棲四壁空，百事從簡易。", "缺籬寒未補，幽戸夜不閉。", "東偏欲廣屋，厚費敢輕議。", "設關力可具，稚子請遂事。", "呀然兩竹扉，寜復志容駟。", "西山正當前，浩蕩納空翠。", "下臨漁樵路，横鎖風月地。", "惟愁俗客來，剥啄驚午睡。"]'),
('95282554-0eee-4b23-905f-5f63545a2526','吾廬','陸游','宋','宋诗','song-poetry','','[]','吾廬雖小亦佳哉，新作柴門斸緑苔。',64,'全唐诗/poet.song.128000.json','["吾廬雖小亦佳哉，新作柴門斸緑苔。", "拄杖每闌歸鶴入，釣船時帯夕陽來。", "墟烟隔水霏霏合，籬菊凌霜續續開。", "千里安期那可得，笑呼鄰父共傳杯。"]'),
('d35288ff-d398-4910-8983-90af52e323a1','冬夜泛舟有懷山南戎幕','陸游','宋','宋诗','song-poetry','','[]','釣船東去掠新塘，船迮篷低露篛香。',64,'全唐诗/poet.song.128000.json','["釣船東去掠新塘，船迮篷低露篛香。", "十里澄波明白石，五更殘月伴清霜。", "飄飄楓葉無時下，嫋嫋菱歌盡意長。", "誰信梁州當日事，鐵衣寒枕緑沉槍。"]'),
('9c8bfd68-b430-40e3-a884-af12c16caa72','夢至成都悵然有作二首  其一','陸游','宋','宋诗','song-poetry','','[]','春風小陌錦城西，翠箔珠簾客意迷。',64,'全唐诗/poet.song.128000.json','["春風小陌錦城西，翠箔珠簾客意迷。", "下盡牙籌閑縱博，刻殘畫燭戲分題。", "紫氍毹暖帳中醉，紅叱撥驕花外嘶。", "孤夢凄凉身萬里，令人憎殺五更雞。"]'),
('e71943cc-41eb-4563-8cd4-d33756e35bc8','夢至成都悵然有作二首  其二','陸游','宋','宋诗','song-poetry','','[]','宦途元不羡飛騰，錦里豪華壓五陵。',64,'全唐诗/poet.song.128000.json','["宦途元不羡飛騰，錦里豪華壓五陵。", "紅袖引行遊玉局，華燈圍坐醉金繩。", "階前汗血洮河馬，架上霜毛海國鷹。", "世事轉頭誰料得，一官南去冷如冰。"]'),
('ca3dd830-8e6f-45cc-bbd7-a87c3146bae8','月夕','陸游','宋','宋诗','song-poetry','','[]','開戸滿庭雪，徐看知月明。',48,'全唐诗/poet.song.128000.json','["開戸滿庭雪，徐看知月明。", "微風入叢竹，復作雪來聲。", "俗塵不待掃，凛然肝肺清。", "村深無漏鼓，鶴唳報三更。"]'),
('25d0313f-69ae-432c-8de6-2cbb7894b988','將入閩夜行之雲門','陸游','宋','宋诗','song-poetry','','[]','東騖並偏門，籃輿兀睡昏。',48,'全唐诗/poet.song.128000.json','["東騖並偏門，籃輿兀睡昏。", "紡燈穿壁罅，吠犬闖籬根。", "久客悲行役，清愁怯夢魂。", "餘生猶幾出，回首付乾坤。"]'),
('cf31fbf4-bb3a-463a-88eb-50d363a9b7b0','山中觀殘菊追懷眉山師伯渾','陸游','宋','宋诗','song-poetry','','[]','空山菊花瘦如棘，傾倒滿地枝三尺。',69,'全唐诗/poet.song.128000.json','["空山菊花瘦如棘，傾倒滿地枝三尺。", "陰風冷雨不相貸，爛草蒼苔共狼藉。", "人雖委棄渠自香，詎必泛酒登華堂。", "君不見仁人志士窮死眉山陽，空使後世傳文章。"]'),
('c2018fbe-2116-418a-a617-00431d002377','自雲門之陶山肩輿者失道行亂山中有茅舍小塘極幽邃求見主人不可意其隱者也','陸游','宋','宋诗','song-poetry','','[]','陂池幽處有茅堂，井臼蕭條草樹荒。',64,'全唐诗/poet.song.128000.json','["陂池幽處有茅堂，井臼蕭條草樹荒。", "小鴨怯波時聚散，病蔬傷蠧半青黄。", "童兒衝雨收魚網，婢子聞鐘上佛香。", "我亦暮年思屏迹，數椽何計得連牆。"]'),
('2fb48dc2-2c06-4fbb-a987-4d813150786d','冬夜聽雨戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','少年交友盡豪英，妙理時時得細評。',32,'全唐诗/poet.song.128000.json','["少年交友盡豪英，妙理時時得細評。", "老去同參惟夜雨，焚香卧聽畫簷聲。"]'),
('e2dee7a1-65e6-46df-913f-01f8fba48a2b','冬夜聽雨戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','繞簷點滴如琴筑，支枕幽齋聽始奇。',32,'全唐诗/poet.song.128000.json','["繞簷點滴如琴筑，支枕幽齋聽始奇。", "憶在錦城歌吹海，七年夜雨不曾知。"]'),
('eec51239-5d2e-41e1-b259-9c1b61166a3b','適閩','陸游','宋','宋诗','song-poetry','','[]','春殘猶看少城花，雪裏來嘗北苑茶。',64,'全唐诗/poet.song.128000.json','["春殘猶看少城花，雪裏來嘗北苑茶。", "未恨光陰疾駒隙，但驚世界等河沙。", "功名塞外心空壯，詩酒樽前髮已華。", "官柳弄黄梅放白，不堪倦馬又天涯。"]'),
('b08ff37f-3aa8-4ef4-a695-ab6931ff8d3a','欲行雨未止','陸游','宋','宋诗','song-poetry','','[]','幽幔依燈影，空階送雨聲。',48,'全唐诗/poet.song.128000.json','["幽幔依燈影，空階送雨聲。", "蹔歸仍客路，投老倍鄉情。", "眼澀書難讀，心揺夢易驚。", "病多常怕醉，酒盡却思傾。"]'),
('4d815ce0-0931-4dee-8a2f-9ee1bcf8debf','比作陳下瓜麴釀成奇絕屬病瘍不敢取醉小啜而已','陸游','宋','宋诗','song-poetry','','[]','翠蔓扶疏采擷忙，麴生糸出古淮陽。',64,'全唐诗/poet.song.128000.json','["翠蔓扶疏采擷忙，麴生糸出古淮陽。", "蹋成明月團團白，釀作新鵝淡淡黄。", "醅甕秋凄驚凛冽，糟床夜注愛淋浪。", "西齋幽事新成譜，首爲高人著此方。"]'),
('5b4a1a3c-3aaa-4e98-89d6-ba64624196d5','大雨中離三山宿天章寺','陸游','宋','宋诗','song-poetry','','[]','苦雨催寒不肯晴，晚來餘勢更縱横。',64,'全唐诗/poet.song.128000.json','["苦雨催寒不肯晴，晚來餘勢更縱横。", "雲如山壞長空黑，風似潮回萬木傾。", "要借關河供遠眼，不辭泥淖困初程。", "解衣一笑僧窗下，幾兩青鞵了此生。"]'),
('98c6c516-adcd-4874-bc29-70a60b130bca','早飯干溪蓋干吉故居也','陸游','宋','宋诗','song-poetry','','[]','劍外歸來席未温，南征浩蕩信乾坤。',64,'全唐诗/poet.song.128000.json','["劍外歸來席未温，南征浩蕩信乾坤。", "峰回內史曾遊地，竹暗仙人舊隱村。", "白髮孤翁鉏麥壟，茜裙小婦闖籬門。", "行行莫動鄉關念，身似流槎豈有根。"]'),
('8397661d-9a63-4c0d-bf3a-9b7f0b1ef4bd','贈楓橋化城院老僧','陸游','宋','宋诗','song-poetry','','[]','老宿禪房裏，深居罷送迎。',48,'全唐诗/poet.song.128000.json','["老宿禪房裏，深居罷送迎。", "爐紅豆萁火，糝白芋魁羮。", "毳衲年年補，紗燈夜夜明。", "門前霜半寸，笑我事晨征。"]'),
('75572388-d464-4537-b40e-f461050c94ed','雙橋道中寒甚','陸游','宋','宋诗','song-poetry','','[]','裂面霜風快似鎌，重重裘袴晚仍添。',64,'全唐诗/poet.song.128000.json','["裂面霜風快似鎌，重重裘袴晚仍添。", "梅當官道香撩客，山逼籃輿翠入簾。", "男子坐爲衣食役，年光常向道途淹。", "古來共說還家樂，豈獨全軀畏楚鉗。"]'),
('97ee186c-5dc3-4e78-826d-e4bfdb616689','行牌頭奴寨之間皆建炎末避賊所經也','陸游','宋','宋诗','song-poetry','','[]','今朝霜薄風氣和，霽色滿野行人多。',132,'全唐诗/poet.song.128000.json','["今朝霜薄風氣和，霽色滿野行人多。", "沙平水淺木葉下，揺檝渡口生微波。", "建炎避兵奔竄地，誰料白首重經過。", "四十餘年萬事改，惟有青嶂高嵯峨。", "安得西國蒲萄酒，滿酌南海鸚鵡螺。", "侑以吳松長絲之玉鱠，送以邯鄲皓齒之清歌。", "向來喪亂汝所記，大地凛凛憂干戈。", "偶然不死到老大，爲底苦惜朱顔酡。"]'),
('ee49746b-88eb-4a13-b223-a935372b4779','早發奴寨','陸游','宋','宋诗','song-poetry','','[]','暖徹衣篝蠟炬明，鄰雞喔喔促殘更。',64,'全唐诗/poet.song.128000.json','["暖徹衣篝蠟炬明，鄰雞喔喔促殘更。", "丈夫雖有四方志，客子終悲千里行。", "月落龍蛇蟠木影，山空風雨起灘聲。", "上車莫恨晨霜冷，又得修途一日晴。"]'),
('e209d03a-93c5-4bf3-bd84-1b2c23485350','題繡川驛','陸游','宋','宋诗','song-poetry','','[]','繡川池閣記曾遊，落日欄邉特地愁。',64,'全唐诗/poet.song.128000.json','["繡川池閣記曾遊，落日欄邉特地愁。", "白首即今行萬里，淡烟依舊送孤舟。", "歸心久負鱸魚鱠，春色初回杜若洲。", "會買一蓑來釣雨，憑誰先爲謝沙鷗。"]'),
('a9ad3c31-964c-4a04-9bfb-acc568337d59','夜行宿湖頭寺','陸游','宋','宋诗','song-poetry','','[]','卧載藍輿黄葉村，疏鐘杳杳隔谿聞。',64,'全唐诗/poet.song.128000.json','["卧載藍輿黄葉村，疏鐘杳杳隔谿聞。", "清霜十里伴微月，斷雁半行穿亂雲。", "去國不堪心破碎，平戎空有膽輪囷。", "泗濱樂石應如舊，誰勒中原第一勲。"]'),
('42b6eba5-1e69-4f2d-93a3-6bdc64aba9b8','衢州道中作','陸游','宋','宋诗','song-poetry','','[]','耿耿孤忠不自勝，南來清夢遶觚稜。',64,'全唐诗/poet.song.128000.json','["耿耿孤忠不自勝，南來清夢遶觚稜。", "驛門上馬千峰雪，寺壁題詩一硯冰。", "疾病時時須藥物，衰遲處處少交朋。", "無情最恨寒沙雁，不爲愁人說杜陵。"]'),
('6a7a35ca-6190-4609-87d8-80ffbe4d6870','過靈石三峰二首  其一','陸游','宋','宋诗','song-poetry','','[]','奇峰迎馬駭衰翁，蜀嶺吳山一洗空。',32,'全唐诗/poet.song.128000.json','["奇峰迎馬駭衰翁，蜀嶺吳山一洗空。", "拔地青蒼五千仞，勞渠蟠屈小詩中。"]'),
('54a99fc4-8ee6-44d2-a21b-f575b2ba6e88','過靈石三峰二首  其二','陸游','宋','宋诗','song-poetry','','[]','曉日曈曨雪未殘，三峰傑立插雲間。',32,'全唐诗/poet.song.128000.json','["曉日曈曨雪未殘，三峰傑立插雲間。", "老夫合是征西將，胸次先收一華山。"]'),
('839b8bf8-4fce-40e4-babb-da8fd90122b4','宿僊霞嶺下','陸游','宋','宋诗','song-poetry','','[]','吾生真是一枯蓬，行徧人間路未窮。',64,'全唐诗/poet.song.128000.json','["吾生真是一枯蓬，行徧人間路未窮。", "暫聽朝雞雙闕下，又騎羸馬萬山中。", "重裘不敵晨霜力，老木爭號夜谷風。", "切勿重尋散關夢，朱顔改盡壯圖空。"]'),
('370bd70d-1d91-404a-9011-1f14b039f427','道中病瘍久不飲酒至魚梁小酌因賦長句','陸游','宋','宋诗','song-poetry','','[]','我行浦城道，小疾屏杯酌。',96,'全唐诗/poet.song.128000.json','["我行浦城道，小疾屏杯酌。", "癬疥何足言，亦復妨作樂。", "此身會當壊，百歲圴電雹。", "胡爲過自惜，憊卧困鍼烙。", "未嘗膾噞喁，况敢烹郭索。", "今朝寓空驛，窗戸寒寂寞。", "悠然忽自笑，頓解貪愛縛。", "紅燭映緑樽，奇哉萬金藥。"]'),
('69356d84-3cfc-44ad-876b-6a9470881a48','宿魚梁驛五鼓起行有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','憶從南鄭客成都，身健官閑一事無。',64,'全唐诗/poet.song.128000.json','["憶從南鄭客成都，身健官閑一事無。", "分騎霜天伐狐兔，張燈雪夜擲梟盧。", "百憂忽墮新衰境，一笑難尋舊酒徒。", "投宿魚梁溪遶屋，五更聽雨擁篝爐。"]'),
('a710ad14-fbfd-49af-bcec-5390b1bca4f3','宿魚梁驛五鼓起行有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','少時談舌坐生風，管葛奇才自許同。',64,'全唐诗/poet.song.128000.json','["少時談舌坐生風，管葛奇才自許同。", "閉戶著書千古計，變名學劍十年功。", "酒醒頓覺狂堪笑，睡起方知夢本空。", "他日故人能憶我，葛僊磯畔覓漁翁。"]'),
('f621f274-37b6-4c15-8a84-cd9f0a0aebde','夢藤驛二首  其一','陸游','宋','宋诗','song-poetry','','[]','倦馬投孤驛，一峰青壓門。',48,'全唐诗/poet.song.128000.json','["倦馬投孤驛，一峰青壓門。", "蕭條秋浦路，荒陋夜郎村。", "地瘴霜常薄，林深日易昏。", "百年常作客，排悶近清樽。"]'),
('075a5c3c-85ee-4a08-98e1-2ed70f8037f7','夢藤驛二首  其二','陸游','宋','宋诗','song-poetry','','[]','又入千山去，真成萬里行。',48,'全唐诗/poet.song.128000.json','["又入千山去，真成萬里行。", "履霜常早駕，秉炬或宵征。", "古驛怪藤合，荒陂群雁鳴。", "客中常少睡，歸夢若爲成。"]'),
('e4bb40b8-0e6d-45a2-aa24-1a6c93332e19','梅花絕句十首  其一','陸游','宋','宋诗','song-poetry','','[]','空谷佳人洛浦仙，洗粧真態更嬋娟。',32,'全唐诗/poet.song.128000.json','["空谷佳人洛浦仙，洗粧真態更嬋娟。", "廣平莫倚心如鐵，撩起清愁又破禪。"]'),
('4cafdfab-d3e0-4854-a8db-4d5b842019e4','梅花絕句十首  其二','陸游','宋','宋诗','song-poetry','','[]','月中疏影雪中香，只爲無言更斷腸。',32,'全唐诗/poet.song.128000.json','["月中疏影雪中香，只爲無言更斷腸。", "曾與詩翁定花品，一丘一壑過姚黄。"]'),
('17f85fc3-d0db-42cd-9de9-e6dfbc79b480','梅花絕句十首  其三','陸游','宋','宋诗','song-poetry','','[]','折得梅花愧滿顔，文書堆案正如山。',32,'全唐诗/poet.song.128000.json','["折得梅花愧滿顔，文書堆案正如山。", "輸君一覺翛然夢，長在清泉白石間。"]'),
('fe138806-809f-4e3f-b054-d17a56303bf3','梅花絕句十首  其四','陸游','宋','宋诗','song-poetry','','[]','濯錦江邊憶舊遊，纒頭百萬醉青樓。',32,'全唐诗/poet.song.128000.json','["濯錦江邊憶舊遊，纒頭百萬醉青樓。", "如今莫索梅花笑，古驛燈前各自愁。"]'),
('0480d01a-3e80-4465-a28d-dc1dcaeb20f1','梅花絕句十首  其五','陸游','宋','宋诗','song-poetry','','[]','蜀王小苑舊池臺，江北江南萬樹梅。',32,'全唐诗/poet.song.128000.json','["蜀王小苑舊池臺，江北江南萬樹梅。", "只怪朝來歌吹閙，園官已報五分開。"]'),
('9cb0328a-8025-49e9-ada6-d17a5cb30cb7','梅花絕句十首  其六','陸游','宋','宋诗','song-poetry','','[]','湖上梅花手自移，小橋風月最相宜。',32,'全唐诗/poet.song.128000.json','["湖上梅花手自移，小橋風月最相宜。", "主人歲歲常爲客，莫怪幽香怨不知。"]'),
('357a1655-27c5-45a2-8150-6bec2712c82e','梅花絕句十首  其七','陸游','宋','宋诗','song-poetry','','[]','吾州古梅舊得名，雲蒸雨漬緑苔生。',32,'全唐诗/poet.song.128000.json','["吾州古梅舊得名，雲蒸雨漬緑苔生。", "一枝只好儈窗看，莫售千金入鳯城。"]'),
('636bf20e-8741-4913-80c1-fff2d3143c7a','梅花絕句十首  其八','陸游','宋','宋诗','song-poetry','','[]','探春歲歲在天涯，醉裏題詩字半斜。',32,'全唐诗/poet.song.128000.json','["探春歲歲在天涯，醉裏題詩字半斜。", "今日谿頭還小飲，冷官不禁看梅花。"]'),
('ed18d5f3-c051-49d8-bc52-b2e123ec5f9e','梅花絕句十首  其九','陸游','宋','宋诗','song-poetry','','[]','池館登臨雪半消，梅花與我兩無聊。',32,'全唐诗/poet.song.128000.json','["池館登臨雪半消，梅花與我兩無聊。", "青羊宮裏應如舊，腸斷春風萬里橋。"]'),
('29cbf424-012a-4440-87b6-e71c3bc73b4e','梅花絕句十首  其一○','陸游','宋','宋诗','song-poetry','','[]','今年真負此花時，醉帽何曾插一枝。',32,'全唐诗/poet.song.128000.json','["今年真負此花時，醉帽何曾插一枝。", "漸老情懷多作惡，不堪還作送梅詩。"]'),
('f2001958-5b31-4572-b6f2-05255ad78704','對酒','陸游','宋','宋诗','song-poetry','','[]','識字記姓名，擊劍一人敵。',96,'全唐诗/poet.song.128000.json','["識字記姓名，擊劍一人敵。", "孫吳相斫書，了解亦何益。", "不如黄金罍，瀲瀲春波碧。", "欣然對之笑，未飲愁已釋。", "白頭生黑絲，蒼顔桃李色。", "金丹空九轉，正恐無此力。", "朝飲績五斗，莫飲髠一石。", "寄謝采芝翁，無爲老青壁。"]'),
('a98e475d-70a2-4d9a-8a73-badd547850fb','遣興','陸游','宋','宋诗','song-poetry','','[]','西州落魄九年餘，濯錦江頭已結廬。',64,'全唐诗/poet.song.128000.json','["西州落魄九年餘，濯錦江頭已結廬。", "誰遣徑歸朝鳳闕，不令小住奉魚書。", "塵埃眯目詩情盡，疾病侵人酒興疏。", "寄語鶯花休入夢，世間萬事有乘除。"]'),
('a5fd8c83-814f-4523-8e58-397c196df2ff','建安雪','陸游','宋','宋诗','song-poetry','','[]','建溪官茶天下絕，香味欲全須小雪。',64,'全唐诗/poet.song.128000.json','["建溪官茶天下絕，香味欲全須小雪。", "雪飛一片茶不憂，何況蔽空如舞鷗。", "銀瓶銅碾春風裏，不枉年来行萬里。", "從渠荔子腴玉膚，自古難兼熊掌魚。"]'),
('611da4c5-8353-450d-a9af-d8a126703a5f','雪晴至後園二首  其一','陸游','宋','宋诗','song-poetry','','[]','病扶藤杖覓殘梅，牢落情懷怕酒杯。',32,'全唐诗/poet.song.128000.json','["病扶藤杖覓殘梅，牢落情懷怕酒杯。", "約束園丁勤灑掃，新年作意待春来。"]'),
('50ad130f-3630-4746-b8c1-014dda9beb4c','雪晴至後園二首  其二','陸游','宋','宋诗','song-poetry','','[]','寶馬東風擁犢車，碧雞坊裏擅豪華。',32,'全唐诗/poet.song.128000.json','["寶馬東風擁犢車，碧雞坊裏擅豪華。", "南来強作尋春夢，何處如今更有花。"]'),
('e9e5bcda-327a-452b-994a-924a85df25f3','開元暮歸','陸游','宋','宋诗','song-poetry','','[]','白髮書生不自珍，天涯又作宦遊身。',64,'全唐诗/poet.song.128000.json','["白髮書生不自珍，天涯又作宦遊身。", "谿橋烟淡偏宜晚，野寺花遲未覺春。", "日暖登山思謝屐，病餘漉酒負陶巾。", "茹芝却粒平生事，回首巖扉一愴神。"]'),
('023220a9-241b-4ad6-9dad-619c2c7cd257','書懷','陸游','宋','宋诗','song-poetry','','[]','濯錦江頭成昨夢，紫芝山下又新年。',64,'全唐诗/poet.song.128000.json','["濯錦江頭成昨夢，紫芝山下又新年。", "久因多病疏雲液，近爲長齋進玉延。", "啼鳥傍簷春寂寂，飛花掠水晚翩翩。", "支離自笑生涯别，一炷爐香繡佛前。"]'),
('c3680bf2-5d48-419c-91ec-5f001e2c0d49','遊鳳皇山','陸游','宋','宋诗','song-poetry','','[]','窮日文書有底忙，幅巾蕭散集山堂。',64,'全唐诗/poet.song.128000.json','["窮日文書有底忙，幅巾蕭散集山堂。", "一樽病起初浮白，連焙春遲未過黄。", "坐上清風隨麈柄，歸途微雨發松香。", "臨溪更覓投竿地，我欲時来小作狂。"]'),
('3e8a0132-ba4d-4619-9f57-a0c17fb2454c','園中雜書四首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭蕭慈竹鳥呼風，宛似山光小閣東。',32,'全唐诗/poet.song.128000.json','["蕭蕭慈竹鳥呼風，宛似山光小閣東。", "剩欲杖藜尋昨夢，更添紅綻緑陰中。"]'),
('3cd42e59-c198-45f3-9896-ed152bd5a4e0','園中雜書四首  其二','陸游','宋','宋诗','song-poetry','','[]','北窗看鏡意凄然，夢斷梁州已七年。',32,'全唐诗/poet.song.128000.json','["北窗看鏡意凄然，夢斷梁州已七年。", "獵獵綵旗春日晚，不堪花外見鞦韆。"]'),
('7c3921ba-fb21-45db-85aa-f4889a3669e8','園中雜書四首  其三','陸游','宋','宋诗','song-poetry','','[]','筍生密密復疏疏，来看偏宜曉雨餘。',32,'全唐诗/poet.song.128000.json','["筍生密密復疏疏，来看偏宜曉雨餘。", "乞與人間作圖畫，幅巾短褐小籃輿。"]'),
('3592f0e3-30eb-402e-aedc-f5bf84c6d2b6','園中雜書四首  其四','陸游','宋','宋诗','song-poetry','','[]','殘花委地筍掀泥，香椀詩囊到處攜。',32,'全唐诗/poet.song.128000.json','["殘花委地筍掀泥，香椀詩囊到處攜。", "幽夢欲成誰喚覺，半窗斜日鷓鴣啼。"]'),
('ca0bb220-e31d-4409-b376-8a64db64f073','烹茶','陸游','宋','宋诗','song-poetry','','[]','麴生可論交，正自畏中聖。',72,'全唐诗/poet.song.128000.json','["麴生可論交，正自畏中聖。", "年来衰可笑，茶亦能作病。", "噎嘔廢晨飱，支離失宵暝。", "是身如芭蕉，寧可與物競。", "兔甌試玉塵，香色兩超勝。", "把玩一欣然，爲汝烹茶竟。"]'),
('dd3a19c8-fa76-49ef-a79e-8a0736bd8d0a','病中久止酒有懷成都海棠之盛','陸游','宋','宋诗','song-poetry','','[]','碧雞坊裏海棠時，彌月兼旬醉不知。',64,'全唐诗/poet.song.128000.json','["碧雞坊裏海棠時，彌月兼旬醉不知。", "馬上難尋前夢境，樽前誰記舊歌辭。", "目窮落日橫千嶂，腸斷春風把一枝。", "說與故人應不信，茶烟禪榻鬢成絲。"]'),
('4e07c9e7-082d-4919-9de2-87bcb143cb21','北齋','陸游','宋','宋诗','song-poetry','','[]','新竹侵幽幔，疏蓮散遠汀。',48,'全唐诗/poet.song.128000.json','["新竹侵幽幔，疏蓮散遠汀。", "研朱朝點易，搗蘖夜潢經。", "巖壑知心賞，琴樽樂性靈。", "會當煩太史，一奏少微星。"]'),
('188d7d4e-fcb3-4fd3-a9f1-9d6e90062887','出塞曲','陸游','宋','宋诗','song-poetry','','[]','千騎爲一隊，萬騎爲一軍。',104,'全唐诗/poet.song.128000.json','["千騎爲一隊，萬騎爲一軍。", "朝踐狼山雪，暮宿榆關雲。", "將軍羽箭不虛發，直到祁連無雁群。", "隆隆春雷收陣鼓，蜿蜿驚蛇射生弩。", "落蕃遺民立道邊，白髮如霜泪如雨。", "褫魄胡兒作窮鼠，競裹頭顱不敢語。", "陣前乞降馬前舞，檄書夜入黄龍府。"]'),
('fad5d31c-4d01-4210-bdf6-e33b245f4c49','思故山','陸游','宋','宋诗','song-poetry','','[]','千金不須買畫圖，聽我長歌歌鏡湖。',152,'全唐诗/poet.song.128000.json','["千金不須買畫圖，聽我長歌歌鏡湖。", "湖山奇麗說不盡，且復爲子陳吾廬。", "柳姑廟前魚作市，道士莊畔菱爲租。", "一彎畫橋出林薄，兩岸紅蓼連菰蒲。", "陂南陂北鴉陣黑，舍西舍東楓葉赤。", "正當九月十月時，放翁艇子無時出。", "舩頭一束書，舩後一壺酒。", "新釣紫鱖魚，旋洗白蓮藕。", "從渠貴人食萬錢，放翁癡腹常便便。", "暮歸稚子迎我笑，遥指一抹西村烟。"]'),
('b9aefe94-7f63-4ca6-baaf-3f0b7bafc98b','送錢仲耕修撰','陸游','宋','宋诗','song-poetry','','[]','姑孰溪邊識勝流，十年重見豈人謀。',64,'全唐诗/poet.song.128000.json','["姑孰溪邊識勝流，十年重見豈人謀。", "自應客路難爲别，不是陽關作許愁。", "儤直公看鼇禁月，倦遊我夢鏡湖秋。", "殷勤爲報中朝舊，睡足平生是建州。"]'),
('f99be42b-eb02-4b37-ac44-da8934304933','建寧重五','陸游','宋','宋诗','song-poetry','','[]','霏微入戸黄梅雨，磊落堆盤碧筒黍。',96,'全唐诗/poet.song.128000.json','["霏微入戸黄梅雨，磊落堆盤碧筒黍。", "病来一滴不飲酒，但嗅菖蒲作端午。", "人生忽忽東逝波，白頭奈此節物何。", "去年已作歸州客，今年建州更愁絕。", "歸州猿吟鳥啼裏，屈沱醉歸詩滿紙。", "即今憶此那可得，西望歸州三嘆息。"]'),
('5c6daecd-f250-4c16-a778-408a9ec1d5dc','雨晴至園中','陸游','宋','宋诗','song-poetry','','[]','入夏經月雨，園路久已荒。',96,'全唐诗/poet.song.128000.json','["入夏經月雨，園路久已荒。", "今朝偶一到，蒿艾如人長。", "豈惟鼃黽豪，頗覺蜂蝶狂。", "悵然懷故山，舍東百本桑。", "迨此積雨餘，枝葉沃以光。", "父老適相遇，藉草揮一觴。", "一觴頽然醉，笑語相扶將。", "賦詩示兒子，此樂未易忘。"]'),
('51b69360-aa57-4b0c-bc08-73a0a3cd3223','夏日三首  其一','陸游','宋','宋诗','song-poetry','','[]','微風過中庭，庭樹颯有聲。',24,'全唐诗/poet.song.128000.json','["微風過中庭，庭樹颯有聲。", "穿簾徐入座，巾屨有餘清。"]'),
('66739a12-fb0a-4b91-95a4-5e11ba18a2a5','夏日三首  其二','陸游','宋','宋诗','song-poetry','','[]','展畫發古香，弄筆娛晝寂。',24,'全唐诗/poet.song.128000.json','["展畫發古香，弄筆娛晝寂。", "是中亦何好，使我喜忘食。"]'),
('c8e826d8-7299-4652-8ee0-81497370e3ba','夏日三首  其三','陸游','宋','宋诗','song-poetry','','[]','呼兒整吾駕，駕言返林廬。',24,'全唐诗/poet.song.128000.json','["呼兒整吾駕，駕言返林廬。", "可使臨老眼，常親吏文書。"]'),
('c87b3959-5a0f-4c8b-9059-3e260587435f','發書畫還故山戲書','陸游','宋','宋诗','song-poetry','','[]','昨日遣畫笥，今日發書簏。',72,'全唐诗/poet.song.128000.json','["昨日遣畫笥，今日發書簏。", "空齋惟一床，窗影亂風竹。", "平生鑽故紙，夙好老尤篤。", "奇哉掃除盡，蟬蛻三萬軸。", "豈惟息煩心，亦足養病目。", "從渠褦襶生，自獻公車牘。"]'),
('810efb60-03d7-42d5-8adc-699bf1723438','白髮','陸游','宋','宋诗','song-poetry','','[]','白髮千莖緑鬢稀，臥看鵷鷺刺天飛。',64,'全唐诗/poet.song.128000.json','["白髮千莖緑鬢稀，臥看鵷鷺刺天飛。", "平生竊鄙貢公喜，故里但思陶令歸。", "清坐了無書可讀，殘年賴有佛堪依。", "君看世事皆虚幻，屏酒長齋豈必非。"]'),
('727229b6-dafa-49f1-9618-3e92c9bce839','懷譚德稱','陸游','宋','宋诗','song-poetry','','[]','譚子文章舊有聲，幾年同客錦官城。',64,'全唐诗/poet.song.128000.json','["譚子文章舊有聲，幾年同客錦官城。", "江樓列炬千鍾飲，花市聮鞍一字行。", "人世絕知非昨夢，天真堪笑博浮名。", "空齋獨夜蕭蕭雨，枕上詩成夢不成。"]'),
('923e4088-bd45-4212-8362-8cd31cefaef8','客思二首  其一','陸游','宋','宋诗','song-poetry','','[]','千里關山道路賒，可憐客子費年華。',64,'全唐诗/poet.song.128000.json','["千里關山道路賒，可憐客子費年華。", "杯觴灧灧紅燒酒，風露盈盈紫笑花。", "孤月有情来海嶠，雙魚無信到天涯。", "此生那得常飄泊，歸臥東溪弄釣車。"]'),
('670fcb7e-12df-414f-a643-4975fe802ed9','客思二首  其二','陸游','宋','宋诗','song-poetry','','[]','兩鬢星星久倦遊，凄涼況復寓南州。',64,'全唐诗/poet.song.128000.json','["兩鬢星星久倦遊，凄涼況復寓南州。", "未甘蟋蟀專清夜，已嘆梧桐報素秋。", "綺語安能敵生死，熱官正欲快恩讐。", "空堂飽作東歸夢，夢泊嚴灘月滿舟。"]'),
('214f1531-d449-4501-aa37-e27343b402e3','建安遣興六首  其一','陸游','宋','宋诗','song-poetry','','[]','建安酒薄客愁濃，除却哦詩事事慵。',32,'全唐诗/poet.song.128000.json','["建安酒薄客愁濃，除却哦詩事事慵。", "不許今年頭不白，城樓殘角寺樓鐘。"]'),
('69f95eec-fca5-47fd-8e10-45ae4f900f75','建安遣興六首  其二','陸游','宋','宋诗','song-poetry','','[]','錦城重到嘆無期，忽憶書臺步月時。',32,'全唐诗/poet.song.128000.json','["錦城重到嘆無期，忽憶書臺步月時。", "白浪黏天鮫鰐橫，夢中識路亦何爲。"]'),
('7665875d-326b-4367-b0bc-75716ae13a03','建安遣興六首  其三','陸游','宋','宋诗','song-poetry','','[]','今歲清詩欠百篇，強尋筆硯意茫然。',32,'全唐诗/poet.song.128000.json','["今歲清詩欠百篇，強尋筆硯意茫然。", "秋風有句君知否，合在嚴光釣瀨邊。"]'),
('9aad966a-b254-4da9-8e53-3631ac12e22d','建安遣興六首  其四','陸游','宋','宋诗','song-poetry','','[]','古今清絕沅湘路，臥想蒲帆十幅開。',32,'全唐诗/poet.song.128000.json','["古今清絕沅湘路，臥想蒲帆十幅開。", "不是避人思遠適，肺肝塵土要詩才。"]'),
('71ccf3e9-4f86-4cee-b7ec-1b82d1edf06a','建安遣興六首  其五','陸游','宋','宋诗','song-poetry','','[]','緑沈金鎖少時狂，幾過秋風古戰場。',32,'全唐诗/poet.song.128000.json','["緑沈金鎖少時狂，幾過秋風古戰場。", "夢裏都忘閩嶠遠，萬人鼓吹入平涼。"]'),
('780b0d05-0e69-4c4f-9900-db88042eb9b6','建安遣興六首  其六','陸游','宋','宋诗','song-poetry','','[]','刺虎騰身萬目前，白袍濺血尚依然。',32,'全唐诗/poet.song.128000.json','["刺虎騰身萬目前，白袍濺血尚依然。", "聖時未用驍騰將，虚老龍門一少年。"]'),
('c0540d45-1726-43a0-be7d-b85c086f1877','病起偶到復庵','陸游','宋','宋诗','song-poetry','','[]','經旬羸臥怯登臨，偶憶東庵試一尋。',64,'全唐诗/poet.song.128000.json','["經旬羸臥怯登臨，偶憶東庵試一尋。", "新竹初成迷棧路，斷雲不散抱城陰。", "陂池緑靜龜魚樂，亭館蒼涼草樹深。", "欲把一杯無奈懶，病来觸目動歸心。"]'),
('dbd86d2c-6b20-4e57-a9e0-709279cf747d','前有樽酒行二首  其一','陸游','宋','宋诗','song-poetry','','[]','虛堂雨過生涼颸，勸君一醉君勿辭。',96,'全唐诗/poet.song.128000.json','["虛堂雨過生涼颸，勸君一醉君勿辭。", "去年不知今歲事，明年萬事今得知。", "舊時扶床同戲兒，還鄉問訊令人悲。", "冢丘累累在者誰，紙錢雨濕抱樹枝。", "君去六十有幾時，更望七十何其癡。", "求師學道亦已遲，謝客努力從鴟夷。"]'),
('30f99a05-e08c-4ef2-9bca-741f6fc5e4d8','前有樽酒行二首  其二','陸游','宋','宋诗','song-poetry','','[]','緑酒盎盎盈芳樽，清歌嫋嫋留行雲。',96,'全唐诗/poet.song.128000.json','["緑酒盎盎盈芳樽，清歌嫋嫋留行雲。", "美人千金織寶裙，水沈龍腦作燎焚。", "問君胡爲慘不樂，四紀妖氛暗幽朔。", "諸人但欲口擊賊，茫茫九原誰可作。", "丈夫可爲酒色死，戰場橫屍勝床第。", "華堂樂飲自有時，少待擒胡獻天子。"]'),
('d5b7fc4b-a764-4915-ad8b-21b932232d17','遊南塔院','陸游','宋','宋诗','song-poetry','','[]','小破文書夢，閑成杖履遊。',48,'全唐诗/poet.song.128000.json','["小破文書夢，閑成杖履遊。", "澗幽泉激激，院靜竹修修。", "病骨涼如洗，歸心浩莫收。", "舩輕不載石，一葉亂沙鷗。"]'),
('7180e5d6-b0c3-4fc4-bdf1-b79f5181a0b1','感懷','陸游','宋','宋诗','song-poetry','','[]','半年建安城，士友闕還往。',72,'全唐诗/poet.song.128000.json','["半年建安城，士友闕還往。", "出門每太息，還舍猶惝怳。", "有酒誰與傾，得句空自賞。", "疏直觸人情，低回泚吾顙。", "豈無佳山水，正爾寄夢想。", "何當載親朋，烟浦揺兩槳。"]'),
('771de7be-c721-4239-87b4-54d13ff89071','雨夜','陸游','宋','宋诗','song-poetry','','[]','一雨遂通夕，安眠失百憂。',48,'全唐诗/poet.song.128000.json','["一雨遂通夕，安眠失百憂。", "窗扉淡欲曉，枕簟凜生秋。", "畫燭爭碁道，金尊數酒籌。", "依然錦城夢，忘却在南州。"]'),
('74bd1061-0682-405e-a806-496cf13e6437','夜坐偶書','陸游','宋','宋诗','song-poetry','','[]','衰髮蕭疏雪滿簪，莫年光景易駸駸。',64,'全唐诗/poet.song.128000.json','["衰髮蕭疏雪滿簪，莫年光景易駸駸。", "已甘身作溝中斷，不願人知爨下音。", "病鶴摧頽分薄俸，悲蛩斷續和微吟。", "向来誤有功名念，欲挽天河洗此心。"]'),
('48823155-008d-4a93-b427-0875d1ff5681','長歌行','陸游','宋','宋诗','song-poetry','','[]','人生宦遊亦不惡，無奈從来宦情薄。',134,'全唐诗/poet.song.128000.json','["人生宦遊亦不惡，無奈從来宦情薄。", "既不能短衣射虎在南山，又不能鬬雞走馬宴平樂。", "惟有釣舩差易具，問君胡爲不歸去。", "片雲雨暗玉笥峰，斜日人爭石旗渡。", "渡頭酒壚堪醉眠，白酒醇釅鱸魚鮮。", "菰米如珠炊正熟，蓴羮似酪不論錢。", "翁唱菱歌兒舞櫂，醉耳那知朝市閙。", "城門幾度送迎官，睡擁亂蓑呼未覺。"]'),
('0cfcd445-9df3-47c2-babc-49d06582c3a1','雨夜不寐觀壁間所張魏鄭公砥柱銘','陸游','宋','宋诗','song-poetry','','[]','疾風三日橫吹雨，竹倒荷傾可憐汝。',96,'全唐诗/poet.song.128000.json','["疾風三日橫吹雨，竹倒荷傾可憐汝。", "空堂無人夜向中，臥看床前燭花吐。", "壯懷耿耿誰與論，榰床老龜不能語。", "世間豈無一好漢，叱咤喑嗚力如虎。", "壁間三丈砥柱銘，貞觀太平如更覩。", "何當鼓吹渡河津，下馬觀碑馳馬去。"]'),
('c533eea8-3140-433f-86a8-4fe62690e370','客談荆渚武昌慨然有作','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去歲出蜀初東遊，峨舸大艑下荆州。',128,'全唐诗/poet.song.128000.json','["去歲出蜀初東遊，峨舸大艑下荆州。", "便風轉頭五百里，吟嘯已在黄鶴樓。", "戲拈鐵笛吹出塞，水涌月落魚龍愁。", "明朝喧傳古仙過，碧玉带束黄絁裘。", "豈知一官自桎梏，簿書期會無時休。", "豐城寶劍已化久，我自吐氣冲斗牛。", "洞庭四萬八千頃，蟹舍正對蘆花洲。", "速脫衣冠挂神武，散髮爛醉垂虹秋。"]'),
('73aa0af0-68b1-45bd-825e-b66221cda631','書懷','陸游','宋','宋诗','song-poetry','','[]','青城結雲巢，擬住三千年。',120,'全唐诗/poet.song.128000.json','["青城結雲巢，擬住三千年。", "御風偶南遊，萬里棲紫烟。", "翠裘緑玉杖，白日凌青天。", "招呼方瞳翁，邂逅鳥爪仙。", "朝咏陰陽歌，暮誦道德篇。", "玉童持碧簡，笙鶴来翩翩。", "海邊武夷山，小留賞宿緣。", "火食非所樂，巾褐常翛然。", "清時未免出，頗息世俗傳。", "行矣秋風高，去采玉井蓮。"]'),
('f40d904e-f031-43d3-ae17-587fdb8d9111','平生','陸游','宋','宋诗','song-poetry','','[]','平生涉世似虚舟，不著胸中一點愁。',64,'全唐诗/poet.song.128000.json','["平生涉世似虚舟，不著胸中一點愁。", "已用浮雲看富貴，肯緣華屋嘆山丘。", "戴溪寒釀千峰雪，嚴瀨聲酣七里秋。", "好景人間隨處有，未埋白骨且閑遊。"]'),
('1eec4e17-7ffa-457d-9aec-aed121d18308','自詠','陸游','宋','宋诗','song-poetry','','[]','遊戲人間歲月多，癡頑將奈此翁何。',64,'全唐诗/poet.song.128000.json','["遊戲人間歲月多，癡頑將奈此翁何。", "放開繩箠牛初熟，照破乾坤鏡未磨。", "日落苔磯閑把釣，雨餘篷舵亂堆蓑。", "明朝不見知何處，又向江湖醉踏歌。"]'),
('e2fa681c-f6af-4b20-8cc1-2af397c2ae08','池亭夜賦','陸游','宋','宋诗','song-poetry','','[]','池上小亭幽，清宵秉燭遊。',48,'全唐诗/poet.song.128000.json','["池上小亭幽，清宵秉燭遊。", "荷盤時瀉露，螢火早知秋。", "有感歲時速，無聲河漢流。", "殊方不堪住，歸夢繞滄洲。"]'),
('1e993f47-36b0-4338-8e99-88534ce7ee48','雨夜偶書','陸游','宋','宋诗','song-poetry','','[]','高臥空堂風雨来，更闌頻看燭花摧。',64,'全唐诗/poet.song.128000.json','["高臥空堂風雨来，更闌頻看燭花摧。", "新涼蕭爽秋期近，多病侵尋老境催。", "萬事極知終變滅，一官那得久低回。", "床頭幸有楞伽在，更炷爐香手自開。"]'),
('dd17255c-08c1-4838-bb57-cc3dc059a977','思歸','陸游','宋','宋诗','song-poetry','','[]','平生無宦情，方外久浪迹。',120,'全唐诗/poet.song.128000.json','["平生無宦情，方外久浪迹。", "往来梁益間，一笑頗自得。", "花穠錦城酒，月白瞿塘笛。", "咿啞下江櫓，跌宕登山屐。", "巴東烟雨秋，渭上風雪夕。", "至今客枕夢，萬里不能尺。", "誰知建安城，觸目非夙昔。", "冥冥瘴霧細，瀲瀲蠻江碧。", "出門無交朋，嗚呼吾何適。", "歸哉故山路，詎必須暖席。"]'),
('b3bccd8d-27b0-4aee-91b7-dfaab6a72b2b','客懷','陸游','宋','宋诗','song-poetry','','[]','客懷耿耿向誰語，世事茫茫空自知。',64,'全唐诗/poet.song.128000.json','["客懷耿耿向誰語，世事茫茫空自知。", "堅坐懶窮牛渚怪，倦遊何恨雁門踦。", "眼前客共一杯酒，身後人傳千首詩。", "報與故交當賀我，計歸猶及菊花時。"]'),
('9294a269-1208-471a-bc55-c793017a7eae','伏中官舍極涼戲作','陸游','宋','宋诗','song-poetry','','[]','盡障東西日，洞開南北堂。',48,'全唐诗/poet.song.128000.json','["盡障東西日，洞開南北堂。", "漏從閑處永，風自遠来涼。", "客愛炊菰美，僧誇瀹茗香。", "曉来秋色起，肅肅滿筠床。"]'),
('3a1156a2-8812-4535-a54c-9e4af57626a1','夢與劉韶美夜飲樂甚','陸游','宋','宋诗','song-poetry','','[]','死生契濶十年餘，欲話交情涕已濡。',64,'全唐诗/poet.song.128000.json','["死生契濶十年餘，欲話交情涕已濡。", "夢裏偶同清夜宴，醉中猶攬故人鬚。", "岸巾談笑今誰記，滿腹詩書只自愚。", "我亦與公同此病，早收身世老江湖。"]'),
('f19a4106-744e-48fb-aa9b-566e425774b3','暑夜','陸游','宋','宋诗','song-poetry','','[]','毒暑彌三伏，微涼起二更。',48,'全唐诗/poet.song.128000.json','["毒暑彌三伏，微涼起二更。", "月窗風竹亂，烟渚露荷傾。", "寂寞借書讀，清羸扶杖行。", "無功耗官廩，太息負平生。"]'),
('2f182c3d-00b1-4afa-afa7-05e12b1fecd4','客意','陸游','宋','宋诗','song-poetry','','[]','山行曳杖水拏舟，走遍茫茫禹畫州。',64,'全唐诗/poet.song.128000.json','["山行曳杖水拏舟，走遍茫茫禹畫州。", "蝴蝶夢魂常是客，芭蕉身世不禁秋。", "早因食少妨高臥，晚憶茶甘作遠遊。", "龍焙一嘗端可去，無心更爲荔枝留。"]'),
('63300b7c-4e7c-4bce-bfa8-c8ecb2ca5319','夜香','陸游','宋','宋诗','song-poetry','','[]','投老誤乘傳，竊食慚無功。',72,'全唐诗/poet.song.128000.json','["投老誤乘傳，竊食慚無功。", "清夜一炷香，實與天心通。", "忤物雖至愚，許國猶孤忠。", "一念倘自欺，百年寧有終。", "上帝職造化，生殺操至公。", "稽首矢此心，其敢累兒童。"]'),
('98c2c03e-ed03-4964-ad2c-c0e54103cacd','柴懷叔殿院世綵堂','陸游','宋','宋诗','song-poetry','','[]','卷服貂冠世間有，榮悴紛紛翻覆手。',128,'全唐诗/poet.song.128000.json','["卷服貂冠世間有，榮悴紛紛翻覆手。", "不如御史老莱衣，世綵堂中奉春酒。", "北斗爲觴山作豆，鳳竹鸞絲太中壽。", "今年宗祀降恩綸，太中拜前公拜後。", "嗚呼人誰無父母，盛事有及公家否。", "萬鍾苦晚三釜薄，人生此恨十八九。", "我欲殺青書孝友，愧非太史馬牛走。", "聖朝若遣采詩官，尚可爲公圖不朽。"]'),
('4fc35c29-0ada-46c8-bef9-e7e979b9af2c','月夜','陸游','宋','宋诗','song-poetry','','[]','小醉初醒月滿床，玉壺銀闕不勝涼。',32,'全唐诗/poet.song.128000.json','["小醉初醒月滿床，玉壺銀闕不勝涼。", "天風忽送荷香過，一葉飄然憶故鄉。"]'),
('0db8d805-42f0-42f8-b7e3-6d7266247d64','雙清堂夜賦','陸游','宋','宋诗','song-poetry','','[]','陸子病少間，獨臥谿上堂。',72,'全唐诗/poet.song.128000.json','["陸子病少間，獨臥谿上堂。", "人靜魚自躍，風定荷更香。", "素月行中天，流螢失孤光。", "歸鳥飛有聲，度此十里塘。", "嗟我獨何事，遲暮客異鄉。", "太息搔短髮，起視夜未央。"]'),
('bde6fc7e-e828-4f08-bce1-731c5fc4a448','采蓮三首  其一','陸游','宋','宋诗','song-poetry','','[]','蘸水朱扉不上關，采蓮小舫夜深還。',32,'全唐诗/poet.song.128000.json','["蘸水朱扉不上關，采蓮小舫夜深還。", "一樽何處無風月，自是人生苦欠閑。"]'),
('e2112c70-49e7-4913-81ce-f0a3cb1e6505','采蓮三首  其二','陸游','宋','宋诗','song-poetry','','[]','雲散青天挂玉鈎，石城艇子近新秋。',32,'全唐诗/poet.song.128000.json','["雲散青天挂玉鈎，石城艇子近新秋。", "風鬟霧鬢歸来晚，忘却荷花記得愁。"]'),
('ad2ea9d6-e32b-4ca7-b675-ba9cd702d537','采蓮三首  其三','陸游','宋','宋诗','song-poetry','','[]','帝青天映麴塵波，時有遊魚動緑荷。',32,'全唐诗/poet.song.128000.json','["帝青天映麴塵波，時有遊魚動緑荷。", "回首家山又千里，不堪醉裏聽吴歌。"]'),
('28f44bc2-439f-4408-8241-715b03bdb68a','橋南納涼','陸游','宋','宋诗','song-poetry','','[]','曵杖来追柳外涼，畫橋南畔倚胡床。',64,'全唐诗/poet.song.128000.json','["曵杖来追柳外涼，畫橋南畔倚胡床。", "月明舩笛參差起，風定池蓮自在香。", "半落星河知夜久，無窮草樹覺城荒。", "碧筒莫惜頽然醉，人事還隨日出忙。"]'),
('55b445d0-994c-4b9e-9836-d6802a2b92d3','芒屨','陸游','宋','宋诗','song-poetry','','[]','芒屨一雙青，笻枝九節輕。',48,'全唐诗/poet.song.128000.json','["芒屨一雙青，笻枝九節輕。", "登山猶健在，投檄太遲生。", "滿意竹風冷，入懷溪月明。", "清秋故不遠，回首憶蓴羮。"]'),
('bf908cd3-a5b1-44fd-a959-1be8fd1f8690','荔子絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','驛騎星馳亦快哉，筠籠露濕手親開。',32,'全唐诗/poet.song.128000.json','["驛騎星馳亦快哉，筠籠露濕手親開。", "不應相與無平素，曾忝戎州刺史来。"]'),
('f1d5d17d-3396-4cb2-a4fb-02b55f05c8e7','荔子絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','放翁遊蜀十年回，病眼茫茫每懶開。',32,'全唐诗/poet.song.128000.json','["放翁遊蜀十年回，病眼茫茫每懶開。", "怪底酒邊光景别，方紅江緑一時来。"]'),
('16db927f-2346-49a8-9010-355bcc8259ff','官舍夙興','陸游','宋','宋诗','song-poetry','','[]','朝陽淡淡挂窗櫺，桐葉無風忽自零。',64,'全唐诗/poet.song.128000.json','["朝陽淡淡挂窗櫺，桐葉無風忽自零。", "不復扶頭傾白墮，但知臨目養黄寧。", "新蔬带露来幽圃，修綆飛泉灑廣庭。", "一出文書又圍繞，正應高臥盡頽齡。"]'),
('be382c33-9b67-424c-bd88-57309e8370de','書懷','陸游','宋','宋诗','song-poetry','','[]','功名富貴兩茫茫，惟有躬耕策最長。',64,'全唐诗/poet.song.128000.json','["功名富貴兩茫茫，惟有躬耕策最長。", "吏牘沈迷妨養疾，囊衣結束待還鄉。", "洲中未種千頭橘，宅畔先栽百本桑。", "書寄子公吾自懶，故人不是總相忘。"]'),
('fd505854-be79-41b4-a2b1-31c29ace7631','風月','陸游','宋','宋诗','song-poetry','','[]','老来苦無伴，風月獨見知。',72,'全唐诗/poet.song.128000.json','["老来苦無伴，風月獨見知。", "未嘗費招呼，到處相娛嬉。", "披襟萬里快，弄影三更奇。", "淋漓蜀苑酒，散落江樓詩。", "狂歌撼山川，醉墨飛蛟螭。", "聊將調俗子，更遣半生疑。"]'),
('00867860-9b64-4b5c-a32c-3dbd6b57bb79','大將出師歌','陸游','宋','宋诗','song-poetry','','[]','將軍北伐辭前殿，恩詔催排苑中宴。',144,'全唐诗/poet.song.128000.json','["將軍北伐辭前殿，恩詔催排苑中宴。", "紫陌驚塵中使来，青門立馬群公餞。", "繡旗雜沓三十里，畫鼓敲鏗五千面。", "行營暮宿咸陽原，滿朝太息傾都羨。", "天聲一震胡已亡，捷書奕奕如飛電。", "高秋不閉玉關城，中夜罷傳青海箭。", "山川圖籍上有司，張掖酒泉開郡縣。", "還朝策勛兼將相，詔假黄鉞調金鉉。", "丈夫未遇誰得知，昔日新豐笑貧賤。"]'),
('d1cf5753-01f7-4ef1-9273-a1a9926a7357','婕妤怨','陸游','宋','宋诗','song-poetry','','[]','妾昔初去家，鄰里持車箱。',120,'全唐诗/poet.song.128000.json','["妾昔初去家，鄰里持車箱。", "共祝善事主，門戸望寵光。", "一入未央宫，顧盼偶非常。", "穉齒不慮患，傾身保專房。", "燕婉承恩澤，但言日月長。", "豈知辭玉陛，翩若葉隕霜。", "永巷雖放棄，猶慮重謗傷。", "悔不侍宴時，一夕稱千觴。", "妾心剖如丹，妾骨朽亦香。", "後身作羽林，爲國死封疆。"]'),
('6af2b283-1f19-430a-b999-1638456054b0','移疾','陸游','宋','宋诗','song-poetry','','[]','朝来移疾臥虚堂，暫屏文書日更長。',64,'全唐诗/poet.song.128000.json','["朝来移疾臥虚堂，暫屏文書日更長。", "鷗鷺近人情漸熟，簾櫳欲雨意先涼。", "紗巾自照清池影，蕊笈閑銷古篆香。", "莫恨微霜侵緑鬢，爲渠歇盡少年狂。"]'),
('af3cc70d-99b8-45da-bcab-8323e2ad2b5c','病中懷故廬','陸游','宋','宋诗','song-poetry','','[]','我家山陰道，湖山淡空濛。',96,'全唐诗/poet.song.128000.json','["我家山陰道，湖山淡空濛。", "小屋如舴艋，出沒烟波中。", "天寒橘柚黄，霜落䆉稏紅。", "祈蠶簫鼓閙，賽雨雞豚空。", "叉魚有竭作，刈麥無遺功。", "去年一月留，行役嗟匆匆。", "今年歸興動，艤舟待秋風。", "社飲可欠我，寄書約鄰翁。"]'),
('6b208faf-7ab7-462e-aea1-dc04ed54ab7b','夏夜不寐有賦','陸游','宋','宋诗','song-poetry','','[]','急雨初過天宇濕，大星磊落纔數十。',64,'全唐诗/poet.song.128000.json','["急雨初過天宇濕，大星磊落纔數十。", "饑鶻掠簷飛磔磔，冷螢墮水光熠熠。", "丈夫無成忽老大，箭羽凋零劍鋒澀。", "徘徊欲睡復起行，三更猶凭闌干立。"]'),
('8da41eba-c9b6-48aa-9033-6bde0fcfcbdd','緑淨亭晚興','陸游','宋','宋诗','song-poetry','','[]','緑淨亭邊物色奇，放翁睡起曵笻枝。',64,'全唐诗/poet.song.128000.json','["緑淨亭邊物色奇，放翁睡起曵笻枝。", "新涼已似雁来後，微雨却如梅熟時。", "緑竹成陰藏細棧，朱闌倒影入清池。", "登臨獨恨非吾土，不爲城頭畫角悲。"]'),
('9087f1c3-c3c1-480c-9bf7-1a6b447e5f42','憶山南二首  其一','陸游','宋','宋诗','song-poetry','','[]','貂裘寶馬梁州日，盤槊橫戈一世雄。',64,'全唐诗/poet.song.128000.json','["貂裘寶馬梁州日，盤槊橫戈一世雄。", "怒虎吼山爭雪刅，驚鴻出塞避雕弓。", "朝陪策畫青油裏，暮醉笙歌錦幄中。", "老去據鞍猶矍鑠，君王何日奏膚功。"]'),
('42eb0fad-7d88-48fa-9184-2bfb37f6eccf','憶山南二首  其二','陸游','宋','宋诗','song-poetry','','[]','醉墨淋漓酒百杯，轅門山色碧崔嵬。',64,'全唐诗/poet.song.128000.json','["醉墨淋漓酒百杯，轅門山色碧崔嵬。", "打毬駿馬千金買，切玉名刀萬里来。", "結客漁陽時遣簡，踏營渭北夜衘枚。", "十年一夢今誰記，閉置車中只自哀。"]'),
('6f7728f2-d68c-4c54-b5df-c173029a5722','夕雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','屣履行莎徑，移床臥草亭。',48,'全唐诗/poet.song.128000.json','["屣履行莎徑，移床臥草亭。", "風聲雜溪瀨，雨氣挾龍腥。", "奕奕空中電，昏昏雲罅星。", "徂年又如許，吾鬢得長青。"]'),
('b75c0703-058e-44c0-a8dd-c5b6012e4633','夕雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','獨夜初傳漏，空齋半掩扉。',48,'全唐诗/poet.song.128000.json','["獨夜初傳漏，空齋半掩扉。", "候蟲燈下語，水鳥雨中歸。", "客舍愁彈劍，京塵怯化衣。", "故人招隱意，字字莫相違。"]'),
('713c85f5-f429-4b78-8857-8b562c5dce99','試茶','陸游','宋','宋诗','song-poetry','','[]','北窗高臥鼾如雷，誰遣香茶挽夢回。',32,'全唐诗/poet.song.128000.json','["北窗高臥鼾如雷，誰遣香茶挽夢回。", "緑地毫甌雪花乳，不妨也道入閩来。"]'),
('36d7c4f3-8a2d-4d9c-bdc6-fd23db13dced','莆陽餉荔子','陸游','宋','宋诗','song-poetry','','[]','江驛山程日夜馳，筠籠初折露猶滋。',32,'全唐诗/poet.song.128000.json','["江驛山程日夜馳，筠籠初折露猶滋。", "星毬皺玉雖奇品，終憶戎州緑荔枝。"]'),
('752b45ab-4c50-4fef-a2e5-4cdba0ac6053','初秋書懷','陸游','宋','宋诗','song-poetry','','[]','二十年前已二毛，即今何恨鬢蕭騷。',64,'全唐诗/poet.song.128000.json','["二十年前已二毛，即今何恨鬢蕭騷。", "孤燈自伴詩情苦，俗子從嫌醉眼高。", "烟外暮鐘来遠寺，雨餘秋漲集空壕。", "思歸更向文書懶，此手惟堪把蟹螯。"]'),
('d78eb4dc-1201-4533-b7ec-85c20169e782','建州絕無芡意頗思之戲作','陸游','宋','宋诗','song-poetry','','[]','鄉國雞頭賣早秋，緑荷紅縷最風流。',32,'全唐诗/poet.song.128000.json','["鄉國雞頭賣早秋，緑荷紅縷最風流。", "建安城裏西風冷，白棗堆盤看却愁。"]'),
('cdbf4785-0f9d-427f-9f2e-f0a0219fbbb5','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔西遊變姓名，獵圍屠肆狎豪英。',64,'全唐诗/poet.song.128000.json','["憶昔西遊變姓名，獵圍屠肆狎豪英。", "淋漓縱酒滄溟窄，慷慨狂歌華岳傾。", "壯士有心悲老大，窮人無路共功名。", "生涯自笑惟詩在，旋種芭蕉聽雨聲。"]'),
('d1652dff-5f49-49ad-9313-5ea34acd146f','客思','陸游','宋','宋诗','song-poetry','','[]','裘馬平生喜遠遊，暮年憔悴向南州。',64,'全唐诗/poet.song.128000.json','["裘馬平生喜遠遊，暮年憔悴向南州。", "文書與睡中分日，衰病和愁總怕秋。", "無復雪郊看射虎，但思烟浦聽呼牛。", "還家誰道無餘俸，倒槖猶堪買釣舟。"]'),
('219aa52a-842c-42f2-a8d8-ed375ca7f1e1','初秋夢故山覺而有作四首  其一','陸游','宋','宋诗','song-poetry','','[]','陂水白茫茫，草烟濕霏霏。',72,'全唐诗/poet.song.128000.json','["陂水白茫茫，草烟濕霏霏。", "牧童一聲笛，落日無餘暉。", "遥山已漸隱，村巷亞竹扉。", "老翁延我入，苦謝柿栗微。", "幸逢歲有秋，一醉君勿違。", "念此動中懷，命駕吾將歸。"]'),
('ef4b0365-9b5d-4039-ba7b-368a4abc877d','初秋夢故山覺而有作四首  其二','陸游','宋','宋诗','song-poetry','','[]','犬吠舍前後，月明村東西。',72,'全唐诗/poet.song.128000.json','["犬吠舍前後，月明村東西。", "岸草蛩亂號，庭樹鳥已栖。", "我僕城中還，擔頭有懸雞。", "小兒勸我飲，村酒拆赤泥。", "我醉不自覺，頹然葛巾低。", "著書笑蒙莊，茗艼物自齊。"]'),
('534967fc-bf7e-430d-9fbb-15547b0c37b9','初秋夢故山覺而有作四首  其三','陸游','宋','宋诗','song-poetry','','[]','昔我東歸時，父老迎舩頭。',72,'全唐诗/poet.song.128000.json','["昔我東歸時，父老迎舩頭。", "開篷相勞苦，怪我領雪稠。", "故山何負君，且作數月留。", "豈知席未暖，疋馬来南州。", "蠻花四時紅，瘴霧日夜浮。", "歸哉不可遲，勿與婦子謀。"]'),
('05035e6b-ff47-4870-8477-814ffcfdec9c','初秋夢故山覺而有作四首  其四','陸游','宋','宋诗','song-poetry','','[]','杜宇真吾交，勸去恨不速。',72,'全唐诗/poet.song.128000.json','["杜宇真吾交，勸去恨不速。", "忠告輸肝肺，厚意均骨肉。", "陋哉鷓鴣語，揣我貧念禄。", "竹雞更鄙淺，泥淖憂車軸。", "秋風嚴瀨清，春雨戴溪緑。", "行矣勿復疑，照影巾一幅。"]'),
('55511e4d-315c-4a98-a99c-e495876cd66c','寓嘆','陸游','宋','宋诗','song-poetry','','[]','千載前人每暗同，眼邊俗客馬牛風。',64,'全唐诗/poet.song.128000.json','["千載前人每暗同，眼邊俗客馬牛風。", "作文要可張子布，飲酒思從陳孟公。", "半世氛埃成潦倒，幾時蓑釣入空濛。", "一庵處處皆堪老，莫怕無山著此翁。"]'),
('22f6877e-0da4-420b-a92a-066462e4e80a','雙清堂醉臥','陸游','宋','宋诗','song-poetry','','[]','客裏逢秋醉似泥，空堂獨臥意凄迷。',64,'全唐诗/poet.song.128000.json','["客裏逢秋醉似泥，空堂獨臥意凄迷。", "亂號庭樹西風急，斜挂城樓北斗低。", "末路敢貪請鶴料，微官久厭駕雞棲。", "平生玉局經行地，擬乞冰衘隱剡溪。"]'),
('043504a1-822d-496b-806b-84fbcdff2f5b','醉書','陸游','宋','宋诗','song-poetry','','[]','半年愁病劇，一雨喜涼新。',48,'全唐诗/poet.song.128000.json','["半年愁病劇，一雨喜涼新。", "稍與藥囊遠，初容酒醆親。", "浩歌驚世俗，狂語任天真。", "我亦輕餘子，君當恕醉人。"]'),
('13504430-2cf4-47b0-9b21-1364b410160b','憶唐安','陸游','宋','宋诗','song-poetry','','[]','南鄭戍還初過蜀，朝衫與鬢猶爭緑。',128,'全唐诗/poet.song.128000.json','["南鄭戍還初過蜀，朝衫與鬢猶爭緑。", "逢春飲酒似長鯨，醉裏千篇風雨速。", "唐安池館夜宴頻，瀲瀲玉船揺畫燭。", "紅索琵琶金縷花，百六十絃彈法曲。", "曲終却看舞霓裳，嫋嫋宫腰細如束。", "明朝解酲不用酒，起尋百畝東湖竹。", "歸吳寂寞時自笑，縱有詩情誰省録。", "今年二頃似可謀，去斸雲根結茅屋。"]'),
('9a68e6d4-074f-48b9-beaf-4b3c50a57e1c','秋懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','暮年身世轉悠悠，又向天涯見早秋。',32,'全唐诗/poet.song.128000.json','["暮年身世轉悠悠，又向天涯見早秋。", "昨夜月明今夜雨，關人何事總成愁。"]'),
('bd305472-d520-41de-ac1d-11233bc972c9','秋懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','星斗闌干河漢流，建州風物更禁秋。',32,'全唐诗/poet.song.128000.json','["星斗闌干河漢流，建州風物更禁秋。", "年来多病題詩懶，付與鳴蛩替說愁。"]'),
('08c9e70b-daa3-42a4-b001-cb236e150875','晝臥聞碾茶','陸游','宋','宋诗','song-poetry','','[]','小醉初消日未晡，幽窗催破紫雲腴。',32,'全唐诗/poet.song.128000.json','["小醉初消日未晡，幽窗催破紫雲腴。", "玉川七盌何須爾，銅碾聲中睡已無。"]'),
('d6958e60-5922-477d-9a6a-faa7e03923b9','月下獨行橋上','陸游','宋','宋诗','song-poetry','','[]','新秋未再旬，月露已浩然。',72,'全唐诗/poet.song.128000.json','["新秋未再旬，月露已浩然。", "放翁一幅巾，與影俱翩僊。", "飛橋挂澄谿，幽竇鳴細泉。", "開歲纔俛仰，已近揺落天。", "殊方久滯留，感此歲月遷。", "歸来看青燈，悄愴不得眠。"]'),
('d5bcbac8-87d1-4b86-840b-6213f2693a61','夜意','陸游','宋','宋诗','song-poetry','','[]','火雲夕方收，草露秋已白。',72,'全唐诗/poet.song.128000.json','["火雲夕方收，草露秋已白。", "堂空燈欲翳，壁壞蟲自嘖。", "四顧寂無人，獨立岸吾幘。", "窮通何足論，等是百年客。", "何能爲一飽，半世出下策。", "布帆幸無恙，誰謂江海迮。"]'),
('fe13f7ee-fee6-457a-896b-eb915c2406c2','秋夜書懷','陸游','宋','宋诗','song-poetry','','[]','斷香漠漠繞藤床，新月娟娟轉畫廊。',64,'全唐诗/poet.song.128000.json','["斷香漠漠繞藤床，新月娟娟轉畫廊。", "鄉遠每勞千里夢，雨慳未放九秋涼。", "衰遲分作驥伏櫪，斂退敢求錐出囊。", "剩喜今年有奇事，嚴遵灘下繫歸航。"]'),
('0e4a429e-8ae8-4ae1-a183-a2a2240d13ce','思故廬','陸游','宋','宋诗','song-poetry','','[]','平生一束書，不爲屋廬計。',72,'全唐诗/poet.song.128000.json','["平生一束書，不爲屋廬計。", "微官寄郵傳，俯仰閱半世。", "草堂白雲邊，日夜長松桂。", "柴門入幽夢，落日亂蟬嘒。", "宦遊有何好，海角愁瘴癘。", "拂衣便可耳，勿使老春薺。"]'),
('0070ac6b-49d9-4c07-86c3-ab045f880175','雨夜','陸游','宋','宋诗','song-poetry','','[]','小雨初涼夜，殘燈欲暗時。',48,'全唐诗/poet.song.128000.json','["小雨初涼夜，殘燈欲暗時。", "病多愁近酒，心弱怯題詩。", "舊友殊方少，歸耕晚歲宜。", "回頭語孤影，此意有君知。"]'),
('ce36da53-fdea-41df-a88c-d9790c62bb48','北窗哦詩因賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','二十年來賦遠遊，一窗又復寄南州。',64,'全唐诗/poet.song.128000.json','["二十年來賦遠遊，一窗又復寄南州。", "雙鵝戲雨陂塘曉，亂葉飄風院落秋。", "顔鬢蹉跎愁覽鏡，江山重復怯登樓。", "平生事業詩千首，殘稿從敎處處留。"]'),
('32ea3598-8cd1-45b0-a1cd-b3245acacb28','北窗哦詩因賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','露下螢飛仲秋月，山圍水繞建安城。',64,'全唐诗/poet.song.128000.json','["露下螢飛仲秋月，山圍水繞建安城。", "病多不辨酒中聖，身遠且令心太平。", "數卷蠧書行老矣，一盂蔬飯太憎生。", "白雲只在簷間宿，聽我清宵詠句聲。"]'),
('954a905b-bb60-4322-9c5b-be429f0d546e','俶裝','陸游','宋','宋诗','song-poetry','','[]','絕物離人恨未能，聊爲旦過打包僧。',64,'全唐诗/poet.song.128000.json','["絕物離人恨未能，聊爲旦過打包僧。", "蹇驢渺渺秋山雨，孤榻昏昏夜店燈。", "酒量已隨詩共退，客愁仍與病相乘。", "頹然衰颯嗟誰識，俠氣當年蓋五陵。"]'),
('732bb9ca-7d68-42d2-b3ab-888504e567d4','追感梁益舊遊有作','陸游','宋','宋诗','song-poetry','','[]','西遊萬里倚朱顔，肯放尊前一笑慳。',64,'全唐诗/poet.song.128000.json','["西遊萬里倚朱顔，肯放尊前一笑慳。", "蜀苑妓圍欺夜雪，梁州獵火滿秋山。", "晚途忽墮塵埃裏，樂事渾疑夢寐間。", "浮世變遷君勿嘆，劇談猶是詫鄉關。"]'),
('b5f4a086-b60c-4574-b83e-053d173cad78','莆陽昭武延平送兵漸集戲書','陸游','宋','宋诗','song-poetry','','[]','鼓聲晨紞紞，角聲莫嗚嗚。',72,'全唐诗/poet.song.128000.json','["鼓聲晨紞紞，角聲莫嗚嗚。", "作官了何事，空嘆歲月徂。", "送兵稍稍集，秣馬脂吾車。", "風霜迫揺落，殘暑亦已無。", "野渡明丹楓，破驛吹黄榆。", "聊收作詩料，未用厭征途。"]'),
('27237302-6f74-42b3-b2e5-0bf71f65823d','别建安三首  其一','陸游','宋','宋诗','song-poetry','','[]','三十年来雲水僧，常挑鉢帒繫行縢。',32,'全唐诗/poet.song.128000.json','["三十年来雲水僧，常挑鉢帒繫行縢。", "信緣不作癡巢窟，即是吾家無盡燈。"]'),
('2955e10c-e102-40be-8afa-c73f5bcbbcb4','别建安三首  其二','陸游','宋','宋诗','song-poetry','','[]','楚澤吳山已慣行，武夷從昔但聞名。',32,'全唐诗/poet.song.128000.json','["楚澤吳山已慣行，武夷從昔但聞名。", "北巖小寺長汀驛，且喜遊山第一程。"]'),
('3c880f4f-be0a-4297-9aa4-17d3d4737bc7','别建安三首  其三','陸游','宋','宋诗','song-poetry','','[]','欹帽揚鞭晚出城，驛亭燈火向人明。',32,'全唐诗/poet.song.128000.json','["欹帽揚鞭晚出城，驛亭燈火向人明。", "多情葉上蕭蕭雨，更把新涼送客行。"]'),
('e1ef2f9e-d64f-4330-8c4c-10b6c67b66a0','初發建安','陸游','宋','宋诗','song-poetry','','[]','小雨初收雲未歸，吾行迨及晚秋時。',64,'全唐诗/poet.song.128000.json','["小雨初收雲未歸，吾行迨及晚秋時。", "寒沙新雁無人問，露井殘桐有客悲。", "征袂拂霜晨喚馬，驛窗剪燭夜題詩。", "悠然且作尋山想，夢裏功名莫自期。"]'),
('56276b91-8756-40f9-b995-603a22b3919e','宿北巖院','陸游','宋','宋诗','song-poetry','','[]','車馬紛紛送入朝，北巖燈火夜無聊。',32,'全唐诗/poet.song.128000.json','["車馬紛紛送入朝，北巖燈火夜無聊。", "中年到處難爲别，也似初程宿灞橋。"]'),
('4374f8cc-a26c-44ad-be91-a831514a4de0','書感','陸游','宋','宋诗','song-poetry','','[]','溪路人家尚闔扉，彊扶衰憊著征衣。',64,'全唐诗/poet.song.128000.json','["溪路人家尚闔扉，彊扶衰憊著征衣。", "百年朝露古所嘆，一櫂秋風吾欲歸。", "楚客長號沽白璧，漢宫太息遣明妃。", "鑠金銷骨從来事，老矣何心踐駭機。"]'),
('629e3ad1-1c63-41c8-b7e6-f7ce92c49491','長汀道中','陸游','宋','宋诗','song-poetry','','[]','晚過長汀驛，溪山乃爾奇。',48,'全唐诗/poet.song.128000.json','["晚過長汀驛，溪山乃爾奇。", "老夫惟坐嘯，造物爲陳詩。", "鳥送穿林語，松垂拂澗枝。", "憑鞍久忘發，不是馬行遲。"]'),
('742d5f71-f942-4f0f-98bb-59e6a305004e','黄亭夜雨','陸游','宋','宋诗','song-poetry','','[]','未到名山夢已新，千峰拔地玉嶙峋。',32,'全唐诗/poet.song.128000.json','["未到名山夢已新，千峰拔地玉嶙峋。", "黄亭一夜風吹雨，似爲遊人洗俗塵。"]'),
('9a74581f-0997-48d2-9f73-b5c3ffb8f7f5','遊武夷山','陸游','宋','宋诗','song-poetry','','[]','少讀封禪書，始知武夷君。',120,'全唐诗/poet.song.128000.json','["少讀封禪書，始知武夷君。", "晚乃遊斯山，秀傑非昔聞。", "三十六奇峰，秋晴無纖雲。", "空巖雞晨號，峭壁丹夜暾。", "巢居寄千仞，鴻荒想羲軒。", "風雨蛻玉骨，難以俗意論。", "丹梯不容躡，修蔓亦畏捫。", "泝灘進小艇，愧驚白鷺群。", "學道雖恨晚，養氣敢不勤。", "宦遊非本志，寄謝鶴與猿。"]'),
('93fa808d-4140-459b-ae4f-c05c4fcfadaa','泛舟武夷九曲溪至六曲或云灘急難上遂回二首  其一','陸游','宋','宋诗','song-poetry','','[]','暮年脚力倦躋攀，借得扁舟臥看山。',32,'全唐诗/poet.song.128000.json','["暮年脚力倦躋攀，借得扁舟臥看山。", "怪怪奇奇何所似，緑蘿溪入下牢關。"]'),
('6f0a3c76-7a9c-4403-bd43-cc161f1fa30d','泛舟武夷九曲溪至六曲或云灘急難上遂回二首  其二','陸游','宋','宋诗','song-poetry','','[]','一葉凌風入硤来，山童指點幾崔嵬。',32,'全唐诗/poet.song.128000.json','["一葉凌風入硤来，山童指點幾崔嵬。", "急流勇退平生意，正要船從半道回。"]'),
('4e0fc3e1-0dc6-4671-b349-1bacb3744d9b','崇安縣驛','陸游','宋','宋诗','song-poetry','','[]','驛外清江十里秋，雁聲初到荻花洲。',32,'全唐诗/poet.song.128000.json','["驛外清江十里秋，雁聲初到荻花洲。", "征車已駕晨窗白，殘燭依然伴客愁。"]'),
('6d173014-a0ce-45d1-a3b2-459a38df8508','過建陽縣以雙鵝贈東觀道士爲長生鵝觀俯大溪鵝得其所矣武夷險絕處有仙船架崖壁間數日前大風吹墮船木數寸堅硬如石予偶得之皆此行奇事也各賦一詩 雙鵝','陸游','宋','宋诗','song-poetry','','[]','閑泛晴波唼緑萍，却衝微雨傍烟汀。',32,'全唐诗/poet.song.128000.json','["閑泛晴波唼緑萍，却衝微雨傍烟汀。", "會稽內史如相遇，換取黄庭一卷經。"]'),
('b61f9c4d-f559-4aca-9586-e17c1e5b088c','過建陽縣以雙鵝贈東觀道士爲長生鵝觀俯大溪鵝得其所矣武夷險絕處有仙船架崖壁間數日前大風吹墮船木數寸堅硬如石予偶得之皆此行奇事也各賦一詩 墮木','陸游','宋','宋诗','song-poetry','','[]','斷崖幽洞白雲深，縹緲仙槎無古今。',32,'全唐诗/poet.song.128000.json','["斷崖幽洞白雲深，縹緲仙槎無古今。", "飛下一峰相勞苦，却疑天外有知音。"]'),
('5a84ba5e-b0b2-4586-926c-5c36d12a422a','紫谿驛二首  其一','陸游','宋','宋诗','song-poetry','','[]','它鄉異縣老何堪，短髮蕭蕭不滿篸。',32,'全唐诗/poet.song.128000.json','["它鄉異縣老何堪，短髮蕭蕭不滿篸。", "旋買一尊持自賀，病身安穩到江南。"]'),
('20c1e98d-cf0d-4386-80b1-a908f5c646fd','紫谿驛二首  其二','陸游','宋','宋诗','song-poetry','','[]','雲外丹青萬仞梯，木陰合處子規啼。',32,'全唐诗/poet.song.128000.json','["雲外丹青萬仞梯，木陰合處子規啼。", "嘉陵棧道吾能說，略似黄亭到紫谿。"]'),
('0badeb6f-1e77-48e8-9b1d-a7de90c8d2a8','鵝湖夜坐書懷','陸游','宋','宋诗','song-poetry','','[]','士生始墮地，弧矢志四方。',264,'全唐诗/poet.song.128000.json','["士生始墮地，弧矢志四方。", "豈若彼婦女，齪齪藏閨房。", "我行環萬里，險阻真備嘗。", "昔者戍南鄭，秦山鬱蒼蒼。", "鐵衣臥枕戈，睡覺身滿霜。", "官雖備幕府，氣實先顔行。", "擁馬涉沮水，飛鷹上中梁。", "勁酒舉數斗，壯士不能當。", "馬鞍挂狐兔，燔炙百步香。", "拔劍切大肉，哆然如餓狼。", "時時登高望，指顧無咸陽。", "一朝去軍中，十載客道傍。", "看花身落魄，對酒色凄凉。", "去年忝號召，五月觸瞿唐。", "青衫暗欲盡，入對衰涕滂。", "今年復詔下，鴻雁初南翔。", "俯仰未閱歲，上恩實非常。", "夜宿鵝湖寺，槁葉投客床。", "寒燈照不寐，撫枕慨以慷。", "李靖聞征遼，病憊更激昻。", "裴度請討蔡，奏事猶裹創。", "我亦思報國，夢繞古戰場。"]'),
('d3701baf-7424-49a4-a312-110252ba9683','信州東驛晨起','陸游','宋','宋诗','song-poetry','','[]','衣上征塵鬢畔霜，信州古驛憩歸裝。',64,'全唐诗/poet.song.128000.json','["衣上征塵鬢畔霜，信州古驛憩歸裝。", "悲歌未肯彈長鋏，豪氣猶能臥大床。", "半暗殘燈揺北壁，常饑老馬臥東廂。", "鄰雞唱罷衣篝暖，自笑行人日日忙。"]'),
('2429a6cf-2a20-4a6e-a8cb-3ae29401fddb','玉山縣南樓晚望','陸游','宋','宋诗','song-poetry','','[]','小樓在何許，正在南溪上。',48,'全唐诗/poet.song.128000.json','["小樓在何許，正在南溪上。", "空濛過釣船，斷續聞漁唱。", "征途苦偪仄，舒嘯喜清曠。", "安得此溪水，爲我變春釀。"]'),
('d1dbc7e3-9183-4cf8-89fb-0e4292953eb0','玉壺亭','陸游','宋','宋诗','song-poetry','','[]','玉壺亭上小徘徊，閑對殘荷把一杯。',32,'全唐诗/poet.song.128000.json','["玉壺亭上小徘徊，閑對殘荷把一杯。", "冠蓋交馳期會急，長官未必辦頻来。"]'),
('f31d5f3a-60c2-472d-a09f-57da98380b62','步過縣南長橋遊南山普寧院山高處有塔院及小亭縹緲可愛恨不能到','陸游','宋','宋诗','song-poetry','','[]','偶扶藤杖過南津，野寺長橋發興新。',64,'全唐诗/poet.song.128000.json','["偶扶藤杖過南津，野寺長橋發興新。", "暫就清溪照鬚鬢，不妨翠霧濕衣巾。", "山縈細棧疑無路，樹落崩崖欲壓人。", "朝暮有程常猝猝，何因攜酒上嶙峋。"]'),
('c5b40694-ace2-46b0-88f2-c6017cb05c02','枕上感懷','陸游','宋','宋诗','song-poetry','','[]','五更攬轡山路長，老大誦書聲琅琅。',96,'全唐诗/poet.song.128000.json','["五更攬轡山路長，老大誦書聲琅琅。", "古人已死心則在，度越秦漢窺虞唐。", "三更投枕窗月白，老夫哦詩聲嘖嘖。", "淵源雅頌吾豈敢，屈宋藩籬或能測。", "一代文章誰汝數，老不能閑真自苦。", "君王雖賞于蒍于，無奈宮中須羯鼓。"]'),
('8fd170ea-906c-4113-a89a-d79841aa0f38','晚過招賢渡','陸游','宋','宋诗','song-poetry','','[]','老馬骨巉然，虺尵不受鞭。',48,'全唐诗/poet.song.128000.json','["老馬骨巉然，虺尵不受鞭。", "行人爭晚渡，歸鳥破秋烟。", "湖海凄凉地，風霜揺落天。", "吾生半行路，搔首送流年。"]'),
('69b6dd55-57bc-437b-94d2-649711fda7c2','臥輿','陸游','宋','宋诗','song-poetry','','[]','白首躬耕已有期，鳳城歸路却遲遲。',32,'全唐诗/poet.song.128000.json','["白首躬耕已有期，鳳城歸路却遲遲。", "臥輿擁被聽秋雨，占盡人間好睡時。"]'),
('3a837d0e-45a4-4098-8279-8f3da793f79e','奏乞奉祠留衢州皇華館待命','陸游','宋','宋诗','song-poetry','','[]','世念蕭然冷欲冰，更堪衰與病相乘。',64,'全唐诗/poet.song.128000.json','["世念蕭然冷欲冰，更堪衰與病相乘。", "從来幸有不材木，此去真爲無事僧。", "耐辱豈惟容唾面，寡言端擬學銘膺。", "尚餘一事猶豪舉，醉後龍蛇滿剡藤。"]'),
('c276e4b9-00e1-448c-84d8-94fd8bc98cd7','寓舍偶題','陸游','宋','宋诗','song-poetry','','[]','轉徙身飄梗，淹留等繫匏。',48,'全唐诗/poet.song.128000.json','["轉徙身飄梗，淹留等繫匏。", "雁孤依遠渚，鳩拙寄空巢。", "寒日頳梨頰，清霜長橘包。", "平生麴道士，歲晚欲深交。"]'),
('d41b485b-1e80-449d-abc9-0f278e1204bc','夙興','陸游','宋','宋诗','song-poetry','','[]','客中睡眠少，常以雞鳴興。',72,'全唐诗/poet.song.128000.json','["客中睡眠少，常以雞鳴興。", "新炭熾宿火，膏油續殘燈。", "焚香倚蒲團，外靜中已凝。", "榮辱兩不到，淡如秋水澄。", "出定窗已白，炯炯寒日昇。", "厨人作芋糝，供此在家僧。"]'),
('5280c954-663d-40be-a7b6-d3faba1de7cb','夜坐','陸游','宋','宋诗','song-poetry','','[]','老知世事謾紛紛，紙帳蒲團自策勲。',32,'全唐诗/poet.song.128000.json','["老知世事謾紛紛，紙帳蒲團自策勲。", "一夜北風吹裂屋，石樓無耳不曾聞。"]'),
('873643dd-86a8-4118-9f37-4b70af0c5a6f','偶得石室酒獨飲醉臥覺而有作','陸游','宋','宋诗','song-poetry','','[]','初寒思小飲，名酒忽墮前。',96,'全唐诗/poet.song.128000.json','["初寒思小飲，名酒忽墮前。", "素甖手自傾，色若秋澗泉。", "浩歌復起舞，與影俱翩僊。", "一笑遺宇宙，未覺異少年。", "詩人不聞道，苦嘆歲月遷。", "豈知汝南市，自有壺中天。", "河洛久未復，銅駞棘森然。", "秋風歸去来，虚老玉井蓮。"]'),
('b6c8467f-c16a-4baf-bdba-daee4e64a1ce','午睡','陸游','宋','宋诗','song-poetry','','[]','風霜踐殘歲，我乃羈旅人。',72,'全唐诗/poet.song.128000.json','["風霜踐殘歲，我乃羈旅人。", "如何得一室，床敷暖如春。", "午枕挾小醉，鼻息撼四鄰。", "心安了無夢，一掃想與因。", "逡巡起頮面，覽鏡正幅巾。", "聊呼蟹眼湯，瀹我玉色塵。"]'),
('350a5337-f03b-4e5c-94e3-abb95f56d967','贈柯山老人','陸游','宋','宋诗','song-poetry','','[]','柯山老人九十餘，亂髮不櫛瘦如枯。',64,'全唐诗/poet.song.128000.json','["柯山老人九十餘，亂髮不櫛瘦如枯。", "百穿千結一布袴，得酒一吸輒倒壺。", "自言少年不蓄孥，有錢徑付酒家壚。", "人生辦此真良圖，棄官從翁許我無。"]'),
('ffa448dd-4618-4826-848e-0397670fc9fa','寓館晚興','陸游','宋','宋诗','song-poetry','','[]','隨牒人間不自憐，衢州孤驛更蕭然。',64,'全唐诗/poet.song.128000.json','["隨牒人間不自憐，衢州孤驛更蕭然。", "百年細數半行路，萬事不如長醉眠。", "髮短經秋真種種，腹寛耐事只便便。", "晚窗商略唯當飲，安得黄花到眼邊。"]'),
('b48d25de-641c-47d7-bb46-13f876e02688','葉相最高亭','陸游','宋','宋诗','song-poetry','','[]','高亭新築冠鼇峰，眼力超然信不同。',64,'全唐诗/poet.song.128000.json','["高亭新築冠鼇峰，眼力超然信不同。", "膚寸油雲澤天下，大千沙界納胸中。", "春遊到處群花擁，夜宴歡時百榼空。", "劉白老来忘世味，只思詩酒伴裴公。"]'),
('d6354416-029f-46eb-93cf-fca1a57c6035','婺州州宅極目亭','陸游','宋','宋诗','song-poetry','','[]','尚書曵履上星辰，小爲東陽作主人。',64,'全唐诗/poet.song.128000.json','["尚書曵履上星辰，小爲東陽作主人。", "朱閣凌空雲縹緲，青山繞郭玉嶙峋。", "似聞旋敎新歌舞，且慰重臨舊吏民。", "莫倚闌干西北角，即今河洛尚沙塵。"]'),
('57388a28-b730-4e70-a370-3243782bc1ed','謝演師送梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','早梅時節到江南，已判樽前酒滿衫。',32,'全唐诗/poet.song.128000.json','["早梅時節到江南，已判樽前酒滿衫。", "輸與西鄰明上座，解從大庾嶺頭參。"]'),
('effc8229-b293-40eb-a6f9-8acb33824f43','謝演師送梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','折送江梅意不疏，要敎相對鬬清臞。',32,'全唐诗/poet.song.128000.json','["折送江梅意不疏，要敎相對鬬清臞。", "爲君著向明窗下，試問山翁具眼無。"]'),
('f85853de-1e9b-4ba7-9936-dca5186b2c53','訪毛平仲問疾與其子适同遊柯山觀王質爛柯遺跡','陸游','宋','宋诗','song-poetry','','[]','籃輿訪客過仙村，千載空餘一局存。',64,'全唐诗/poet.song.128000.json','["籃輿訪客過仙村，千載空餘一局存。", "曵杖不妨呼小友，還家便恐見来孫。", "林巒巉絕秋風瘦，樓堞參差暮氣昏。", "酒美魚肥吾事畢，一庵那得住雲根。"]'),
('e18d8597-eb5a-43f5-a70e-8abcb5f0adfd','月巖','陸游','宋','宋诗','song-poetry','','[]','幾年不作月巖遊，萬里重来已白頭。',32,'全唐诗/poet.song.128000.json','["幾年不作月巖遊，萬里重来已白頭。", "雲外連姢何所似，平羌江上半輪秋。"]'),
('0677e488-283b-44b9-afb6-53529d175036','弋陽縣驛','陸游','宋','宋诗','song-poetry','','[]','大雨山中采藥回，丫頭巖畔覓詩来。',64,'全唐诗/poet.song.128000.json','["大雨山中采藥回，丫頭巖畔覓詩来。", "喚船野渡逢迎雪，攜酒溪頭領略梅。", "久客愁心端欲折，何時笑口得頻開。", "慇勤記著今朝事，破驛空廊葉作堆。"]'),
('042bc7b2-1059-4407-a293-f9466ecc2408','弋陽道中遇大雪','陸游','宋','宋诗','song-poetry','','[]','我行江郊暮猶進，大雪塞空迷遠近。',96,'全唐诗/poet.song.128000.json','["我行江郊暮猶進，大雪塞空迷遠近。", "壯哉組練從天来，人間有此堂堂陣。", "少年頗愛軍中樂，跌宕不耐微官縛。", "憑鞍寓目一悵然，思爲君王掃河洛。", "夜聽簌簌窗紙鳴，恰似鐵馬相磨聲。", "起傾斗酒歌出塞，彈壓胸中十萬兵。"]'),
('d7996c4e-1786-4591-9968-13790a9ebc69','雪中懷成都','陸游','宋','宋诗','song-poetry','','[]','憶在西州遇雪時，繡筵處處百花圍。',64,'全唐诗/poet.song.128000.json','["憶在西州遇雪時，繡筵處處百花圍。", "烏絲闌展新詩就，油壁車迎小獵歸。", "感事鏡鸞悲獨舞，寄書箏雁恨慵飛。", "愁多自是難成醉，不爲天寒酒力微。"]'),
('76aff377-20df-4e63-8d05-ea7bd36d2d47','雪後苦寒行饒撫道中有感','陸游','宋','宋诗','song-poetry','','[]','殘雪暮還結，朔風晴更寒。',72,'全唐诗/poet.song.128000.json','["殘雪暮還結，朔風晴更寒。", "重裘猶粟膚，連酌無騂顔。", "指直不可握，終日縮袖間。", "十年走萬里，何適不艱難。", "附火財須臾，攬轡復慨嘆。", "恨不以此勞，爲國戌玉關。"]'),
('68166174-3e3c-4c7a-8f7e-c44828c8f578','對酒二首  其一','陸游','宋','宋诗','song-poetry','','[]','温如春色爽如秋，一榼燈前自獻酬。',32,'全唐诗/poet.song.128000.json','["温如春色爽如秋，一榼燈前自獻酬。", "百萬愁魔降未得，故應用爾作戈矛。"]'),
('4ac52f6a-a691-4dc7-ba8b-3d64d61c7bd3','對酒二首  其二','陸游','宋','宋诗','song-poetry','','[]','嘆息人真未易知，暮年始覺麴生奇。',32,'全唐诗/poet.song.128000.json','["嘆息人真未易知，暮年始覺麴生奇。", "個中妙趣誰堪語，最是初醺未醉時。"]'),
('2db45e16-25da-4da1-8d75-4cb0f8d06770','梅花','陸游','宋','宋诗','song-poetry','','[]','我與梅花有舊盟，即今白髮未忘情。',64,'全唐诗/poet.song.128000.json','["我與梅花有舊盟，即今白髮未忘情。", "不愁索笑無多子，惟恨相思太瘦生。", "身世何曾怨空谷，風流正自合傾城。", "增冰積雪行人少，試倩羈鴻爲寄聲。"]'),
('8052562a-39d2-4064-9c39-d51f8c6e53d2','雪中尋梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','莫遣扁舟興盡回，正須衝雪看江梅。',32,'全唐诗/poet.song.128000.json','["莫遣扁舟興盡回，正須衝雪看江梅。", "楚人原未知真色，施粉何曾太白来。"]'),
('ad71666d-e5d7-49fd-9511-ad71fa822424','雪中尋梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','幽香淡淡影疏疏，雪虐風饕亦自如。',32,'全唐诗/poet.song.128000.json','["幽香淡淡影疏疏，雪虐風饕亦自如。", "正是花中巢許輩，人間冨貴不關渠。"]'),
('cf95257f-c2d2-4fea-a222-376df8899a63','江上梅花','陸游','宋','宋诗','song-poetry','','[]','老来樂事少關身，猶喜尊前見玉人。',64,'全唐诗/poet.song.128000.json','["老来樂事少關身，猶喜尊前見玉人。", "豈是凄凉偏薄命，自緣纖瘦不禁春。", "姢姢月上明江練，黯黯天低糝玉塵。", "絕磵斷橋幽獨處，護持應有主林神。"]'),
('19c1a2c1-feda-4c41-acd1-7e7f1ec54f7e','擬峴臺觀雪','陸游','宋','宋诗','song-poetry','','[]','垂虹亭上三更月，擬峴臺前清曉雪。',128,'全唐诗/poet.song.128000.json','["垂虹亭上三更月，擬峴臺前清曉雪。", "我行萬里跨秦吴，此地固應名二絕。", "山川滅沒雪作海，亂墜天花自成態。", "狂歌痛飲豪不除，更憶衘枚馳出塞。", "蘆摧葦折號饑鴻，欲傅粉墨無良工。", "摩挲東絹三嘆息，收入放翁詩卷中。", "明朝青天行日轂，萬瓦生烟失瓊玉。", "世間成壞本相尋，却看晴山暈眉緑。"]'),
('625a6dc1-4e3b-408f-b4d5-9dbaddda532f','舊在成都初春無事日訪昭覺保福正法諸刹甚可樂也追懷慨然因賦長句','陸游','宋','宋诗','song-poetry','','[]','憶在西川集寶坊，幅巾蕭散日初長。',64,'全唐诗/poet.song.128000.json','["憶在西川集寶坊，幅巾蕭散日初長。", "伊蒲塞饌分香積，優鉢羅花散道場。", "客路逢春增感慨，舊遊回首已微凉。", "新晴強作尋幽計，有底文書作許忙。"]'),
('7b4b368c-1839-4453-8fde-bb37d60a5431','園中賞梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','閱盡千葩百卉春，此花風味獨清真。',64,'全唐诗/poet.song.128000.json','["閱盡千葩百卉春，此花風味獨清真。", "江邊曉雪愁欲語，馬上夕陽香趁人。", "慰眼紅苞初報信，回頭青子又生仁。", "覊遊偏覺年華速，徙倚闌干一愴神。"]'),
('1e0068ae-9212-42d1-b3eb-a86ead207f90','園中賞梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','行遍茫茫禹畫州，尋梅到處得閑遊。',64,'全唐诗/poet.song.128000.json','["行遍茫茫禹畫州，尋梅到處得閑遊。", "春前春後百回醉，江北江南千里愁。", "未愛繁枝壓紗帽，最憐亂點糝貂裘。", "一寒可賀君知否，又得幽香數日留。"]'),
('b92ce9ff-b466-4cc7-adce-3cdf583abbe8','正月十五日出郊至金石臺二首  其一','陸游','宋','宋诗','song-poetry','','[]','漸老惜時節，思遊那可忘。',48,'全唐诗/poet.song.128000.json','["漸老惜時節，思遊那可忘。", "雪晴天淺碧，春動柳輕黄。", "笑語寛衰疾，登臨到夕陽。", "未須催野渡，聊欲據胡床。"]'),
('869090b5-f248-4c39-bce7-a0b0e41cc60a','正月十五日出郊至金石臺二首  其二','陸游','宋','宋诗','song-poetry','','[]','開歲多休暇，官身亦暫閑。',48,'全唐诗/poet.song.128000.json','["開歲多休暇，官身亦暫閑。", "樓臺先晝永，花柳向春慳。", "啼鳥隨遊轡，和風惬醉顔。", "更憐歸路好，破墨數峰山。"]'),
('e3b313ef-7424-4212-94c4-20ca9fe1ebee','六日小飲園中光景鮮妍紅梅已拆恍記在果州時偶得絕句','陸游','宋','宋诗','song-poetry','','[]','輕裘駿馬金泉路，黙數新春又九年。',32,'全唐诗/poet.song.128000.json','["輕裘駿馬金泉路，黙數新春又九年。", "風景不殊人自老，忽驚作夢到臨川。"]'),
('874f873e-70df-49b0-bcc2-07e8e6964662','聞雁','陸游','宋','宋诗','song-poetry','','[]','過盡梅花把酒稀，熏籠香冷換春衣。',32,'全唐诗/poet.song.128000.json','["過盡梅花把酒稀，熏籠香冷換春衣。", "秦關漢苑無消息，又在江南送雁歸。"]'),
('3253fdd7-df1a-4fff-9013-e52c59bad437','撫州上元','陸游','宋','宋诗','song-poetry','','[]','江月微雲外，街泥小雨餘。',48,'全唐诗/poet.song.128000.json','["江月微雲外，街泥小雨餘。", "人如虛市散，燈似曉星疏。", "覉雁同身世，新霜上鬢鬚。", "明年更清絕，漁火對茅廬。"]'),
('5641649f-0c70-4e70-97b6-263eaf16a55e','登擬峴臺','陸游','宋','宋诗','song-poetry','','[]','層臺縹緲壓城闉，倚杖来觀浩蕩春。',64,'全唐诗/poet.song.128000.json','["層臺縹緲壓城闉，倚杖来觀浩蕩春。", "放盡樽前千里目，洗空衣上十年塵。", "縈廻水抱中和氣，平遠山如醖藉人。", "更喜機心無復在，沙邊鷗鷺亦相親。"]'),
('df5f1928-2872-448a-9ce5-18692607c5fb','燈夕有感','陸游','宋','宋诗','song-poetry','','[]','芙渠紅緑亦參差，睡起燒香強賦詩。',32,'全唐诗/poet.song.128000.json','["芙渠紅緑亦參差，睡起燒香強賦詩。", "萬里錦城無夢到，豈惟虛負放燈時。"]'),
('05b46227-a110-48d1-9723-35ed697011d2','庚子正月十八日送梅','陸游','宋','宋诗','song-poetry','','[]','滿城桃李爭春色，不許梅花不成雪。',96,'全唐诗/poet.song.128000.json','["滿城桃李爭春色，不許梅花不成雪。", "世間尤物無盛衰，萬點縈風愈奇絕。", "我行柯山眠酒家，初見窗前三四花。", "恨無壯士挽斗柄，坐令東指催年華。", "今朝零落已可惜，明日重尋更無迹。", "情之所鍾在我曹，莫倚心腸如鐵石。"]'),
('5ee5ce76-e88e-4555-a406-6983cc95d491','初春懷成都','陸游','宋','宋诗','song-poetry','','[]','我昔薄遊西適秦，歸到錦城逢早春。',96,'全唐诗/poet.song.128000.json','["我昔薄遊西適秦，歸到錦城逢早春。", "五門收燈藥市近，小桃妖妍狂殺人。", "霓裳法曲華清譜，燕妬身輕鶯學語。", "歌舞更休轉盼間，但見宮衣換金縷。", "世上悲歡豈易知，不堪風景似當時。", "病来幾與麴生絕，禪榻茶烟雙鬢絲。"]'),
('e47fed96-5969-468e-b4e3-ba5a45fd394c','春雨','陸游','宋','宋诗','song-poetry','','[]','冬旱土不膏，愛此春夜雨。',72,'全唐诗/poet.song.128000.json','["冬旱土不膏，愛此春夜雨。", "四郊農事興，老穉迭歌舞。", "相呼長沮耕，分喜樊遲圃。", "豐年已在目，亭障靜桴鼓。", "我歸未有期，一官寄倉庾。", "幸復寛簡書，不敢恨覊旅。"]'),
('0735a7f8-c3fa-48e8-ae72-3305b912b1d6','雨中遣懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','病中草草度年華，睡起匆匆日易斜。',64,'全唐诗/poet.song.128000.json','["病中草草度年華，睡起匆匆日易斜。", "抵死愁禁千斛酒，薄情雨送一城花。", "鏡湖烟水揺朱舫，錦里香塵走鈿車。", "此夢即今都打破，不妨寂寞住天涯。"]'),
('ec3cc29e-0287-45d6-a46c-85b7971d6985','雨中遣懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','霏霏春雨細如絲，正是春寒欺客時。',64,'全唐诗/poet.song.128000.json','["霏霏春雨細如絲，正是春寒欺客時。", "心向宦途元淡薄，夢尋鄉國苦參差。", "樓前新漲緑三尺，墻外尚餘紅幾枝。", "擺撥簿書呼酒榼，南湖西塔有幽期。"]'),
('d1e587a6-4067-48e2-aad4-dcf20ccde52f','晚晴','陸游','宋','宋诗','song-poetry','','[]','水聲㶁㶁赴回塘，簾影疏疏遶四廊。',64,'全唐诗/poet.song.128000.json','["水聲㶁㶁赴回塘，簾影疏疏遶四廊。", "靜院數杯傾白墮，幽窗一枕夢清湘。", "潤侵書笥深防蠧，暖徹衣篝剩得香。", "解組徑歸應更樂，偷閑猶足傲羲皇。"]'),
('3406ffe8-7215-4891-a154-86c1143ea555','春晚','陸游','宋','宋诗','song-poetry','','[]','五十六翁身百憂，年来轉覺此生浮。',64,'全唐诗/poet.song.128000.json','["五十六翁身百憂，年来轉覺此生浮。", "山川信美故鄉遠，天地無情雙鬢秋。", "社後燕如歸客至，春殘花不爲人留。", "一觴一詠從来事，莫笑扶衰又上樓。"]'),
('1d0ab6e6-6f41-48cf-b3bb-a79c892be2cc','春晚坐睡忽夢泛舟飲酒樂甚既覺悵然有賦','陸游','宋','宋诗','song-poetry','','[]','夢泛扁舟逸興多，畫橈揺蕩麴生波。',64,'全唐诗/poet.song.128000.json','["夢泛扁舟逸興多，畫橈揺蕩麴生波。", "微風蔌蔌生蒲葦，小雨霏霏濕芰荷。", "舞落烏紗從歲去，歌酣白紵奈情何。", "年来惟覺華胥樂，莫遣茶甌戰睡魔。"]'),
('c12681a9-591d-4e5a-8d02-c03ddeacf96b','遣興','陸游','宋','宋诗','song-poetry','','[]','老子癡頑慣轉蓬，殘年懶復問窮通。',64,'全唐诗/poet.song.128000.json','["老子癡頑慣轉蓬，殘年懶復問窮通。", "赦書雖未除詩債，盟府猶當策酒功。", "桐嶺市回人踏月，柘岡月落鳥呼風。", "浮生觸處無真實，豈獨南柯是夢中。"]'),
('884ab076-f71c-474c-a1ac-ac43bf93f268','老去','陸游','宋','宋诗','song-poetry','','[]','老去時時病，春来日日陰。',48,'全唐诗/poet.song.128000.json','["老去時時病，春来日日陰。", "文書有期會，山水負登臨。", "倦客風埃眼，孤臣狗馬心。", "餘寒欺短褐，莫惜酒杯深。"]'),
('fb2cdfe0-e0fc-4a56-8bc5-e5a04df0e4f5','雨夜','陸游','宋','宋诗','song-poetry','','[]','百紫千紅占歲華，又隨風雨捲泥沙。',64,'全唐诗/poet.song.128000.json','["百紫千紅占歲華，又隨風雨捲泥沙。", "即今空有夢爲蝶，當日曾將命乞花。", "倦枕殘燈人寂寞，幽窗小草字欹斜。", "悲歡變滅何窮已，學得山僧自一家。"]'),
('7e61dfae-ca1d-4bba-9356-65a951d49491','簡黎道士','陸游','宋','宋诗','song-poetry','','[]','滿箔吴蠶繭漸稠，四郊膏雨麥方秋。',64,'全唐诗/poet.song.128000.json','["滿箔吴蠶繭漸稠，四郊膏雨麥方秋。", "道人昔是茶山客，病叟新爲藥市遊。", "耆舊凋零誰晤語，篇章璀璨尚風流。", "蘭亭剡曲春光好，倘肯相從弄釣舟。"]'),
('a6c71061-cf32-423b-94f7-94bab0cdd86a','臨川絕無佳酒時得一醉戲書','陸游','宋','宋诗','song-poetry','','[]','有酒時劇飲，無酒徒浩歌。',96,'全唐诗/poet.song.128000.json','["有酒時劇飲，無酒徒浩歌。", "庭花五六株，老子獨婆娑。", "誰云苦寂寞，在我亦已多。", "管弦萬二千，一笑謝天魔。", "夢作青城去，翠磴捫松蘿。", "又爲平羌遊，素月沉烟波。", "覺来撫几嘆，奈此桎梏何。", "流年不貸人，去去如飛梭。"]'),
('b4a4a04e-c5c6-4a2e-ae26-ac0b69a792c2','醉中懷江湖舊遊偶作短歌','陸游','宋','宋诗','song-poetry','','[]','無渡河，浪花無蒂高崢嶸。',114,'全唐诗/poet.song.128000.json','["無渡河，浪花無蒂高崢嶸。", "莫登樓，茫茫芳草難爲情。", "華軒寶馬只好路旁看，冶金伐石空留後世名。", "古来惟有竹林諸人稱達生，一醉之外萬事鴻毛輕。", "可憐癡人競聲利，坐使方寸森五兵。", "散花洲上青山横，野魚可膾菰可烹。", "脫冠散髮風露冷，臥看江月金盆傾。"]'),
('4aaeb4ca-872d-497c-be0c-16e4d237a026','三月二十一日作','陸游','宋','宋诗','song-poetry','','[]','蹴踘牆東一市譁，鞦韆樓外兩旗斜。',64,'全唐诗/poet.song.128000.json','["蹴踘牆東一市譁，鞦韆樓外兩旗斜。", "及時小雨放桐葉，無賴餘寒開楝花。", "明月吹笙思蜀苑，軟塵騎馬夢京華。", "懽情減盡朱顔改，節物催人只自嗟。"]'),
('01956c45-72eb-48c2-a37c-f598d9f69a9b','天祺節日飯罷小憩','陸游','宋','宋诗','song-poetry','','[]','臥聽午漏隔花傳，簾裏花殘有斷烟。',32,'全唐诗/poet.song.128000.json','["臥聽午漏隔花傳，簾裏花殘有斷烟。", "莫放轆轤鳴玉井，偷閑要補五更眠。"]'),
('23044c82-8f1b-47f0-9f08-501923138458','思歸','陸游','宋','宋诗','song-poetry','','[]','白髮滿青鏡，悵然山水身。',48,'全唐诗/poet.song.128000.json','["白髮滿青鏡，悵然山水身。", "那因五斗米，常作半塗人。", "涉世風波惡，思歸懷抱真。", "會當求鈯斧，送老鏡湖濱。"]'),
('891207bd-5bc9-4a13-a462-8694076a7e43','齒痛有感','陸游','宋','宋诗','song-poetry','','[]','眼暗頭童負聖時，齒牙欲脫更堪悲。',32,'全唐诗/poet.song.128000.json','["眼暗頭童負聖時，齒牙欲脫更堪悲。", "暮年漸解人間事，蒸食哀梨亦自奇。"]'),
('c5fb455c-818e-4c11-8e80-f4f3cebb1e98','南窗睡起二首  其一','陸游','宋','宋诗','song-poetry','','[]','夢中忘却在天涯，一似當年錦里時。',64,'全唐诗/poet.song.128000.json','["夢中忘却在天涯，一似當年錦里時。", "狂倚寶箏歌白紵，醉移銀燭寫烏絲。", "酒来郫縣香初壓，花送彭州露尚滋。", "起坐南窗成絕嘆，玉樓乾鵲誤歸期。"]'),
('e9ec17bd-d5ff-4fb6-a880-67aa279f1d68','南窗睡起二首  其二','陸游','宋','宋诗','song-poetry','','[]','晝漏迢迢暑氣清，不妨小倦带餘酲。',64,'全唐诗/poet.song.128000.json','["晝漏迢迢暑氣清，不妨小倦带餘酲。", "夢從隴客聲中斷，愁向湘屏曲處生。", "風度簾旌紅浪颭，窗明香岫碧雲横。", "閑情賦罷憑誰寄，悵望壺天白玉京。"]'),
('750a3aea-34fb-4ba9-b5c7-11e9f8a65e9d','初夏','陸游','宋','宋诗','song-poetry','','[]','百葉盆榴照眼明，桐陰初密暑猶清。',64,'全唐诗/poet.song.128000.json','["百葉盆榴照眼明，桐陰初密暑猶清。", "深深簾幕度香縷，寂寂房櫳聞燕聲。", "細煆詩聨憑棐几，靜思棋劫對楸枰。", "浣花光景應如昨，回首西州一愴情。"]'),
('dfec9b0d-71ec-4647-9643-1a507f28db37','讀程秀才詩','陸游','宋','宋诗','song-poetry','','[]','程子晚相得，居然一坐傾。',48,'全唐诗/poet.song.128000.json','["程子晚相得，居然一坐傾。", "新詩欲飛動，病眼爲開明。", "英妙非凢質，衰遲畏後生。", "吾徒可相賀，五字有長城。"]'),
('6708d8ba-09e4-4fda-af7b-17822897897e','晨起','陸游','宋','宋诗','song-poetry','','[]','一官又寄汝江頭，落魄文園故倦遊。',64,'全唐诗/poet.song.129000.json','["一官又寄汝江頭，落魄文園故倦遊。", "榻上鐸聲悲破夢，簷邊桐葉冷生秋。", "暮年作吏寧長策，薄禄縻人尚小留。", "晨起凭欄嘆衰甚，接䍦紗薄髮颼颼。"]'),
('47a8052b-4630-4126-9447-27c16d32b413','雨夜','陸游','宋','宋诗','song-poetry','','[]','兩鬢新霜換舊青，客遊身世等浮萍。',32,'全唐诗/poet.song.129000.json','["兩鬢新霜換舊青，客遊身世等浮萍。", "少年樂事消除盡，雨夜焚香誦道經。"]'),
('671bdbb4-ad5e-457a-bf5f-09c9187fdf40','得京書或怪久不通問','陸游','宋','宋诗','song-poetry','','[]','慣向江湖鎩羽翰，雲霄那敢接鵷鸞。',64,'全唐诗/poet.song.129000.json','["慣向江湖鎩羽翰，雲霄那敢接鵷鸞。", "百年未必如炊久，萬事真須作夢看。", "白首據鞍慚侠氣，青燈顧影嘆儒酸。", "手遮西日成何味，還我平生舊釣竿。"]'),
('cfa604f8-e81e-41d9-aa85-9e68d9fd9304','水亭','陸游','宋','宋诗','song-poetry','','[]','日淡暑猶薄，雨餘風更清。',48,'全唐诗/poet.song.129000.json','["日淡暑猶薄，雨餘風更清。", "翛然水亭立，試此葛衣輕。", "晒粉憐孤蝶，穿枝喜晚鶯。", "誰知簿書裏，也復得吾生。"]'),
('e205f82f-7b2d-49ee-9178-679c4574b71c','醉眠','陸游','宋','宋诗','song-poetry','','[]','達士如鴟夷，無客亦自醉。',72,'全唐诗/poet.song.129000.json','["達士如鴟夷，無客亦自醉。", "癡人如撲滿，多藏作身祟。", "放翁亦何長，偶自遠聲利。", "胸中白如練，不著一毫僞。", "醉来酣午枕，晴日雷起鼻。", "寄謝敲門人，予方有公事。"]'),
('cbf9b13c-e6e7-4f8b-ac98-e392f5fc18e6','感舊絕句七首  其一','陸游','宋','宋诗','song-poetry','','[]','鴨翎堠前山簇馬，雞蹤橋下水連天。',32,'全唐诗/poet.song.129000.json','["鴨翎堠前山簇馬，雞蹤橋下水連天。", "金丹煉成不肯服，且戲人間五百年。"]'),
('b44d0a9a-1162-472d-b2b8-a5b19d79bd5e','感舊絕句七首  其二','陸游','宋','宋诗','song-poetry','','[]','鵝黄酒邊緑荔枝，摩訶池上納涼時。',32,'全唐诗/poet.song.129000.json','["鵝黄酒邊緑荔枝，摩訶池上納涼時。", "冰紈不畫驂鸞女，却寫江南白紵辭。"]'),
('bdb58eef-6f50-421e-973c-c4c4de39f823','感舊絕句七首  其三','陸游','宋','宋诗','song-poetry','','[]','南市夜夜上元燈，西郊日日是清明。',32,'全唐诗/poet.song.129000.json','["南市夜夜上元燈，西郊日日是清明。", "青氊犢車碾花去，黄金馬鞭穿柳行。"]'),
('79b6c20b-bfcb-4baf-a5b3-b5cdd13d6dc9','感舊絕句七首  其四','陸游','宋','宋诗','song-poetry','','[]','十月新霜兔正肥，佳人駿馬去如飛。',32,'全唐诗/poet.song.129000.json','["十月新霜兔正肥，佳人駿馬去如飛。", "纖腰嫋嫋戎衣窄，學射山前看打圍。"]'),
('10697912-a200-4bf3-8840-9a6afea59d3b','感舊絕句七首  其五','陸游','宋','宋诗','song-poetry','','[]','半紅半白官池蓮，半醒半醉女郎舩。',32,'全唐诗/poet.song.129000.json','["半紅半白官池蓮，半醒半醉女郎舩。", "鴛鴦驚起何曾管，折得雙頭喜欲顛。"]'),
('9957355b-8c73-4d73-84db-3183c46aa0c6','感舊絕句七首  其六','陸游','宋','宋诗','song-poetry','','[]','紅葉琵琶出嘉州，四弦彈盡古今愁。',32,'全唐诗/poet.song.129000.json','["紅葉琵琶出嘉州，四弦彈盡古今愁。", "胡沙漫漫紫塞曉，漢月娟娟青冢秋。"]'),
('07d90306-bd51-4cfb-84ad-380bfbf9e7e4','感舊絕句七首  其七','陸游','宋','宋诗','song-poetry','','[]','美人傳酒清夜闌，欲歌未歌愁遠山。',32,'全唐诗/poet.song.129000.json','["美人傳酒清夜闌，欲歌未歌愁遠山。", "蒲萄一斗元無價，換得涼州也是閑。"]'),
('c0a23155-029d-445f-8ef5-9d7dda0e73e9','晝臥聞百舌','陸游','宋','宋诗','song-poetry','','[]','雨後郊原已遍犁，陰陰簾幙燕分泥。',32,'全唐诗/poet.song.129000.json','["雨後郊原已遍犁，陰陰簾幙燕分泥。", "閑眠不作華胥計，說與春烏自在啼。"]'),
('a5c3d8a4-ef13-483a-ab87-9970133b4705','寄呂博士','陸游','宋','宋诗','song-poetry','','[]','薄宦東西蜀，僑居太少城。',48,'全唐诗/poet.song.129000.json','["薄宦東西蜀，僑居太少城。", "休論九年謫，喜識萬人英。", "别久心常折，書来眼未明。", "功名君自力，丘壑我平生。"]'),
('20c7ba7a-133a-487f-8e50-e476ccb844b3','遊疏山','陸游','宋','宋诗','song-poetry','','[]','我願匹馬飛騰遍九州，如今苦無騕褭與驊騮。',132,'全唐诗/poet.song.129000.json','["我願匹馬飛騰遍九州，如今苦無騕褭與驊騮。", "葛陂之龍又難致，兀兀安得忘吾愁。", "幸餘一事差可喜，雲山萬里芒鞵底。", "曵杖行穿嶓冢雲，試茶手挹香溪水。", "江西山水增怪奇，疏山之名舊所知。", "惜哉不見侏儒師，尚想薪水俱空時。", "寺門欲近山若拆，老樹蒼崖含古色。", "挂包便住吾豈能，一来要是疏山客。"]'),
('61ca9af2-659b-4865-ad60-03bf955746a6','疏山東堂晝眠','陸游','宋','宋诗','song-poetry','','[]','飯飽眼欲閉，心閑身自安。',48,'全唐诗/poet.song.129000.json','["飯飽眼欲閉，心閑身自安。", "樂超六欲界，美過八珍盤。", "香縷縈簷斷，松風逼枕寒。", "吾兒解原夢，爲我轉雲圑。"]'),
('1a5c65df-efa3-4c37-88e5-52e5ee87810f','山中作','陸游','宋','宋诗','song-poetry','','[]','朱墨紛紛訟滿庭，半年初得試山行。',64,'全唐诗/poet.song.129000.json','["朱墨紛紛訟滿庭，半年初得試山行。", "燒香掃地病良已，飲水飯蔬身頓輕。", "日落三通傳浴鼓，雨餘千耦看農耕。", "故巢光景還如此，爲底淹留白髮生。"]'),
('abcfb288-276d-4361-8153-f8d706a43493','觀蔬圃','陸游','宋','宋诗','song-poetry','','[]','菘芥可葅芹可羮，晚風咿{中軋}桔槔聲。',35,'全唐诗/poet.song.129000.json','["菘芥可葅芹可羮，晚風咿{中軋}桔槔聲。", "白頭孤宦成何味，悔不畦蔬過此生。"]'),
('3349dfad-01a6-44b5-a21b-10661c9e0681','東堂晨起有感','陸游','宋','宋诗','song-poetry','','[]','不解飛車越九州，青鞵處處爲山留。',64,'全唐诗/poet.song.129000.json','["不解飛車越九州，青鞵處處爲山留。", "百年未盡且作夢，三日閑行聊散愁。", "世上幾經華表柱，尊前好在黑貂裘。", "龍泉幸是無人斸，暮露光芒上斗牛。"]'),
('809b8f01-29f2-4fd8-88a0-53e27ad5fc3a','金溪道中','陸游','宋','宋诗','song-poetry','','[]','雲闇苦竹市，雨来烏石岡。',48,'全唐诗/poet.song.129000.json','["雲闇苦竹市，雨来烏石岡。", "駕犁雙犢健，煮繭一村香。", "天地君恩重，風埃吏責忙。", "敢辭坡路滑，且領筍輿涼。"]'),
('1038e2f7-dd60-45e6-8d65-049dc2cb1eb3','小憩前平院戲書觸目','陸游','宋','宋诗','song-poetry','','[]','道邊小寺名前平，殘僧二三屋半傾。',128,'全唐诗/poet.song.129000.json','["道邊小寺名前平，殘僧二三屋半傾。", "旁分千畦畫楸局，正對一山横翠屏。", "修纖弱蔓上幽援，堅瘦穉柏當前榮。", "稻秧正青白鷺下，桑椹爛紫黄鸝鳴。", "村虚賣茶已成市，林薄打麥惟聞聲。", "泥行扶犁吒新犢，野饁燒笋炊香秔。", "十年此樂發夢想，忽然到眼難爲情。", "上車欲去復回首，那將暮境供浮名。"]'),
('afe488b3-ab64-4ad6-9de3-cc39ae8de526','遣興','陸游','宋','宋诗','song-poetry','','[]','小麥登場雨熟梅，閉門病眼每慵開。',64,'全唐诗/poet.song.129000.json','["小麥登場雨熟梅，閉門病眼每慵開。", "酒杯不解爲愁敵，書卷纔開作睡媒。", "骨朽空名垂斷簡，冢荒殘碣臥蒼苔。", "紛紛傾奪知何得，老覺人間但可哀。"]'),
('0b056378-b710-4e02-b136-3960b838af58','雨後獨登擬峴臺','陸游','宋','宋诗','song-poetry','','[]','高城斷處閣横空，目力雖窮興未窮。',64,'全唐诗/poet.song.129000.json','["高城斷處閣横空，目力雖窮興未窮。", "燕子爭泥朱檻外，人家曬網緑洲中。", "誰能招喚三秋月，我欲憑陵萬里風。", "更比峴山無湛輩，論交惟是一枝笻。"]'),
('f81a4623-1088-44b1-b861-68faaee8fa29','數日訴牒苦多憊甚戲作','陸游','宋','宋诗','song-poetry','','[]','江南五月暑猶薄，梅子正黄風雨惡。',64,'全唐诗/poet.song.129000.json','["江南五月暑猶薄，梅子正黄風雨惡。", "庭中訟獠不貸人，急甚常如虎遭縛。", "空齋鼠迹留几塵，賦詩飲酒疑前身。", "脫歸徑臥與壁語，敢恨無人問良苦。"]'),
('04ad4cb2-1f92-4740-b6cd-7038521a5f4c','與黎道士小飲偶言及曾文清公慨然有感','陸游','宋','宋诗','song-poetry','','[]','臨川税駕忽數月，嗜睡愛閑常閉門。',64,'全唐诗/poet.song.129000.json','["臨川税駕忽數月，嗜睡愛閑常閉門。", "君詩始惬病僧意，吾道難爲俗人言。", "秋雨凄凄黄葉寺，春風酣酣緑樹村。", "曾公九原不可作，一尊破涕誦招魂。"]'),
('d94c1a7b-c6e6-41f9-8cf1-04ad292f342d','念歸','陸游','宋','宋诗','song-poetry','','[]','江城五月朝暮雨，雨脚纔收水流礎。',96,'全唐诗/poet.song.129000.json','["江城五月朝暮雨，雨脚纔收水流礎。", "酒杯未把愁作病，麈柄欲拈誰共語。", "有時暫解簿書圍，獨坐藤床看香縷。", "林塘渺渺鳩正懽，簾幙陰陰燕新乳。", "湖山舊隱入我夢，白首忘歸獨安取。", "一生花裏醉春風，即今願作扶犁翁。"]'),
('ca7ce9e0-37c0-42a0-a7ad-d4b616b22cb8','五月十一日夜且半夢從大駕親征盡復漢唐故地見城邑人物繁麗云西涼府也喜甚馬上作長句未終篇而覺乃足成之','陸游','宋','宋诗','song-poetry','','[]','天寶胡兵陷兩京，北庭安西無漢營。',128,'全唐诗/poet.song.129000.json','["天寶胡兵陷兩京，北庭安西無漢營。", "五百年間置不問，聖主下詔初親征。", "熊羆百萬從鑾駕，故地不勞傳檄下。", "築城絕塞進新圖，排仗行宮宣大赦。", "岡巒極目漢山川，文書初用淳熙年。", "駕前六軍錯錦繡，秋風鼓角聲滿天。", "苜蓿峰前盡亭障，平安火在交河上。", "涼州女兒滿高樓，梳頭已學京都様。"]'),
('b9ba2299-9269-4f8b-8e5d-ab0e19e0d476','雨夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','牆西泥三寸，牆東草三尺。',72,'全唐诗/poet.song.129000.json','["牆西泥三寸，牆東草三尺。", "可憐白鹿泉，蛙黽紛狼籍。", "濕螢如隕星，入戸黏几席。", "病夫本嗜睡，況此風雨夕。", "永懷瀼西寺，更憶山南驛。", "陳迹不可追，昏然墮吾幘。"]'),
('01be9e3b-065a-4c1c-8b66-326fcc176179','雨夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','簷高雨聲壯，堂豁霧氣入。',72,'全唐诗/poet.song.129000.json','["簷高雨聲壯，堂豁霧氣入。", "飛螢照畫棟，相逐光熠熠。", "向来經春旱，蒼耳暗原隰。", "微官又厚責，撫事百憂集。", "三日雨不休，四野苖盡立。", "登高思賦詩，簿書縛人急。"]'),
('14166e1b-9999-496b-a179-62bf8230d02f','焚香晝睡比覺香猶未散戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','小屏烟樹遠參差，吏散身閑與睡宜。',32,'全唐诗/poet.song.129000.json','["小屏烟樹遠參差，吏散身閑與睡宜。", "誰似爐香念幽獨，伴人直到夢回時。"]'),
('dca68bdc-08c6-4aad-a73b-c31819f0059d','焚香晝睡比覺香猶未散戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','燕梁寂寂篆烟殘，偷得勞生數刻閑。',32,'全唐诗/poet.song.129000.json','["燕梁寂寂篆烟殘，偷得勞生數刻閑。", "三疊秋屏護琴枕，臥遊忽到瀼西山。"]'),
('e46f9652-275c-4866-8954-6336b2143b93','仲夏小旱方致禱忽大雨連日江水爲漲喜而有作','陸游','宋','宋诗','song-poetry','','[]','旱苖垂槁嘆何堪，大雨誰知變立談。',64,'全唐诗/poet.song.129000.json','["旱苖垂槁嘆何堪，大雨誰知變立談。", "翠麓青林呑欲盡，惡風白浪戰方酣。", "江翻龜窟連雲澤，雷挟龍腥起雪潭。", "從此年豐真少事，炷香終日坐蒲龕。"]'),
('336208e8-af4f-4048-a256-b2595b55d304','冒雨登擬峴臺觀江漲','陸游','宋','宋诗','song-poetry','','[]','雨氣分千嶂，江聲撼萬家。',48,'全唐诗/poet.song.129000.json','["雨氣分千嶂，江聲撼萬家。", "雲翻一天墨，浪蹴半空花。", "噴薄侵虚閣，低昻泛斷槎。", "壯遊思夙昔，乘醉下三巴。"]'),
('61329884-d99a-47f7-893e-d1be4cc6ce90','薙庭草','陸游','宋','宋诗','song-poetry','','[]','露草烟蕪與砌平，群蛙得意亂疏更。',32,'全唐诗/poet.song.129000.json','["露草烟蕪與砌平，群蛙得意亂疏更。", "微涼要作安眠地，放散今宵鼓吹聲。"]'),
('c64bc020-3a89-4e77-aa64-bc089954f824','蛺蝶詞','陸游','宋','宋诗','song-poetry','','[]','蛱蝶子，去復来，草長齊腰花亂開。',64,'全唐诗/poet.song.129000.json','["蛱蝶子，去復来，草長齊腰花亂開。", "蜜蜂辛苦爲人計，林鶯百囀胡爲哉。", "嗟爾蛺蝶獨得意，飛来飛去無嫌猜。", "追花逐絮闌干角，人生安得如汝樂。"]'),
('1ff31e09-46ad-4682-8394-c45f22e0955e','大雨踰旬既止復作江遂大漲二首  其一','陸游','宋','宋诗','song-poetry','','[]','牆角蚊雷喧甲夜，濕星昏昏出雲罅。',64,'全唐诗/poet.song.129000.json','["牆角蚊雷喧甲夜，濕星昏昏出雲罅。", "臨堂仰占久嘆咤，懸知龍君未稅駕。", "行人困苦泥沒胯，居人悲啼江入舍。", "便晴猶可望秋稼，努力共禱城南社。"]'),
('e235bc0b-49aa-4a63-b1d1-6644571eaa0f','大雨踰旬既止復作江遂大漲二首  其二','陸游','宋','宋诗','song-poetry','','[]','一春少雨憂旱暵，熟睡湫潭坐龍懶。',64,'全唐诗/poet.song.129000.json','["一春少雨憂旱暵，熟睡湫潭坐龍懶。", "以勤贖懶護其短，水浸城門渠不管。", "傳聞霖潦千里遠，榜舟發粟敢不勉。", "空村避水無雞犬，茆舍夜深螢火滿。"]'),
('5149ed55-356b-4065-82ea-7a81ddd867d2','燒丹示道流','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','昔燒大藥青牛谷，磊落玉床收箭鏃。',96,'全唐诗/poet.song.129000.json','["昔燒大藥青牛谷，磊落玉床收箭鏃。", "扶桑朝暾謹火候，仙掌秋露勤沐浴。", "带間小瓢鬼神衛，異氣如虹夜穿屋。", "點成黄金棄山海，揮手人間一裘足。", "明年服丹徑仙去，洞庭月冷吹横玉。", "相逢只恐驚倒君，毛髮毿毿垂地緑。"]'),
('98c62993-c009-4dfc-b234-7e41f8f599bb','書感','陸游','宋','宋诗','song-poetry','','[]','半世狂疏踐駭機，暮年持此欲安居。',64,'全唐诗/poet.song.129000.json','["半世狂疏踐駭機，暮年持此欲安居。", "曾憑香火消前業，已築茆茨訟昨非。", "薄俗慣看翻覆手，憂心空復倒顛衣。", "烟蓑雪笠家風在，送老湖邊一釣磯。"]'),
('8e74c3ff-e75a-47e6-8c66-107f91ad1fe8','夏日','陸游','宋','宋诗','song-poetry','','[]','病退身初健，時清吏更休。',48,'全唐诗/poet.song.129000.json','["病退身初健，時清吏更休。", "渴蜂窺硯水，慵燕息簾鈎。", "碁局每坐隱，屏山時臥遊。", "真成愛長日，未用憶新秋。"]'),
('3e91c1d9-775e-4c13-8bde-8b2aa32e4c18','寄統','陸游','宋','宋诗','song-poetry','','[]','大兒挈藥囊，小兒負書笈。',96,'全唐诗/poet.song.129000.json','["大兒挈藥囊，小兒負書笈。", "共作蘭亭遊，詎必群賢集。", "言此二十年，白首終未踐。", "汝復守荆扉，經年不相見。", "楚越天一涯，書疏何由頻。", "諸弟亦可憐，說兄輒酸辛。", "江城秋尚遠，桐葉落可掃。", "悵然懷故谿，菱絲雨中老。"]'),
('9ace2ba6-eecc-4e86-a8df-0945555f7b56','自訟','陸游','宋','宋诗','song-poetry','','[]','家弊須微禄，年衰尚遠遊。',48,'全唐诗/poet.song.129000.json','["家弊須微禄，年衰尚遠遊。", "未逃朋友責，更遣吏民羞。", "采藥思長往，傳書却小留。", "微風入桐葉，分我一簾秋。"]'),
('dbdc06f2-a7fa-4c26-a0e3-da2000fc279c','夏日晝寢夢遊一院闃然無人簾影滿堂惟燕蹋箏弦有聲覺而聞鐵鐸風響璆然殆所夢也邪因得絕句','陸游','宋','宋诗','song-poetry','','[]','桐陰清潤雨餘天，簷鐸揺風破晝眠。',32,'全唐诗/poet.song.129000.json','["桐陰清潤雨餘天，簷鐸揺風破晝眠。", "夢到畫堂人不見，一雙輕燕蹴箏弦。"]'),
('805d9cda-41fd-4523-999a-810f9066312e','虚堂','陸游','宋','宋诗','song-poetry','','[]','暑氣虚堂一點無，爽如秋露貯冰壺。',64,'全唐诗/poet.song.129000.json','["暑氣虚堂一點無，爽如秋露貯冰壺。", "滄州未遽浮舴艋，碧井聊聽放轆轤。", "肅肅清風生薤簟，酣酣美睡付紗幮。", "惱人不奈奴兵輩，環抱文書待日晡。"]'),
('a0d09f3e-1bc4-41ac-afdc-f91d93748f20','夢仙','陸游','宋','宋诗','song-poetry','','[]','中宵遊帝所，廣殿綴仙官。',48,'全唐诗/poet.song.129000.json','["中宵遊帝所，廣殿綴仙官。", "天逼星辰大，霜清劍珮寒。", "賦詩題碧簡，侍宴跨青鸞。", "惆悵塵緣重，夢殘更未殘。"]'),
('b3cfc0e2-f56c-4acb-8140-e4d0f6a0c358','自嘲','陸游','宋','宋诗','song-poetry','','[]','夜作看花夢，朝賦飲酒詩。',72,'全唐诗/poet.song.129000.json','["夜作看花夢，朝賦飲酒詩。", "吾夢固忘矣，詩亦聊自欺。", "荒園無佳花，牽牛漫疏籬。", "給酒月四斗，一觴難屢持。", "悲歡有定數，未至誰得知。", "願從大鈞問，一笑在何時。"]'),
('c15e3158-6c7f-4ce3-8a3a-cf867e4fe56b','長歌行','陸游','宋','宋诗','song-poetry','','[]','燕燕尾涎涎，横穿乞巧樓。',98,'全唐诗/poet.song.129000.json','["燕燕尾涎涎，横穿乞巧樓。", "低入吹笙院，鴨鴨觜唼唼。", "朝浮杜若洲，暮宿蘆花夾。", "嗟爾自適天，地間將儔命。", "侶意甚閑我，今獨何爲一。", "笑乃爾慳世，上悲歡亦偶。", "然何時爛醉，錦江邊人歸。", "華表三千歲，春入箜篌十四弦。"]'),
('b221605c-2c4f-492d-b180-89c2bf36a2bd','對酒','陸游','宋','宋诗','song-poetry','','[]','簷鐸鳴雜珮，簾旌動微波。',84,'全唐诗/poet.song.129000.json','["簷鐸鳴雜珮，簾旌動微波。", "我老懶讀書，如此長日何。", "名酒来清江，嫩色如新鵝。", "奇葅映玉盤，珍鮓開緑荷。", "萬事姑置之，逌然酣且歌。", "宦遊亦何好，且復小婆娑。", "秋風雲門道，踏月捫青蘿。"]'),
('3caf6224-1b14-4fe0-b787-28127f52cfac','自詠','陸游','宋','宋诗','song-poetry','','[]','夢歸不恨故山深，霜雪今年已滿簪。',64,'全唐诗/poet.song.129000.json','["夢歸不恨故山深，霜雪今年已滿簪。", "報國有心身潦倒，養生無術病侵尋。", "晨興聊取經遮眼，夜坐時憑易洗心。", "安用更爲逃暑飲，虚堂三復自蕭森。"]'),
('1ffb84a2-7c8f-423e-9530-0c8263324742','夏日睡起','陸游','宋','宋诗','song-poetry','','[]','簟紋似秋水，含風蹙微漪。',72,'全唐诗/poet.song.129000.json','["簟紋似秋水，含風蹙微漪。", "帳幅如春烟，縹緲不受吹。", "團扇墮枕邊，皎皎素月暉。", "非睡復非覺，心定息自遲。", "茶熟我亦起，寒泉掬珠璣。", "浮瓜空把玩，甚矣今年衰。"]'),
('41cf2061-ad91-4e0c-95fa-068d1610060c','所居堂極涼雖三伏常有秋意也偶得長句','陸游','宋','宋诗','song-poetry','','[]','高棟虚簷六月涼，野人誰遣寄華堂。',64,'全唐诗/poet.song.129000.json','["高棟虚簷六月涼，野人誰遣寄華堂。", "炎威自避重重幙，清吹時生曲曲廊。", "白苧出箱開疊雪，甘瓜隨刃落輕霜。", "憑誰爲報金羈客，滿帽京塵有底忙。"]'),
('266891c4-edcf-476a-84d1-73d4881b3859','雨後露坐小酌','陸游','宋','宋诗','song-poetry','','[]','閉門誰與樂頽年，旋掃桐陰近酒邊。',64,'全唐诗/poet.song.129000.json','["閉門誰與樂頽年，旋掃桐陰近酒邊。", "病久一春稀見蝶，雨多六月始聞蟬。", "官倉求飽真聊爾，山墅懷歸每惘然。", "從此讀書仍復懶，惟留白眼望青天。"]'),
('3c3f95b6-4218-439b-a76d-e591434eec13','日暮南窗納涼','陸游','宋','宋诗','song-poetry','','[]','冠蓋塵沙得我憎，脫巾聊喜髮鬅鬙。',64,'全唐诗/poet.song.129000.json','["冠蓋塵沙得我憎，脫巾聊喜髮鬅鬙。", "素娥東踊行空濶，清吹南来掃鬱蒸。", "團扇正閑看破墨，矮床欹臥怯文藤。", "扁舟歸去應尤樂，莫羡金盤賜苑冰。"]'),
('ef9cde1a-abef-4299-a04d-51dd0df57849','中夜起登堂北小亭','陸游','宋','宋诗','song-poetry','','[]','幽人曵杖上青冥，掠面風輕宿醉醒。',64,'全唐诗/poet.song.129000.json','["幽人曵杖上青冥，掠面風輕宿醉醒。", "朱戸半開迎落月，碧溝不動浸疏星。", "禽聲格磔頻移樹，花影扶疏自滿庭。", "嘆息明年又安往，此身何啻似浮萍。"]'),
('1653b78a-6416-4aaa-83da-0a09edf461a0','登擬峴臺','陸游','宋','宋诗','song-poetry','','[]','憔悴思吴客，凄涼擬峴臺。',48,'全唐诗/poet.song.129000.json','["憔悴思吴客，凄涼擬峴臺。", "一年秋欲到，兩鬢老先催。", "裊裊菱歌斷，翩翩水鳥来。", "倚闌哦五字，未穩莫輕回。"]'),
('4bfcef21-71c1-46fd-aa1c-c542395176c3','夜意','陸游','宋','宋诗','song-poetry','','[]','灑地移床曲檻前，葛衣蕭爽接䍦偏。',64,'全唐诗/poet.song.129000.json','["灑地移床曲檻前，葛衣蕭爽接䍦偏。", "庭空秋近露沾草，月落夜闌星滿天。", "靜待微風停素扇，旋消殘酒潄寒泉。", "翛然自與氛埃遠，安用騎鯨學水仙。"]'),
('a3fa0af4-daae-4ef1-8838-b86b421d3505','道院遣興','陸游','宋','宋诗','song-poetry','','[]','微官不復嘆頭顱，高棟虚窗樂有餘。',64,'全唐诗/poet.song.129000.json','["微官不復嘆頭顱，高棟虚窗樂有餘。", "中夜塔鈴空際語，望秋庭樹月中疏。", "甗炊青飯留巖客，露點朱毫勘玉書。", "猶恨未成歸剡曲，小舟閑采白芙渠。"]'),
('9135da28-2501-4d54-9067-92b16c54d048','夜行至白鹿泉上','陸游','宋','宋诗','song-poetry','','[]','小雨病良已，新秋夜漸長。',48,'全唐诗/poet.song.129000.json','["小雨病良已，新秋夜漸長。", "隔城聞鶴唳，出户逐螢光。", "荒徑穿蒙密，遥空望莽蒼。", "泉聲落環珮，肝肺爲清涼。"]'),
('aca2c91e-85eb-4808-9635-ccadf95231d0','堂中以大盆漬白蓮花石菖蒲翛然無復暑意睡起戲書','陸游','宋','宋诗','song-poetry','','[]','海東銅盆面五尺，中貯澗泉涵淺碧。',96,'全唐诗/poet.song.129000.json','["海東銅盆面五尺，中貯澗泉涵淺碧。", "豈惟冷浸玉芙蕖，青青菖蒲絡奇石。", "長安火雲行日車，此間暑氣一點無。", "紗幮竹簟睡正美，鼻端雷起驚僮奴。", "覺来隱几日初午，碾就壑源分細乳。", "却拈燥筆寫新圖，八幅冰綃瘦蛟舞。"]'),
('c8022ce5-feab-4669-8447-a0d5a8c8768b','初秋','陸游','宋','宋诗','song-poetry','','[]','濕螢相逐照高棟，又見一年風露秋。',64,'全唐诗/poet.song.129000.json','["濕螢相逐照高棟，又見一年風露秋。", "流落江湖常踽踽，掃平河洛轉悠悠。", "簿書終日了官事，尊酒何時寛客愁。", "擬倩天風吹夢去，浩歌起舞散花樓。"]'),
('9685575e-a6e3-4e58-b135-5d0134d244c0','書懷絕句五首  其一','陸游','宋','宋诗','song-poetry','','[]','不到天台三十年，草庵猶記宿雲邊。',32,'全唐诗/poet.song.129000.json','["不到天台三十年，草庵猶記宿雲邊。", "老僧曉出松門去，手挈軍持取澗泉。"]'),
('3c055add-01ea-4fa5-b6de-51728f4afc61','書懷絕句五首  其二','陸游','宋','宋诗','song-poetry','','[]','憶過棲賢見蜀僧，雲堂十月冷生冰。',32,'全唐诗/poet.song.129000.json','["憶過棲賢見蜀僧，雲堂十月冷生冰。", "定回蔌蔌聞窗雪，一椀琉璃照佛燈。"]'),
('b3bbb4f2-4dfe-4b0d-abfe-534a12bfa40c','書懷絕句五首  其三','陸游','宋','宋诗','song-poetry','','[]','丈人祠西山谷盤，麻姑洞前松櫟寒。',32,'全唐诗/poet.song.129000.json','["丈人祠西山谷盤，麻姑洞前松櫟寒。", "仙翁欲覓渺無處，聞在青溪浴大丹。"]'),
('a92cbeb4-3eb9-4465-ad07-7aa7e15f7c0e','書懷絕句五首  其四','陸游','宋','宋诗','song-poetry','','[]','早佩黄庭兩卷經，不應靈府雜羶腥。',32,'全唐诗/poet.song.129000.json','["早佩黄庭兩卷經，不應靈府雜羶腥。", "憑君爲買金鴉觜，歸去秋山斸茯苓。"]'),
('30f0b1fe-0830-415c-b8ed-cc45693840d1','書懷絕句五首  其五','陸游','宋','宋诗','song-poetry','','[]','未駕青鸞返帝鄉，三江七澤路茫茫。',32,'全唐诗/poet.song.129000.json','["未駕青鸞返帝鄉，三江七澤路茫茫。", "看山看水無程數，漁艇爲家芡作糧。"]'),
('8e814cac-6fb9-4467-b5f0-97dbbf2aa3c0','狂吟','陸游','宋','宋诗','song-poetry','','[]','浮世何須宇宙名，一狂自足了平生。',64,'全唐诗/poet.song.129000.json','["浮世何須宇宙名，一狂自足了平生。", "秋風湘浦紉蘭佩，夜月緱山聽玉笙。", "學劍慣曾遊紫閣，結巢終欲隱青城。", "年来自笑彌耽酒，百斛蒲萄未觧酲。"]'),
('c556e490-0099-4fc1-8e9f-cc839b2de00b','閔雨','陸游','宋','宋诗','song-poetry','','[]','潭底乖龍喚不譍，驕陽似欲敗西成。',32,'全唐诗/poet.song.129000.json','["潭底乖龍喚不譍，驕陽似欲敗西成。", "虚堂永夜耿無睡，起聽四郊車水聲。"]'),
('b427931f-b897-4cfc-8d58-a4af54f9633a','初秋小疾效俳諧體','陸游','宋','宋诗','song-poetry','','[]','宿疢逢秋劇，衰容逐日添。',48,'全唐诗/poet.song.129000.json','["宿疢逢秋劇，衰容逐日添。", "專房一竹几，列屋萬牙籖。", "遣悶憑清聖，忘情付黑甜。", "晚来風月好，一笑捲疏簾。"]'),
('2b721d4d-5d09-4bf0-be17-4c66c3c2fb57','雨後極涼料簡篋中舊書有感','陸游','宋','宋诗','song-poetry','','[]','日昳小雨不至晡，雨雖未足涼有餘。',128,'全唐诗/poet.song.129000.json','["日昳小雨不至晡，雨雖未足涼有餘。", "細泉泠泠咽幽竇，清吹策策驚高梧。", "笠澤老翁病蘇醒，欣然起理西齋書。", "十年燈前手自校，行間顛倒黄與朱。", "區區樸學老自信，要與萬卷歸林廬。", "爾来世俗喜變古，鑿空飾詐無根株。", "愀然撫几三太息，力薄抱恨何由袪。", "蘭臺漆書非己責，且爲籖幐除蠧魚。"]'),
('ce1edc7a-0e97-4afe-8abd-b08c0a2f01f1','秋夜','陸游','宋','宋诗','song-poetry','','[]','湖海秋初到，房櫳夜轉幽。',48,'全唐诗/poet.song.129000.json','["湖海秋初到，房櫳夜轉幽。", "露濃驚鶴夢，月冷伴蛩愁。", "生計依微禄，年光墮遠遊。", "嚴灘已在眼，早晚放孤舟。"]'),
('7164695f-1d0e-4dcc-a612-a697fd0f400f','鈔書','陸游','宋','宋诗','song-poetry','','[]','書生習氣重，見書喜欲狂。',84,'全唐诗/poet.song.129000.json','["書生習氣重，見書喜欲狂。", "擣蘖潢剡藤，辛苦補散亡。", "且作短檠伴，未暇名山藏。", "故家借籤帙，舊友餉朱黄。", "皇墳探八索，奇字窮三蒼。", "儲積山崇崇，探求海茫茫。", "一笑語兒子，此是却老方。"]'),
('a7a3ae23-b43d-4214-9476-93158c3e128a','晚自白鹿泉上歸','陸游','宋','宋诗','song-poetry','','[]','坐穴藜床愧未能，酌泉聊喜曵枯藤。',64,'全唐诗/poet.song.129000.json','["坐穴藜床愧未能，酌泉聊喜曵枯藤。", "詩從病後功殊少，酒到愁邊量自增。", "事業何由垂竹帛，笑談空覺負交朋。", "興闌却逐棲鴉返，寂寞西窗已上燈。"]'),
('2dcb311d-7f14-438a-8ef7-ef6fba25b950','秋旱方甚七月二十八夜忽雨喜而有作','陸游','宋','宋诗','song-poetry','','[]','嘉穀如焚稗草青，沉憂耿耿欲忘生。',32,'全唐诗/poet.song.129000.json','["嘉穀如焚稗草青，沉憂耿耿欲忘生。", "鈞天九奏簫韶樂，未抵虚簷瀉雨聲。"]'),
('5e6d1370-4cac-49d8-9ec7-bafc2c60a597','秋日小雨有感','陸游','宋','宋诗','song-poetry','','[]','七月江邊暑已微，虚窗臥看雨霏霏。',64,'全唐诗/poet.song.129000.json','["七月江邊暑已微，虚窗臥看雨霏霏。", "凄凉蛩伴草根語，憔悴鵲從天上歸。", "志士酒酣看寶劍，美人泪盡倚鴛機。", "嗟予亦有新秋感，遥憶蒼苔滿釣磯。"]'),
('4e09d377-0dbb-425b-86a4-0a85081e1819','書李商叟秀才所藏曾文清詩卷後','陸游','宋','宋诗','song-poetry','','[]','隴蜀歸来兩鬢絲，茶山已作隔生期。',32,'全唐诗/poet.song.129000.json','["隴蜀歸来兩鬢絲，茶山已作隔生期。", "西風落葉秋蕭瑟，泪灑行間讀舊詩。"]'),
('4a3d6496-1ff7-44bb-a9dc-dfe04027ecab','碧海行','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','碧海如鏡天無雲，衆真東謁青童君。',80,'全唐诗/poet.song.129000.json','["碧海如鏡天無雲，衆真東謁青童君。", "九奏鏗鏘洞庭樂，八角森茫龍漢文。", "共傳上帝新有詔，蚩尤下統旄頭軍。", "徑持河洛還聖主，更度邊徼清塵氛。", "藝祖騎龍在帝左，世上但策雲臺勲。"]'),
('31532f68-3145-4e8d-b660-10fd552cec7b','道院遣興','陸游','宋','宋诗','song-poetry','','[]','滿鏡新霜老可驚，十年烟隴廢春耕。',64,'全唐诗/poet.song.129000.json','["滿鏡新霜老可驚，十年烟隴廢春耕。", "黄絲黑黍有歸夢，白髮蒼顔無宦情。", "浮世不堪供把玩，安心隨處是修行。", "尚嫌未到無爲地，酷愛朝鐘暮磬聲。"]'),
('3f240947-ff3c-436f-9c91-a053273ba1b2','夜酌','陸游','宋','宋诗','song-poetry','','[]','遥夜澆愁賴麴生，燈前忽見臥長瓶。',64,'全唐诗/poet.song.129000.json','["遥夜澆愁賴麴生，燈前忽見臥長瓶。", "比紅有句狂猶在，染白無方老已成。", "園徑露螢粘濕草，塔簷風鐸亂疏更。", "悲秋要是騷人事，未必忘情勝有情。"]'),
('d9027342-14d4-464d-8c47-894dad4fc359','言懷','陸游','宋','宋诗','song-poetry','','[]','莫笑生涯似斷蓬，向来諸俠避豪雄。',64,'全唐诗/poet.song.129000.json','["莫笑生涯似斷蓬，向来諸俠避豪雄。", "報仇使氣風塵裏，吹竹彈絲錦繡中。", "樂事眼看成昨夢，倦遊心伏作衰翁。", "論交尚喜笻枝在，白鹿泉邊遡晚風。"]'),
('a82b35b0-32b3-44fa-bca9-00f62fd14a99','送客城西','陸游','宋','宋诗','song-poetry','','[]','倦客憑鞍半醉醒，秋光滿眼嘆頹齡。',64,'全唐诗/poet.song.129000.json','["倦客憑鞍半醉醒，秋光滿眼嘆頹齡。", "日斜野渡放船小，風急漁村攤網腥。", "客思不堪聞斷雁，詩情彊半在郵亭。", "歸来更恨城笳咽，烟火昏昏獨掩屏。"]'),
('d180c81c-2301-4b9e-9142-85de1bc7660f','雨夜','陸游','宋','宋诗','song-poetry','','[]','庭院蕭條秋意深，銅爐一炷海南沉。',32,'全唐诗/poet.song.129000.json','["庭院蕭條秋意深，銅爐一炷海南沉。", "幽人聽盡芭蕉雨，獨與青燈話此心。"]'),
('3b453f07-d704-4105-b373-492e71d6ff9f','病中作','陸游','宋','宋诗','song-poetry','','[]','浮世寄酣枕，勞生居漏船。',48,'全唐诗/poet.song.129000.json','["浮世寄酣枕，勞生居漏船。", "已悲身老大，更著病沈綿。", "親舊動千里，歡娱無百年。", "床頭周易在，端擬絕韋編。"]'),
('73bfe3f0-8105-4f69-8268-76d8e0fdb4f1','社日小飲','陸游','宋','宋诗','song-poetry','','[]','社日西風吹角巾，一尊彊醉汝江濱。',32,'全唐诗/poet.song.129000.json','["社日西風吹角巾，一尊彊醉汝江濱。", "杏梁燕子還堪恨，歸去匆匆不報人。"]'),
('e1f1ebce-68b7-41c0-9a40-243d2981eb2a','晚到東園','陸游','宋','宋诗','song-poetry','','[]','岸幘尋青士，憑軒待素娥。',48,'全唐诗/poet.song.129000.json','["岸幘尋青士，憑軒待素娥。", "官身苦日短，荒圃得秋多。", "醉眼輕浮世，羈懷激浩歌。", "功名從蹭蹬，詩酒且婆娑。"]'),
('f41fcc8b-f953-47e3-88f2-2eb6cdf34d2a','秋晚登擬峴望祥符觀','陸游','宋','宋诗','song-poetry','','[]','放翁局促留江干，愛此樓前烟水寛。',64,'全唐诗/poet.song.129000.json','["放翁局促留江干，愛此樓前烟水寛。", "雨昏回望殿突兀，秋晚剩覺山蒼寒。", "中原未復泪横臆，故里欲歸身屬官。", "雲外飛仙故不遠，喚渠小爲駐青鸞。"]'),
('c2217851-e60f-456a-a3d6-2a2e57826edf','秋思','陸游','宋','宋诗','song-poetry','','[]','黄落梧桐覆井床，莎根日夜泣寒螿。',64,'全唐诗/poet.song.129000.json','["黄落梧桐覆井床，莎根日夜泣寒螿。", "老生窺鏡鬢成雪，俊鶻掣韝天欲霜。", "破虜誰持白羽扇，從軍曾擁緑沈槍。", "壯心自笑何時豁，夢遶祁連古戰場。"]'),
('8f9ddfd0-1a58-4c0a-ada5-a9ebd94d5883','病目廢書終日危坐','陸游','宋','宋诗','song-poetry','','[]','肺渴常止酒，目昏復捐書。',72,'全唐诗/poet.song.129000.json','["肺渴常止酒，目昏復捐書。", "蒲團坐袖手，一窗寛有餘。", "心知世緣薄，分與鐘鼎疏。", "湛然千仞淵，養此徑寸珠。", "光明照憂患，何適不自娱。", "白雲可與友，晴空閑卷舒。"]'),
('0c9d9159-240b-455d-93e3-248788e9b705','感昔二首  其一','陸游','宋','宋诗','song-poetry','','[]','常記東園按舞時，春風一架晚薔薇。',32,'全唐诗/poet.song.129000.json','["常記東園按舞時，春風一架晚薔薇。", "尊前不展鴛鴦錦，只就殘紅作地衣。"]'),
('f33da51b-4c37-47c1-86c9-bcd3b6b63926','感昔二首  其二','陸游','宋','宋诗','song-poetry','','[]','八陣原頭縱獵歸，割鮮藉草酒淋漓。',32,'全唐诗/poet.song.129000.json','["八陣原頭縱獵歸，割鮮藉草酒淋漓。", "誰知此夕西窗裏，一盞青燈獨詠詩。"]'),
('94d6c008-f678-4d8c-a45e-d8e44f56de92','視陂至崇仁村落','陸游','宋','宋诗','song-poetry','','[]','津亭徙倚客衣單，秋盡江南亦已寒。',64,'全唐诗/poet.song.129000.json','["津亭徙倚客衣單，秋盡江南亦已寒。", "雁翅不禁疏雨濕，楓林初染早霞丹。", "少年已嘆儒冠誤，暮境更知行路難。", "倦馬歸来踏殘日，長吟聊得寫憂端。"]'),
('f4c72288-e838-48df-9ba6-6b248e83fe20','馬上','陸游','宋','宋诗','song-poetry','','[]','客遊多感慨，老病少歡欣。',48,'全唐诗/poet.song.129000.json','["客遊多感慨，老病少歡欣。", "去去穿村市，翻翻吹帽裙。", "天低落平野，雁遠入寒雲。", "漸覺江城近，秋笳馬上聞。"]'),
('efdc19b8-b80c-4a37-ba8e-af8f7827192d','寄周洪道參政二首  其一','陸游','宋','宋诗','song-poetry','','[]','半生蓬艇弄烟波，最愛三湘欸乃歌。',32,'全唐诗/poet.song.129000.json','["半生蓬艇弄烟波，最愛三湘欸乃歌。", "擬作此行公勿怪，胸中詩本漸無多。"]'),
('0bae1440-b549-4579-905b-232f52645eaa','寄周洪道參政二首  其二','陸游','宋','宋诗','song-poetry','','[]','菱舟烟雨久思歸，貪戀明時未拂衣。',32,'全唐诗/poet.song.129000.json','["菱舟烟雨久思歸，貪戀明時未拂衣。", "乞與一城敎睡足，猶能覓句寄黄扉。"]'),
('847f7b14-a09a-4cff-b868-b7ef3adad5d1','北窗','陸游','宋','宋诗','song-poetry','','[]','白首微官只自囚，青燈明滅北窗幽。',64,'全唐诗/poet.song.129000.json','["白首微官只自囚，青燈明滅北窗幽。", "五更風雨夢千里，半世江湖身百憂。", "壯志已孤金鎖甲，倦遊空攬黑貂裘。", "灞亭夜獵猶堪樂，敢恨將軍老不侯。"]'),
('6102a9f0-e601-4506-a51b-c07eee4535f1','登擬峴','陸游','宋','宋诗','song-poetry','','[]','翠阜圍平野，朱樓壓繚牆。',48,'全唐诗/poet.song.129000.json','["翠阜圍平野，朱樓壓繚牆。", "風回半汀雁，雲護一天霜。", "有地聊容拙，無方可療狂。", "白頭詩興在，吟罷意差彊。"]'),
('6afe119e-fe10-4de3-b3dd-270284be6768','休日','陸游','宋','宋诗','song-poetry','','[]','賜休暫許養衰殘，靜院翛然晝掩關。',64,'全唐诗/poet.song.129000.json','["賜休暫許養衰殘，靜院翛然晝掩關。", "釀酒移花調護悶，弄琴洗硯破除閑。", "與人多忤讒銷骨，報國無功愧滿顔。", "一寸歸心向誰說，小屏依約剡中山。"]'),
('9f3835f0-2b2e-426f-8428-e208c5376494','别張敎授歸獨登擬峴','陸游','宋','宋诗','song-poetry','','[]','小閣敞朱扉，停車暫息機。',48,'全唐诗/poet.song.129000.json','["小閣敞朱扉，停車暫息機。", "行人呼晚渡，幼婦浣秋衣。", "霜樹欹危堞，風鴉滿落暉。", "登臨客愁裏，況是送將歸。"]'),
('9808fac5-f5cf-4aa5-99f0-72d854675936','晚晴至索笑亭','陸游','宋','宋诗','song-poetry','','[]','中年苦肺熱，賸喜見新霜。',48,'全唐诗/poet.song.129000.json','["中年苦肺熱，賸喜見新霜。", "登覽江山美，經行草樹荒。", "堂空響棋子，盞小聚茶香。", "興盡扶藜去，斜陽滿畫廊。"]'),
('65992edc-a3cb-4335-a676-fab984c014bc','新釀熟小酌索笑亭','陸游','宋','宋诗','song-poetry','','[]','新酒黄如脫殻鵝，小園持盞暫婆娑。',64,'全唐诗/poet.song.129000.json','["新酒黄如脫殻鵝，小園持盞暫婆娑。", "文章不進技止此，仕宦忘歸人謂何。", "宿業簿書昏病眼，夢遊烟雨濕漁蓑。", "醉中笑向兒童說，白髮今年添幾多。"]'),
('cb685f64-c748-40f7-beab-5cba7d48c813','乾道初予自臨川歸鍾陵李德遠范周士送别于西津是日宿戰平風雨終夕今自臨川之高安復以雨中宿戰平悵然感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','故人已作山頭土，倦客猶鄣陌上塵。',32,'全唐诗/poet.song.129000.json','["故人已作山頭土，倦客猶鄣陌上塵。", "十五年間真一夢，又騎羸馬涉西津。"]'),
('5a18d2b7-ad66-4252-9943-46c366329208','乾道初予自臨川歸鍾陵李德遠范周士送别于西津是日宿戰平風雨終夕今自臨川之高安復以雨中宿戰平悵然感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','十五年前宿戰平，長亭風雨夜連明。',32,'全唐诗/poet.song.129000.json','["十五年前宿戰平，長亭風雨夜連明。", "無端老作天涯客，還聽當時夜雨聲。"]'),
('18d69a14-12c9-4967-a2b0-9ce038b77650','村舍小酌','陸游','宋','宋诗','song-poetry','','[]','野性安衡茅，傑屋愁躭躭。',120,'全唐诗/poet.song.129000.json','["野性安衡茅，傑屋愁躭躭。", "上不補縣官，下有肉食慚。", "雖非策雲驥，實鄙作繭蠶。", "失計不容悔，漁蓑換朱藍。", "少壯尚可力，老大真難堪。", "今朝意頗豁，村舍寄半酣。", "玉版烹雪筍，金苞擘霜柑。", "豈惟寫我憂，亦以稅我驂。", "弄筆作一笑，何用與客談。", "逡巡上車去，濕翠浮烟嵐。"]'),
('43dd7304-daed-4d97-a2bd-689af863364f','白塔道中乘臥輿行','陸游','宋','宋诗','song-poetry','','[]','小疾載臥輿，獨飲亦薄醉。',72,'全唐诗/poet.song.129000.json','["小疾載臥輿，獨飲亦薄醉。", "朝離戰平館，午過白塔市。", "清寒正宜懶，揺兀更益睡。", "所嗟下程早，不得究此味。", "忽憶從軍時，雪夜馳鐵騎。", "壯心誰復識，撫事有餘愧。"]'),
('6e9cf2a7-2ef2-4d2e-93b8-211477db1d7e','宿城頭鋪小飲而睡','陸游','宋','宋诗','song-poetry','','[]','亭傳臨江滸，床敷息我勞。',48,'全唐诗/poet.song.129000.json','["亭傳臨江滸，床敷息我勞。", "屋茅殘月冷，庭樹北風鏖。", "墟市饒新兔，村場有濁醪。", "氣衰仍病著，小飲不能豪。"]'),
('73d042f8-6b1b-43e0-913c-21548912305f','豐城村落小憩','陸游','宋','宋诗','song-poetry','','[]','霜信催寒力尚微，郵亭繫馬旋添衣。',64,'全唐诗/poet.song.129000.json','["霜信催寒力尚微，郵亭繫馬旋添衣。", "平郊極目冬耕遍，小婦篸花晚餉歸。", "孤宦毎隨征雁遠，故人已似曉星稀。", "上書自劾真須猛，菰正堪炊蟹正肥。"]'),
('1da23bcd-f416-4236-8fb4-72acf10e5c6a','再題','陸游','宋','宋诗','song-poetry','','[]','柴門數頃秋，半日爲遲留。',48,'全唐诗/poet.song.129000.json','["柴門數頃秋，半日爲遲留。", "老驥厭伏櫪，饑鷹思下韝。", "野橋危欲斷，山雨落還收。", "何許丹青手，端能寫此愁。"]'),
('d719171c-d604-4fc6-baac-9b3ab8614816','發豐城縣','陸游','宋','宋诗','song-poetry','','[]','豐城古縣已再遷，出郭十步江渺然。',64,'全唐诗/poet.song.129000.json','["豐城古縣已再遷，出郭十步江渺然。", "冷雲四合欲下雪，柔櫓數聲初放船。", "孤村燈火照破驛，客子何以娱今夕。", "不辭金盌醉十分，要看玉花深一尺。"]'),
('53910824-a37f-4995-bf74-32ad84039b3c','豐城高安之間憩民家景趣幽邃爲之慨然懷歸','陸游','宋','宋诗','song-poetry','','[]','數家聚雲根，細路入叢薄。',96,'全唐诗/poet.song.129000.json','["數家聚雲根，細路入叢薄。", "濺濺石渠水，来往一略彴。", "有無鄰里通，笑語婦子樂。", "濁醪時相就，青蔬缺鹽酪。", "日暮歸閉門，績火星煜爚。", "先期畢租稅，老不入城郭。", "嗟予獨何事，早插紅塵脚。", "故山未成歸，悵望有餘怍。"]'),
('560381df-60e5-4b38-a0ea-dc0490a539b2','宿華嚴寺','陸游','宋','宋诗','song-poetry','','[]','夜宿華嚴寺，人扶到上方。',48,'全唐诗/poet.song.129000.json','["夜宿華嚴寺，人扶到上方。", "喚僧同看畫，避佛旋移床。", "小雨不成雪，烈風還作霜。", "鐘殘燈漸暗，趺坐黙焚香。"]'),
('0a6ca550-f6c2-40c3-a594-74ac5374fa8d','寄奉新高令','陸游','宋','宋诗','song-poetry','','[]','小雨催寒著客袍，草行露宿敢辭勞。',64,'全唐诗/poet.song.129000.json','["小雨催寒著客袍，草行露宿敢辭勞。", "歲饑民食糟糠窄，吏惰官倉鼠雀豪。", "只要閭閻寛箠楚，不須亭障肅弓刀。", "九重屢下丁寧詔，此責吾曹未易逃。"]'),
('569e9056-3421-4b81-a31c-6c1d1f812cbf','高安州宅三詠 丹井','陸游','宋','宋诗','song-poetry','','[]','丹成人已仙，遺竈亦已平。',48,'全唐诗/poet.song.129000.json','["丹成人已仙，遺竈亦已平。", "尚餘松根井，鏘然環玦聲。", "我来試一啜，槁面還童嬰。", "祝君勿關鑰，人人遣長生。"]'),
('2df7d78c-58e1-494a-b97b-9ae8c18bfd32','高安州宅三詠 劍池','陸游','宋','宋诗','song-poetry','','[]','我壯喜學劍，十年客峨岷。',48,'全唐诗/poet.song.129000.json','["我壯喜學劍，十年客峨岷。", "毫髮恐未盡，屠釣求隱淪。", "今年獨何幸，見此度世人。", "夜深来較術，雷雨戰江津。"]'),
('7fa58846-d61e-4197-a76b-66ee418d4bc3','高安州宅三詠 偃松','陸游','宋','宋诗','song-poetry','','[]','巨松偃青蓋，閱世巋獨存。',48,'全唐诗/poet.song.129000.json','["巨松偃青蓋，閱世巋獨存。", "頗疑古仙翁，藏丹在其根。", "或是結靈藥，百尺有伏黿。", "終隨風雨化，不死何足言。"]'),
('a2d6544c-793a-4882-af45-4434623506f7','與高安劉丞遊大愚觀壁間兩蘇先生詩','陸游','宋','宋诗','song-poetry','','[]','野性縱壑魚，官身墮穽虎。',100,'全唐诗/poet.song.129000.json','["野性縱壑魚，官身墮穽虎。", "適得建溪春，頗憶松下{父/鬲}。", "微霜初變寒，短景已過午。", "佳客能聨翩，老宿相勞苦。", "懷哉兩蘇公，去日不可數。", "泉扃一埋玉，世事幾炊黍。", "吾儕生苦晚，佇立久惻楚。", "尚想来遊時，黄鍾賡大呂。"]'),
('268fef30-d5ba-48d2-924f-2a2fa19f11dd','宿黄僊觀兵火焚蕩之餘惟一殿突兀猶在黄僊蓋與許旌陽同時飛昇者','陸游','宋','宋诗','song-poetry','','[]','拔宅翛然上碧虛，神僊豈亦愛吾廬。',64,'全唐诗/poet.song.129000.json','["拔宅翛然上碧虛，神僊豈亦愛吾廬。", "重門不改雲山色，古殿猶存劫火餘。", "翠木蕭森高蔽日，黄冠貧窶自畦蔬。", "殘年安得長来此，一椀松肪讀隱書。"]'),
('ce17a520-8ae6-4e33-9ea5-754feeac223e','玉隆得丹芝','陸游','宋','宋诗','song-poetry','','[]','何用金丹九轉成，手持芝草已身輕。',32,'全唐诗/poet.song.129000.json','["何用金丹九轉成，手持芝草已身輕。", "祥雲平地擁笙鶴，便自西山朝玉京。"]'),
('3c62c617-8518-4996-bda9-9b70b297dd85','贈西山老人','陸游','宋','宋诗','song-poetry','','[]','生世不把筆，殘年惟灌園。',48,'全唐诗/poet.song.129000.json','["生世不把筆，殘年惟灌園。", "賃舂来竝舍，賣畫到前村。", "勤苦供租稅，清貧遺子孫。", "從来棲遁志，剩欲與翁言。"]'),
('c2ec0a23-3544-4909-8e16-b038fec785a3','病酒宿土坊驛','陸游','宋','宋诗','song-poetry','','[]','少時見酒喜欲舞，老大畏酒如畏虎。',64,'全唐诗/poet.song.129000.json','["少時見酒喜欲舞，老大畏酒如畏虎。", "一日飲酒三日病，客路那堪夜聞雨。", "雨聲蕭蕭宿空堂，不寐始知更漏長。", "賣藥思從伯休隱，愛花却笑拾遺狂。"]'),
('8f21bda5-90bb-4280-a69b-10246e58c64d','十一月上七日蔬飯騾嶺小店','陸游','宋','宋诗','song-poetry','','[]','新秔炊飯白勝玉，枯松作薪香出屋。',96,'全唐诗/poet.song.129000.json','["新秔炊飯白勝玉，枯松作薪香出屋。", "冰蔬雪菌競登槃，瓦鉢氊巾俱不俗。", "曉途微雨壓征塵，午店清泉带修竹。", "建谿小春初出碾，一碗細乳浮銀粟。", "老来畏酒厭芻豢，却喜今朝食無肉。", "尚嫌車馬苦縻人，會入青雲騎白鹿。"]'),
('c87f5346-b69b-4042-90dc-7ca0ede0bdfb','進賢驛感懷','陸游','宋','宋诗','song-poetry','','[]','環走幾千里，馳歸亦再旬。',48,'全唐诗/poet.song.129000.json','["環走幾千里，馳歸亦再旬。", "征途饒感慨，訟牒費精神。", "風雪常欺客，文章本誤身。", "小詩無傑思，猶得當吟呻。"]'),
('b2fb87bf-729f-47c2-adeb-d3955ec14dc2','入臨川境馬上作','陸游','宋','宋诗','song-poetry','','[]','投老縻身簿領間，却因馬上得偷閑。',64,'全唐诗/poet.song.129000.json','["投老縻身簿領間，却因馬上得偷閑。", "兼旬敢恨常爲客，一飯何曾不對山。", "銅鏡無情欺白髮，霜風有力散酡顔。", "今宵要看浮橋月，儘放征騑晚入關。"]'),
('37d75429-0a9f-4f0c-af16-a92d7aee1d1c','别楊秀才','陸游','宋','宋诗','song-poetry','','[]','歲暮江頭又語離，淡烟衰草不勝悲。',64,'全唐诗/poet.song.129000.json','["歲暮江頭又語離，淡烟衰草不勝悲。", "俗人憒憒寧知子，心事悠悠欲語誰。", "燈暗想傾澆悶酒，路長應和贈行詩。", "人生但要身彊健，一笑相從自有時。"]'),
('6f9ce9a0-3a2c-426a-adfe-b2ac7b8acd42','發臨川','陸游','宋','宋诗','song-poetry','','[]','見客道傍店，添衣江上村。',48,'全唐诗/poet.song.129000.json','["見客道傍店，添衣江上村。", "陂長風浩浩，山遠霧昏昏。", "虛日人聲合，凶年菜色繁。", "扶衰歸北闕，何以報君恩。"]'),
('7c65cd81-e694-4b9d-a0d6-7a44de8f484a','早行','陸游','宋','宋诗','song-poetry','','[]','江路迢迢馬首東，臨川一夢又成空。',64,'全唐诗/poet.song.129000.json','["江路迢迢馬首東，臨川一夢又成空。", "日高未泫晨霜白，風勁先消卯酒紅。", "山市人經饑饉後，孤生身老道途中。", "著身穩處君知否，射的峰前臥釣篷。"]'),
('c08fb698-3664-4d95-b491-3aecabb3fa7d','白干鋪别傅用之主簿','陸游','宋','宋诗','song-poetry','','[]','我行忽百里，送客亦已空。',120,'全唐诗/poet.song.129000.json','["我行忽百里，送客亦已空。", "傅子獨眷眷，旦暮隨此翁。", "謝之不肯去，瘦馬衝北風。", "泥濺及馬臆，霜飛逼裘茸。", "茅店得小語，慨然念年凶。", "不作兒女悲，道義相磨礲。", "我歸亦何爲，魚鳥愁池籠。", "君乃臺閣人，鸞鳳儀笙鏞。", "若耶遶青山，天祿摩蒼穹。", "此别各努力，出處何必同。"]'),
('8b6a04cc-81fc-4035-b58b-0ad87e69dff4','過茱茰鋪青松朱戸前臨大道絕似西陲亭驛悵然有作','陸游','宋','宋诗','song-poetry','','[]','茱茰小驛夕陽愁，搔首臨風感舊遊。',32,'全唐诗/poet.song.129000.json','["茱茰小驛夕陽愁，搔首臨風感舊遊。", "渾似軍行散關路，但無鼓吹動涼州。"]'),
('a64d7349-89fd-4479-9b49-ffb5b0bfc9ff','青溪道中行古松間因少留瀹茶而行','陸游','宋','宋诗','song-poetry','','[]','露濕青松細細香，旋呼拄杖踏斜陽。',64,'全唐诗/poet.song.129000.json','["露濕青松細細香，旋呼拄杖踏斜陽。", "三生舊發遊山願，一卷新傳辟穀方。", "雲外未論笙鶴近，塵中實厭簿書忙。", "拾樵汲磵俱清絕，聊爲煎茶一據床。"]'),
('a127a531-1c62-4652-9b37-8f27b97e0040','弋陽縣江上書觸目','陸游','宋','宋诗','song-poetry','','[]','縣前奇哉一江水，日暮風吹碧鱗起。',64,'全唐诗/poet.song.129000.json','["縣前奇哉一江水，日暮風吹碧鱗起。", "客恨征塵忽如洗，不用金篦刮眸子。", "丹楓岸邊雪色蘆，下有老翁方捕魚。", "欲求妙思貌畫圖，王維鄭虔今世無。"]'),
('1a7401cc-502f-4591-a6d4-4323981e3711','乾封驛早行','陸游','宋','宋诗','song-poetry','','[]','己巳被驛書，乙亥戒徂兩。',96,'全唐诗/poet.song.129000.json','["己巳被驛書，乙亥戒徂兩。", "扶衰犯霜露，疲憊不可狀。", "夜行星滿天，晨起雞初唱。", "槁枝燒代燭，凍菜擷供餉。", "三年走萬里，天幸苟亡恙。", "深知賦材薄，自笑得名妄。", "宣温望玉座，何以待諮訪。", "春江色如藍，歸舟行可榜。"]'),
('c136cf38-8ab2-4b87-b417-df8a42685790','過江山縣浮橋有感','陸游','宋','宋诗','song-poetry','','[]','堪笑行人日日忙，又扶衰病過浮梁。',64,'全唐诗/poet.song.129000.json','["堪笑行人日日忙，又扶衰病過浮梁。", "灘流急處水禽下，桑葉空時村酒香。", "枯枿敢懷貪雨露，饑鴻自憫犯風霜。", "宦途商略無安處，早晚歸耕剡曲旁。"]'),
('9aab3ebb-2497-44f3-9edb-aa5f2ed9393d','衢州早行書懷','陸游','宋','宋诗','song-poetry','','[]','鄰雞已三號，殘燭無一寸。',96,'全唐诗/poet.song.129000.json','["鄰雞已三號，殘燭無一寸。", "參差發行槖，迢逓望前頓。", "滿靴霜若雪，破面風抵刃。", "敢辭行路難，漸喜京邑近。", "少年奉朝請，親見堯授舜。", "飄然如脫葉，蹭蹬垂七閏。", "風埃暗征袍，歲月集衰鬢。", "餘生迫歸休，周行愧英俊。"]'),
('19b1512b-0a0a-49bd-9ef9-a9f946e92d54','杭頭晚興二首  其一','陸游','宋','宋诗','song-poetry','','[]','山色蒼寒野色昏，下程初閉驛亭門。',32,'全唐诗/poet.song.129000.json','["山色蒼寒野色昏，下程初閉驛亭門。", "不須更把澆愁酒，行盡天涯慣斷魂。"]'),
('32e5f2b0-1a81-42d9-a7f4-869a3bdf0eec','杭頭晚興二首  其二','陸游','宋','宋诗','song-poetry','','[]','落葉孤村晚下程，癡雲殘日半陰晴。',32,'全唐诗/poet.song.129000.json','["落葉孤村晚下程，癡雲殘日半陰晴。", "篝爐火暖床敷穏，臥聽黄鴉穀穀聲。"]'),
('af331b18-86d2-40da-b6f9-10167b210a83','行至嚴州壽昌縣界得請許免入奏仍除外官感恩述懷','陸游','宋','宋诗','song-poetry','','[]','曉傳尺一到江村，拜起朝衣漬泪痕。',64,'全唐诗/poet.song.129000.json','["曉傳尺一到江村，拜起朝衣漬泪痕。", "敢恨帝城如日遠，喜聞天語似春温。", "翰林惟奉還山詔，湘水空招去國魂。", "聖主恩深何力報，時從天末望修門。"]'),
('0c84193d-0ed3-4b86-9837-25e124158d37','桐廬縣泛舟東歸','陸游','宋','宋诗','song-poetry','','[]','桐江艇子去乘月，笠澤老翁歸放慵。',64,'全唐诗/poet.song.129000.json','["桐江艇子去乘月，笠澤老翁歸放慵。", "一尺輪囷霜蟹美，十分瀲灧社醅濃。", "宦遊何啻路九折，歸臥恨無山萬重。", "醉裏試吹蒼玉笛，爲君中夜舞魚龍。"]'),
('92d8930f-4893-49df-8102-13d36629f73d','予欲自嚴買船下七里灘謁嚴光祠而歸會灘淺陸行至桐廬始能泛江因得絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','客星祠下渺烟波，欠我扁舟舞短蓑。',32,'全唐诗/poet.song.129000.json','["客星祠下渺烟波，欠我扁舟舞短蓑。", "不爲窮冬怕灘惡，正愁此老笑人多。"]'),
('0201bb78-9c16-4c86-9fd7-207f14d6c258','予欲自嚴買船下七里灘謁嚴光祠而歸會灘淺陸行至桐廬始能泛江因得絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','桐廬縣前櫓聲急，蒼烟茫茫白鳥雙。',32,'全唐诗/poet.song.129000.json','["桐廬縣前櫓聲急，蒼烟茫茫白鳥雙。", "亂山日落潮未落，勝絕不减吴松江。"]'),
('08e955b3-0158-4aec-8d1a-9fb0fca89630','漁浦二首  其一','陸游','宋','宋诗','song-poetry','','[]','桐廬處處是新詩，漁浦江山天下稀。',32,'全唐诗/poet.song.129000.json','["桐廬處處是新詩，漁浦江山天下稀。", "安得移家常住此，隨潮入縣伴潮歸。"]'),
('52a02056-42d9-4022-93b8-7c1ba5923159','漁浦二首  其二','陸游','宋','宋诗','song-poetry','','[]','漁翁持魚叩舷賣，炯炯緑瞳雙臉丹。',32,'全唐诗/poet.song.129000.json','["漁翁持魚叩舷賣，炯炯緑瞳雙臉丹。", "我欲從之逝已遠，菱歌一曲暮江寒。"]'),
('f3cec825-3420-46c8-999c-6e6fbbd3b09c','蕭山','陸游','宋','宋诗','song-poetry','','[]','素衣已免染京塵，一笑江邊整幅巾。',64,'全唐诗/poet.song.129000.json','["素衣已免染京塵，一笑江邊整幅巾。", "入港緑潮深蘸岸，披雲白塔遠招人。", "功名姑付未来劫，詩酒何孤見在身。", "會向桐江謀小築，浮家從此往来頻。"]'),
('1c609994-a8a4-4186-90b1-8dcd6430a14c','辛丑正月三日雪','陸游','宋','宋诗','song-poetry','','[]','開歲尚殘冬，佳哉雪意濃。',72,'全唐诗/poet.song.129000.json','["開歲尚殘冬，佳哉雪意濃。", "潤歸千里麥，聲亂五更鐘。", "簾隙收初密，牆隅積已重。", "龍團笑羔酒，狐腋襲駝茸。", "危檻臨欹竹，幽窗聽墮松。", "忽思西戌日，憑堞待傳烽。"]'),
('11e39a76-09c1-4b30-869a-262d8a32fcec','正月二十八日大雪過若耶溪至雲門山中','陸游','宋','宋诗','song-poetry','','[]','山中看雪醉騎驢，清賞真成十載無。',64,'全唐诗/poet.song.129000.json','["山中看雪醉騎驢，清賞真成十載無。", "高壓孤峰增峭絕，斜傾叢竹失枝梧。", "松肪火暖眠僧榻，芋糝羮香擁地爐。", "病骨雖癯猶健在，未應遽作臥遊圖。"]'),
('9098d3ae-c00f-4382-9d4b-f3f663e6cfc8','雪中登雲泉上方','陸游','宋','宋诗','song-poetry','','[]','滃滃雲堆上，茫茫雪海中。',48,'全唐诗/poet.song.129000.json','["滃滃雲堆上，茫茫雪海中。", "煎茶誇坐客，打竹課蠻童。", "冰谷鳴饑鶴，烟汀立斷鴻。", "歸来更堪喜，葑火滿爐紅。"]'),
('39ff19a0-7f97-44a9-8035-3d0943029014','衝雪至餘慶覺林雪連日不止','陸游','宋','宋诗','song-poetry','','[]','策蹇清吟涉若耶，灞橋猶恨近京華。',64,'全唐诗/poet.song.129000.json','["策蹇清吟涉若耶，灞橋猶恨近京華。", "山前千頃誰種玉，座上六時天散花。", "林雀無聲溪彴斷，炊烟不動竹籬斜。", "勝遊更覺平生少，未羨銀河泛客槎。"]'),
('a6f050b2-4694-4d1b-be5f-57ba564b02e7','大雪歌','陸游','宋','宋诗','song-poetry','','[]','若耶溪頭朝暮雪，鴉鵲墮死長松折。',128,'全唐诗/poet.song.129000.json','["若耶溪頭朝暮雪，鴉鵲墮死長松折。", "横飛忽已平屐齒，亂點似欲粧簾纈。", "放翁憑閣喜欲顛，摩挲拄杖向渠說。", "莫辭從我上嵯峨，此景與子同清絕。", "銀杯拌蜜非老事，石鼎煎茶且時啜。", "題詩但覺退筆鋒，把酒未易生耳熱。", "扶衰忍冷君勿笑，報國寸心堅似鐵。", "漁陽上谷要一行，馬蹄蹴踏河冰裂。"]'),
('67e75edd-48b6-45fd-89e6-3be4636fc956','雪霽歸湖上過千秋觀少留','陸游','宋','宋诗','song-poetry','','[]','縱轡不嫌遠，逢山猶一登。',48,'全唐诗/poet.song.129000.json','["縱轡不嫌遠，逢山猶一登。", "夕陽陂渺渺，殘雪塔層層。", "折竹横遮道，饑烏下啄冰。", "欲歸還小駐，倚杖對崚嶒。"]'),
('5bb325ed-78ff-401e-9c96-0c758e7af52d','二月四日作','陸游','宋','宋诗','song-poetry','','[]','早春風力已輕柔，瓦雪消殘玉半溝。',32,'全唐诗/poet.song.129000.json','["早春風力已輕柔，瓦雪消殘玉半溝。", "飛蝶鳴鳩俱得意，東風應笑我閑愁。"]'),
('05b63df6-4c36-4dd3-962b-7feae781cf34','新築山亭戲作','陸游','宋','宋诗','song-poetry','','[]','危檻凌風出半空，怪奇造化欲無功。',64,'全唐诗/poet.song.129000.json','["危檻凌風出半空，怪奇造化欲無功。", "天垂繚白縈青外，人在紛紅駭綠中。", "日月匆匆雙轉轂，古今杳杳一飛鴻。", "酒酣獨臥林間石，未許塵寰識此翁。"]'),
('ec5ff704-7aae-48c3-a81e-f4ba66ed0c56','春晴出遊','陸游','宋','宋诗','song-poetry','','[]','一春彊半病，頗廢山澤遊。',72,'全唐诗/poet.song.129000.json','["一春彊半病，頗廢山澤遊。", "今晨忽良已，風日亦清柔。", "朝飡具冷餅，瘦骨辭重裘。", "稺荷出溝港，芳杜滿汀洲。", "勿言酒苦薄，一笑失百憂。", "且當詠尋壑，詎必賦登樓。"]'),
('2edd2b8a-47e3-4623-83b4-46c934839f5d','題山家壁','陸游','宋','宋诗','song-poetry','','[]','山中無傳漏，猿鳴知既夕。',72,'全唐诗/poet.song.129000.json','["山中無傳漏，猿鳴知既夕。", "芳藤上幽援，素月照高壁。", "主人殊喜事，歡若有夙昔。", "稚子檠竹槃，炊黍持餉客。", "卜鄰雖未辨，清嘯聊自適。", "衰病久廢詩，筆端嘆荆棘。"]'),
('87fa2274-0cd4-4e79-b65d-b93f2e0ecb45','春晚風雨中作','陸游','宋','宋诗','song-poetry','','[]','箕踞藜床岸幅巾，何妨病酒住湖濱。',64,'全唐诗/poet.song.129000.json','["箕踞藜床岸幅巾，何妨病酒住湖濱。", "駕風浪作連三日，掃地花空又一春。", "樂事清宵當秉燭，畏途平地有摧輪。", "頽然耐辱君無怪，元是人間澹蕩人。"]'),
('d213b7fb-1cd2-4394-8912-b30595acf60e','北窗','陸游','宋','宋诗','song-poetry','','[]','九陌黄塵早暮忙，幽人自愛北窗涼。',64,'全唐诗/poet.song.129000.json','["九陌黄塵早暮忙，幽人自愛北窗涼。", "清吟微變舊詩律，細字閑抄新酒方。", "草木扶疏春已去，琴書蕭散日初長。", "破羌臨罷榰頤久，又破銅匜半篆香。"]'),
('e70cff93-b3af-4c35-b1cb-d409e21c9a93','山中晚興','陸游','宋','宋诗','song-poetry','','[]','薄酒亦陶然，偃蹇澗石側。',48,'全唐诗/poet.song.129000.json','["薄酒亦陶然，偃蹇澗石側。", "巾墮拄杖横，意象頗自得。", "青山受落日，忽作玻瓈色。", "躊躇不忍去，下磴天已黑。"]'),
('3ce375f3-b43c-4c23-98f1-71e692edf6fd','夜登山亭','陸游','宋','宋诗','song-poetry','','[]','飛觀崢嶸天宇寛，幽人半醉凭闌干。',64,'全唐诗/poet.song.129000.json','["飛觀崢嶸天宇寛，幽人半醉凭闌干。", "三山渺渺鸞鶴遠，七澤茫茫蓑笠寒。", "清吹拂林横玉笛，紫雲覆鼎熟金丹。", "童顔緑鬢無人識，回首塵寰一夢殘。"]'),
('392a8fcd-e15c-4d67-b31a-8f7c81b37183','西村醉歸','陸游','宋','宋诗','song-poetry','','[]','俠氣崢嶸蓋九州，一生常恥爲身謀。',64,'全唐诗/poet.song.129000.json','["俠氣崢嶸蓋九州，一生常恥爲身謀。", "酒寧剩欠尋常債，劍不虛施細碎讎。", "岐路凋零白羽箭，風霜破弊黑貂裘。", "陽狂自是英豪事，村市歸来醉跨牛。"]'),
('f344e7ca-0876-4821-847b-a7fa1f201509','自詠','陸游','宋','宋诗','song-poetry','','[]','三十年前接俊遊，即今身世寄滄洲。',64,'全唐诗/poet.song.129000.json','["三十年前接俊遊，即今身世寄滄洲。", "俚聲不辦諧韶頀，暮氣寧能徹斗牛。", "緑酒可人消永日，黄鸝多事管閑愁。", "吹笙跨鶴何時去，剩欲平章太華秋。"]'),
('c2ab5950-24c8-4dc2-8b3a-b5ad2791dac3','閑中頗有四方之志偶得長句','陸游','宋','宋诗','song-poetry','','[]','世論紛紛枉見仇，吾身自計本悠悠。',64,'全唐诗/poet.song.129000.json','["世論紛紛枉見仇，吾身自計本悠悠。", "讀書漸懶惟思睡，壓酒初成不怕愁。", "蜀棧冷雲侵瘦馬，楚江籠月繫孤舟。", "興来會作飄然去，更續騷人賦遠遊。"]'),
('ee8123eb-fac5-44c2-b57e-b1835003cf53','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','緑髮凋零白髮多，山林未死且婆娑。',64,'全唐诗/poet.song.129000.json','["緑髮凋零白髮多，山林未死且婆娑。", "無端忤俗坐狂耳，甚欲讀書如懶何。", "雨過亂蓑堆野艇，月明長笛和菱歌。", "此中得意君須領，莫愛車前印幾窠。"]'),
('30deb572-dfd7-4c17-bbe3-b569e066578f','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','遠簷新葉著啼鶯，睡起東窗一榻横。',64,'全唐诗/poet.song.129000.json','["遠簷新葉著啼鶯，睡起東窗一榻横。", "愁衮衮来疑有約，春堂堂去恨無情。", "鶻飛局上新棋勢，龍吼床頭古劍聲。", "莫嘆柴荆無客到，緑尊還對莫山傾。"]'),
('eb6af4ed-28ab-4e28-b515-7d1b2eafcffb','醉題','陸游','宋','宋诗','song-poetry','','[]','坎止流行五十秋，胸中不解著閑愁。',64,'全唐诗/poet.song.129000.json','["坎止流行五十秋，胸中不解著閑愁。", "浩歌野渡驚雲起，狂舞空庭挽月留。", "性本自然憎截鶴，器非大受愧函牛。", "平生最愛嚴灘路，早晚貂裘換釣舟。"]'),
('f1c8436f-03eb-4efd-bff0-fc64c0874793','小園四首  其一','陸游','宋','宋诗','song-poetry','','[]','小園烟草接鄰家，桑柘陰陰一徑斜。',32,'全唐诗/poet.song.129000.json','["小園烟草接鄰家，桑柘陰陰一徑斜。", "臥讀陶詩未終卷，又乘微雨去鋤瓜。"]'),
('3e28f271-32e5-450b-9a79-55c4afc68852','小園四首  其二','陸游','宋','宋诗','song-poetry','','[]','歴盡危機歇盡狂，殘年惟有付耕桑。',32,'全唐诗/poet.song.129000.json','["歴盡危機歇盡狂，殘年惟有付耕桑。", "麥秋天氣朝朝變，蠶月人家處處忙。"]'),
('fc931e96-878e-4a86-b50c-827cd8988db8','小園四首  其三','陸游','宋','宋诗','song-poetry','','[]','村南村北鵓鴣聲，水刺新秧漫漫平。',32,'全唐诗/poet.song.129000.json','["村南村北鵓鴣聲，水刺新秧漫漫平。", "行遍天涯千萬里，却從鄰父學春耕。"]'),
('25595b25-3a66-4333-a5f9-da9ba4968f7c','小園四首  其四','陸游','宋','宋诗','song-poetry','','[]','少年壯氣吞殘虜，晚覺丘樊樂事多。',32,'全唐诗/poet.song.129000.json','["少年壯氣吞殘虜，晚覺丘樊樂事多。", "駿馬寶刀俱一夢，夕陽閑和飯牛歌。"]'),
('50f1879c-bc05-4e74-80a8-54bc1cd9e059','步虛四首  其一','陸游','宋','宋诗','song-poetry','','[]','微風吹碧海，細細生龍鱗。',80,'全唐诗/poet.song.129000.json','["微風吹碧海，細細生龍鱗。", "半醉騎一鶴，去謁青華君。", "歸来天風急，吹我過緱山。", "鏘然哦詩聲，清曉落人間。", "人間仰視空浩浩，遠孫白髮塵中老。", "初見姬翁禮樂新，千九百年如電掃。"]'),
('c42f7756-fa90-49b3-8816-1e2e0ca65c68','步虛四首  其二','陸游','宋','宋诗','song-poetry','','[]','瀛海日月淵，蓬壺仙聖宅。',80,'全唐诗/poet.song.129000.json','["瀛海日月淵，蓬壺仙聖宅。", "駕鶴一時遊，海面日夜窄。", "人生蜉蝣耳，一鬨瓦甕中。", "天地廣如許，誰能發其蒙。", "丹書千卷藏一塵，子能求之勿從人。", "晴窗趺坐春滿腹，崑崙待得丹芝熟。"]'),
('59773081-be3b-4895-ad85-142463f11b0f','步虛四首  其三','陸游','宋','宋诗','song-poetry','','[]','曩者過洛陽，宮闕侵雲起。',80,'全唐诗/poet.song.129000.json','["曩者過洛陽，宮闕侵雲起。", "今者過洛陽，蕭然但荒壘。", "銅駝臥深棘，使我惻愴多。", "可憐陌上人，亦復笑且歌。", "世事茫茫幾成壞，萬人看花身獨在。", "北邙秋風吹野蒿，古冢漸平新冢高。"]'),
('d438fa70-8035-4eda-8941-944e113235e2','步虛四首  其四','陸游','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','一瓢小如繭，芳醪溢其中。',80,'全唐诗/poet.song.129000.json','["一瓢小如繭，芳醪溢其中。", "醉此一市人，吾瓢故無窮。", "不言術神奇，要是心廣大。", "觴豆有德色，笑子乃爾隘。", "岳陽樓中横笛聲，分明爲子說長生。", "金丹養成不自服，度盡世人朝玉京。"]'),
('f79399cd-a988-4717-9630-317751ca03ca','醉中登避俗臺','陸游','宋','宋诗','song-poetry','','[]','半醉行歌上古臺，脫巾散髮謝氛埃。',64,'全唐诗/poet.song.129000.json','["半醉行歌上古臺，脫巾散髮謝氛埃。", "但知禮豈爲我設，莫管客從何處来。", "剡曲烟波菱蔓滑，耶溪風露藕花開。", "老来世事渾成懶，一櫂幽尋未擬回。"]'),
('8e56d3cb-26ac-485a-9e78-b173f6277c78','立秋前三日夜坐庭中偶賦','陸游','宋','宋诗','song-poetry','','[]','絳闕清都侍宴還，天風揺珮夜珊珊。',64,'全唐诗/poet.song.129000.json','["絳闕清都侍宴還，天風揺珮夜珊珊。", "月輪桂滿蟾初冷，星渚橋空鵲尚閑。", "一鶴每臨雲雨上，幾人虛老市朝間。", "試將綠髮窺清鏡，未愧僊姝玉鍊顔。"]'),
('fe33e047-f42b-42ab-bfa5-7e3c13cc3d4d','南堂臥觀月','陸游','宋','宋诗','song-poetry','','[]','河漢横斜星宿稀，臥看涼月入窗扉。',32,'全唐诗/poet.song.129000.json','["河漢横斜星宿稀，臥看涼月入窗扉。", "恍如北戍梁州日，睡覺清霜滿鐵衣。"]'),
('fc2e99d2-b638-42ee-ae7f-4c4abf1dd86c','夜坐獨酌','陸游','宋','宋诗','song-poetry','','[]','玉宇沉沉夜向闌，跨空飛閣倚高寒。',32,'全唐诗/poet.song.129000.json','["玉宇沉沉夜向闌，跨空飛閣倚高寒。", "一壺清露来雲表，聊爲幽人洗肺肝。"]'),
('e1957c6b-4067-4a7d-bf67-0c2522c108dc','夜興','陸游','宋','宋诗','song-poetry','','[]','鶴瘦龜饑與靜宜，更闌徙倚竝清池。',64,'全唐诗/poet.song.129000.json','["鶴瘦龜饑與靜宜，更闌徙倚竝清池。", "月當三五初盈夜，河直西南欲落時。", "浩浩醉歌群鶩起，翩翩孤影角巾欹。", "飛僊授我青瑶簡，索賦山中夜興詩。"]'),
('f2da28d6-ce49-4b77-8b07-1048b54ff5b3','月夜泛小舟湖中三更乃歸','陸游','宋','宋诗','song-poetry','','[]','落日愁思把釣鈎，南鄰借得采菱舟。',64,'全唐诗/poet.song.129000.json','["落日愁思把釣鈎，南鄰借得采菱舟。", "湖心月上明如晝，樹杪風生冷逼秋。", "壯歲功名慚汗馬，暮年心事許沙鷗。", "桐江一葉真奇策，莫爲兒曹作滯留。"]'),
('4933e031-4d30-4717-b78c-bc7b6b5b2c70','無題二首  其一','陸游','宋','宋诗','song-poetry','','[]','半醉凌風過月旁，水精宮殿桂花香。',32,'全唐诗/poet.song.129000.json','["半醉凌風過月旁，水精宮殿桂花香。", "素娥定赴瑶池宴，侍女皆騎白鳳凰。"]'),
('71a4c678-b318-4e08-9250-c9d3f351ee31','無題二首  其二','陸游','宋','宋诗','song-poetry','','[]','出繭修眉淡薄粧，丁東環佩立西廂。',32,'全唐诗/poet.song.129000.json','["出繭修眉淡薄粧，丁東環佩立西廂。", "人間浪作新秋感，銀闕瓊樓夜夜涼。"]'),
('e3386d14-2d59-42e4-a787-36ba18a4acf6','自山中夜行還湖上','陸游','宋','宋诗','song-poetry','','[]','火雲崢嶸水車鳴，行人畏熱不敢寧。',128,'全唐诗/poet.song.129000.json','["火雲崢嶸水車鳴，行人畏熱不敢寧。", "蕭然一馬兩園丁，缺月照我影伶俜。", "荒鷄起早忽再唱，北斗低盡餘三星。", "扁舟菱歌正嫋嫋，叢冢鬼火何熒熒。", "迎人漸見鏡湖白，回首已失秦山青。", "道邊野店得小憩，一杯濁酒傾殘瓶。", "登盤絕愛畦韭美，轑釜未厭谿鱗腥。", "丈夫所要飽辛苦，文叔尚困蕪蔞亭。"]'),
('39331ed8-885b-4dcb-b714-fa343eb73ed9','大風','陸游','宋','宋诗','song-poetry','','[]','今年毒熱不可支，白汗如雨愁纖絺。',64,'全唐诗/poet.song.129000.json','["今年毒熱不可支，白汗如雨愁纖絺。", "皇天悔禍爲一洗，秋風作意来如期。", "聲如怒濤撼坤軸，夜半折我南齋竹。", "幽人晨起得奇觀，鳳尾襳襹一窗緑。"]'),
('bfaba32f-7ad0-4ab5-855c-1651389a71bd','新秋','陸游','宋','宋诗','song-poetry','','[]','天河漸近鵲橋時，一夜風吹斗柄移。',64,'全唐诗/poet.song.129000.json','["天河漸近鵲橋時，一夜風吹斗柄移。", "金井梧桐元未覺，畫廊蟋蟀已先知。", "青燈耿耿還相伴，白髮蕭蕭只自悲。", "猶勝玉門關外客，臥聽沙雁數歸期。"]'),
('36e2f910-62d4-4fdc-8fb5-f150d099f1e1','月夕睡起獨吟有懷建康參政','陸游','宋','宋诗','song-poetry','','[]','月上虛堂一榻横，斷香漠漠欲三更。',64,'全唐诗/poet.song.129000.json','["月上虛堂一榻横，斷香漠漠欲三更。", "隔簾清露挾秋氣，繞樹驚鴉啼月明。", "只怪夢尋千里道，不知愁作幾重城。", "苦吟更恨知心少，西望金陵闕寄聲。"]'),
('18d9d4d0-971d-4a61-9a07-7ef56635705b','病瘧後偶書','陸游','宋','宋诗','song-poetry','','[]','秋色已蕭然，曲肱清夜眠。',48,'全唐诗/poet.song.129000.json','["秋色已蕭然，曲肱清夜眠。", "孤燈欺病後，薄酒慰愁邊。", "藥物從人乞，文章畏客傳。", "惟應一篷艇，湖海送凋年。"]'),
('f7f0ed52-231c-4665-a7c5-48058f554d4d','秋日聞蟬','陸游','宋','宋诗','song-poetry','','[]','斷角斜陽觸處愁，長亭搔首晚悠悠。',32,'全唐诗/poet.song.129000.json','["斷角斜陽觸處愁，長亭搔首晚悠悠。", "世間最是蟬堪恨，送盡行人更送秋。"]'),
('412575a3-be1f-4ee7-afbd-a074fc4eb4e5','感秋','陸游','宋','宋诗','song-poetry','','[]','南山射虎漫豪雄，投老還鄉一秃翁。',64,'全唐诗/poet.song.129000.json','["南山射虎漫豪雄，投老還鄉一秃翁。", "世味掃除和蠟盡，生涯零落併錐空。", "秋驚蠧葉凋殘緑，病著衰顔失舊紅。", "笠澤松陵家世事，一竿惟是待西風。"]'),
('6bbcdde4-df4e-4d37-a00f-5b0ae65f7065','南軒','陸游','宋','宋诗','song-poetry','','[]','今年秋早涼，七月已蕭然。',72,'全唐诗/poet.song.129000.json','["今年秋早涼，七月已蕭然。", "南軒修竹下，枕簟終日眠。", "時將半殘夢，聽此欲斷蟬。", "推枕起太息，四序忽已遷。", "功名墮渺莽，衰疾方沈綿。", "新月獨多情，窺窗澹姢姢。"]'),
('74fec8b4-0575-4dbb-8d50-a35ceb697fda','夜坐','陸游','宋','宋诗','song-poetry','','[]','虛堂夜無寐，顧影嘆竛竮。',48,'全唐诗/poet.song.129000.json','["虛堂夜無寐，顧影嘆竛竮。", "露濕螢黏草，雲迷雁落汀。", "舊書開蠧簡，濁酒倒殘缾。", "流落知無憾，危機實飽經。"]'),
('9f904365-8f09-428b-b056-3f2b59ab8f54','新涼書事','陸游','宋','宋诗','song-poetry','','[]','臥看鳥篆印蒼苔，窗户涼生亦樂哉。',64,'全唐诗/poet.song.129000.json','["臥看鳥篆印蒼苔，窗户涼生亦樂哉。", "鳴樹亂蟬催日落，拂堦飛葉報秋来。", "病餘已覺身如寄，醉裏却憐心尚孩。", "排日從今占幽事，折殘籬菊探溪梅。"]'),
('f52ed57e-c49e-4186-891d-6bb8437acfc3','聞蟬思南鄭','陸游','宋','宋诗','song-poetry','','[]','昔在南鄭時，送客褒谷口。',96,'全唐诗/poet.song.129000.json','["昔在南鄭時，送客褒谷口。", "金羈叱撥駒，玉盌蒲萄酒。", "醉歸涉漾水，鳴蟬在高柳。", "回鞭指秦中，所懼壯心負。", "人生豈易料，蹭蹬十年後。", "蟬聲怳如昔，而我已白首。", "逆冦亡形具，輿地淪陷久。", "豈無好少年，共取印如斗。"]'),
('dcc95126-f5c5-4398-96b7-863e6f476db1','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔浮江發劍南，夕陽船尾每相衘。',64,'全唐诗/poet.song.129000.json','["憶昔浮江發劍南，夕陽船尾每相衘。", "楠陰暗處尋高寺，荔子紅時宿下巖。", "峽口烹猪賽龍廟，沙頭伐鼓挂風帆。", "區區陳迹何由記，惟有征塵尚滿衫。"]'),
('1b4a4492-ef92-4540-a531-e2e0be6d7572','病中夜興','陸游','宋','宋诗','song-poetry','','[]','病瘧秋来久未平，草堂遥夜不勝清。',64,'全唐诗/poet.song.129000.json','["病瘧秋来久未平，草堂遥夜不勝清。", "疾風遞響驚林葉，列宿收芒避月明。", "百計不能逃白髮，一生堪笑役虛名。", "釣車且作桐江夢，莫念安西萬里行。"]'),
('e8d2dd39-6580-4113-90da-b0e022e5bcf6','秋夜','陸游','宋','宋诗','song-poetry','','[]','秋氣侵帷夢不成，一燈西壁翳還明。',64,'全唐诗/poet.song.129000.json','["秋氣侵帷夢不成，一燈西壁翳還明。", "風高露井無桐葉，雨急烟村有雁聲。", "擊筑誰同燕市飲，賃舂方作會稽行。", "從来自許知何等，堪嘆江湖白髮生。"]'),
('fbe8d71b-77d7-4f33-b931-4054307ef3a8','謝張時可通判贈詩編','陸游','宋','宋诗','song-poetry','','[]','聖朝中興六十年，君家文武何聨翩。',96,'全唐诗/poet.song.129000.json','["聖朝中興六十年，君家文武何聨翩。", "先生劍履冠麟閣，後嗣簪槖陪甘泉。", "流傳到君愈卓犖，投我千篇皆傑作。", "未分玉帳萬貔貅，且擅詩人一丘壑。", "爾来士氣日靡靡，文章光燄伏不起。", "君今已似驥籋雲，更看他年鯤擊水。"]'),
('d5b164d1-4aa0-4f6d-b34f-a1d937ebdc7d','酬莊器之賢良見贈','陸游','宋','宋诗','song-poetry','','[]','先朝六科親策士，事業功名何壯偉。',128,'全唐诗/poet.song.129000.json','["先朝六科親策士，事業功名何壯偉。", "元祐復科財數年，所得四三俄復止。", "中興思賢形夢想，屢詔自是朝廷美。", "紈袴小兒壞人事，賜帛西歸困嘲詆。", "諸公相視嘆才難，一士臥雲誰挽起。", "跨驢過我時共語，晁董千年元不死。", "高談亹亹有脉絡，横得虛名吾可恥。", "烏巾白紵塞路衢，砥柱頹波望吾子。"]'),
('5bee908c-c380-466b-be77-0a1f423ee7eb','舟過樊江憩民家具食','陸游','宋','宋诗','song-poetry','','[]','旅食何妨美蕨薇，夕陽来叩野人扉。',64,'全唐诗/poet.song.129000.json','["旅食何妨美蕨薇，夕陽来叩野人扉。", "蕭蕭短鬢秋初冷，寂寂空村歲薦饑。", "蓼岸刺船驚雁起，烟陂吹笛喚牛歸。", "詩情剩向窮途得，蹭蹬人間未必非。"]'),
('a8e64e3c-269f-455e-bfb7-714fef2a75a1','舟中作','陸游','宋','宋诗','song-poetry','','[]','斷岸飲觳觫，清波跳噞喁。',48,'全唐诗/poet.song.129000.json','["斷岸飲觳觫，清波跳噞喁。", "紅橋未斜日，白塔已昏鐘。", "詩律與年邁，客愁如酒濃。", "宋公題壁處，横靄抱孤峰。"]'),
('bade05a5-8d3d-4789-865f-8651f838ef50','九月三日泛舟湖中作','陸游','宋','宋诗','song-poetry','','[]','兒童隨笑放翁狂，又向湖邊上野航。',64,'全唐诗/poet.song.129000.json','["兒童隨笑放翁狂，又向湖邊上野航。", "魚市人家滿斜日，菊花天氣近新霜。", "重重紅樹秋山晚，獵獵青帘社酒香。", "鄰曲莫辭同一醉，十年客裏過重陽。"]'),
('26413af5-c995-46fa-9416-b5b2c5383006','霜天晚興','陸游','宋','宋诗','song-poetry','','[]','薄霜門巷不勝清，小立湖邊夕照明。',64,'全唐诗/poet.song.129000.json','["薄霜門巷不勝清，小立湖邊夕照明。", "紅顆带芒收晚稻，緑苞和葉摘新橙。", "閑評琴價留僧話，靜聽松聲領鶴行。", "壯志消磨渾欲盡，西風莫動玉關情。"]'),
('fe662c43-e3dd-4f5d-bed6-616c07a8e984','九月六日小飲醒後作','陸游','宋','宋诗','song-poetry','','[]','短劍悲秦俠，高歌憶楚狂。',48,'全唐诗/poet.song.129000.json','["短劍悲秦俠，高歌憶楚狂。", "酒醒愁衮衮，香冷夢倀倀。", "屋老垣衣茂，池深石髮長。", "地爐須早計，衰病怯新霜。"]'),
('cf9be49f-8db3-44b3-ad06-ed71232c28d6','書悲二首  其一','陸游','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u6000", "\u56fd\u5bb6"]','今日我復悲，堅臥脚踏壁。',96,'全唐诗/poet.song.129000.json','["今日我復悲，堅臥脚踏壁。", "古来共一死，何至爾寂寂。", "秋風兩京道，上有胡馬跡。", "和戎壯士廢，憂國清泪滴。", "關河入指顧，忠義勇推激。", "常恐埋山丘，不得委鋒鏑。", "立功老無期，建議賤非職。", "賴有墨成池，淋漓豁胸臆。"]'),
('762aeb66-dff0-4729-ae84-79a03cf2acff','書悲二首  其二','陸游','宋','宋诗','song-poetry','','[]','丈夫孰能窮，吐氣成虹霓。',96,'全唐诗/poet.song.129000.json','["丈夫孰能窮，吐氣成虹霓。", "釀酒東海乾，累麴南山齊。", "平生搴旗手，頭白歸扶犁。", "誰知蓬窗夢，中有鐵馬嘶。", "何當受詔出，函谷封丸泥。", "築城天山北，開府蕭關西。", "萬里掃塵烟，三邊無鼓鼙。", "此意恐不遂，月明號荒雞。"]'),
('0ee50dce-afe7-468f-8187-da6cec7600d0','中夜起出門月露浩然歸坐燈下有賦','陸游','宋','宋诗','song-poetry','','[]','月白萬瓦霜，露重四山雨。',96,'全唐诗/poet.song.129000.json','["月白萬瓦霜，露重四山雨。", "開門忽驚嘆，秋色已如許。", "去蜀如昨日，坐閱四寒暑。", "無才屏朝蹟，有罪宜野處。", "平生萬里心，收斂臥環堵。", "朱顔逝不留，白髮生幾縷。", "人言尺蠖屈，要有黄鵠舉。", "功名非老事，歲晚忍羈旅。"]'),
('48c20375-4e1b-401a-b9a8-21d68f667056','新寒','陸游','宋','宋诗','song-poetry','','[]','病怯新寒欲不禁，南窗擁褐夜愔愔。',64,'全唐诗/poet.song.129000.json','["病怯新寒欲不禁，南窗擁褐夜愔愔。", "江湖跌宕送餘日，書劍蕭條孤壯心。", "杜曲新愁隨斷雁，遼陽遺恨入疏砧。", "此懷擬向何人說，賴有昏燈伴苦吟。"]'),
('f43b022f-84d7-4665-9ef9-019df0954c86','幽居','陸游','宋','宋诗','song-poetry','','[]','松陵甫里舊家風，晚節何妨號放翁。',64,'全唐诗/poet.song.129000.json','["松陵甫里舊家風，晚節何妨號放翁。", "衰極睡魔殊有力，愁多酒聖欲無功。", "一編蠧簡晴窗下，數捲疏籬落木中。", "退士所圖惟一飽，諸公好爲致年豐。"]'),
('f6d28fbc-fa79-4086-a004-4731c9a558c2','醉中步月湖上','陸游','宋','宋诗','song-poetry','','[]','閏餘時節早，天氣已凄冷。',72,'全唐诗/poet.song.129000.json','["閏餘時節早，天氣已凄冷。", "悠哉曵杖行，樂此清夜永。", "霜風鎪病骨，林月寫孤影。", "新詩得復忘，薄酒吹易醒。", "浮生役聲利，百歲常鼎鼎。", "清遊倘可繼，終老謝人境。"]'),
('6458f6da-85f3-433b-b734-7be26b5f082c','東村','陸游','宋','宋诗','song-poetry','','[]','塘路東頭烏桕林，偶攜藤杖得幽尋。',64,'全唐诗/poet.song.129000.json','["塘路東頭烏桕林，偶攜藤杖得幽尋。", "桃源阡陌自来往，輞口雲山無古今。", "遠浦過帆供極目，暮天横雁入微吟。", "歸来更覺愁無那，剩放燈前酒椀深。"]'),
('de89e5dc-7559-45bc-a0ca-4ea0ded5e0e0','西村','陸游','宋','宋诗','song-poetry','','[]','湖塘西去兩三家，杖履經行日欲斜。',64,'全唐诗/poet.song.129000.json','["湖塘西去兩三家，杖履經行日欲斜。", "蹙蹙水紋生細縠，蜿蜿沙路臥修蛇。", "旱餘蟲鏤園蔬葉，寒淺蜂爭野菊花。", "老去郊居多樂事，脫巾未用嘆蒼華。"]'),
('bc73a6c7-1523-4cde-ad11-58ef2ed919d3','題張幾仲所藏醉道士圖二首  其一','陸游','宋','宋诗','song-poetry','','[]','千載風流賀季真，畫圖髣髴見精神。',32,'全唐诗/poet.song.129000.json','["千載風流賀季真，畫圖髣髴見精神。", "邇来祭酒皆巫祝，眼底難逢此輩人。"]'),
('a12af56d-e1c9-4364-8bd1-3acf086bfdc6','題張幾仲所藏醉道士圖二首  其二','陸游','宋','宋诗','song-poetry','','[]','臥聽床頭壓酒聲，起行籬下摘新橙。',32,'全唐诗/poet.song.129000.json','["臥聽床頭壓酒聲，起行籬下摘新橙。", "一尊久欠敲門客，風味何人似麴生。"]'),
('bdf54d04-c209-4304-ab24-5a1b64ef5fb0','山園草間菊數枝開席地獨酌','陸游','宋','宋诗','song-poetry','','[]','屋東菊畦蔓草荒，瘦枝出草三尺長。',67,'全唐诗/poet.song.129000.json','["屋東菊畦蔓草荒，瘦枝出草三尺長。", "碎金狼藉不堪摘，掃地爲渠持一觴。", "日斜大醉叫墮幘，野花村酒何曾擇。", "君不見詩人跌宕例如此，蒼耳林中留太白。"]'),
('7285d618-8271-4043-a79e-6c62277c13fe','湖村月夕四首  其一','陸游','宋','宋诗','song-poetry','','[]','客路風塵化素衣，閑愁冉冉鬢成絲。',32,'全唐诗/poet.song.129000.json','["客路風塵化素衣，閑愁冉冉鬢成絲。", "平生不負月明處，神女廟前聞竹枝。"]'),
('55359fc2-1017-4761-a2bb-8f767c48d8b7','湖村月夕四首  其二','陸游','宋','宋诗','song-poetry','','[]','錦城曾醉六重陽，回首秋風每斷腸。',32,'全唐诗/poet.song.129000.json','["錦城曾醉六重陽，回首秋風每斷腸。", "最憶銅壺門外路，滿街歌吹月如霜。"]'),
('20d474fe-dc4c-4d54-afd8-2f31e1b3e5af','湖村月夕四首  其三','陸游','宋','宋诗','song-poetry','','[]','金尊翠杓猶能醉，狐帽貂裘不怕寒。',32,'全唐诗/poet.song.129000.json','["金尊翠杓猶能醉，狐帽貂裘不怕寒。", "安得驊騮三萬疋，月中鼓吹渡桑乾。"]'),
('585a9ae0-9dc9-49da-8f17-6edb4360e1e3','湖村月夕四首  其四','陸游','宋','宋诗','song-poetry','','[]','誰持緑酒醉幽人，鶴氅笻枝發興新。',32,'全唐诗/poet.song.129000.json','["誰持緑酒醉幽人，鶴氅笻枝發興新。", "今夜湖邊有奇事，青山缺處涌冰輪。"]'),
('98b89360-ab46-405d-baf9-b57bb0520df1','卯酒徑醉走筆','陸游','宋','宋诗','song-poetry','','[]','少時憑酒剩狂顛，摘宿緣雲欲上天。',32,'全唐诗/poet.song.129000.json','["少時憑酒剩狂顛，摘宿緣雲欲上天。", "才盡氣衰空自笑，一杯纔放已頽然。"]'),
('1856fc7f-cbaf-419c-8b5f-aa2f3caa8520','山中望籬東楓樹有懷成都','陸游','宋','宋诗','song-poetry','','[]','五門西角紅樓下，一樹丹楓馬上看。',32,'全唐诗/poet.song.129000.json','["五門西角紅樓下，一樹丹楓馬上看。", "回首舊遊如夢裏，西風吹泪倚闌干。"]'),
('040a785b-5427-4be1-8448-472531a2206c','暮秋有懷王四季夷','陸游','宋','宋诗','song-poetry','','[]','鏡湖西畔小茅茨，紅葉黄花秋晚時。',64,'全唐诗/poet.song.129000.json','["鏡湖西畔小茅茨，紅葉黄花秋晚時。", "天闊素書無雁寄，夜闌清夢有燈知。", "功名蹭蹬初何憾，朋舊乖離未免悲。", "遥想扁舟五湖口，阻風中酒又成詩。"]'),
('21d81d17-639f-48fd-901c-3fc0cdb5a92d','幽居','陸游','宋','宋诗','song-poetry','','[]','老子堪咍老轉癡，幽居喜及早寒時。',64,'全唐诗/poet.song.129000.json','["老子堪咍老轉癡，幽居喜及早寒時。", "芋魁加糝香出屋，菰首芼羮甘若飴。", "顛倒朱黄思誤字，縱横黑白戲拈棋。", "此懷敢向今人說，骨朽諸賢却見知。"]'),
('a3f71130-b20d-44d3-be24-0004b7207833','有懷','陸游','宋','宋诗','song-poetry','','[]','笻杖斜斜倚素屏，北窗遥夜冷如冰。',32,'全唐诗/poet.song.129000.json','["笻杖斜斜倚素屏，北窗遥夜冷如冰。", "何時得與平生友，作字觀書共一燈。"]'),
('8f95a962-bd17-4b03-9338-02b73c281f93','對酒','陸游','宋','宋诗','song-poetry','','[]','醫從和扁来，未著却老方。',96,'全唐诗/poet.song.129000.json','["醫從和扁来，未著却老方。", "吾晚乃得之，莫如麴糵良。", "一杯臉生春，況復累十觴。", "坐令桃花紅，換盡霜葉黄。", "看鏡喜欲舞，追還少年狂。", "但恨寶釵樓，胡沙隔咸陽。", "芳華雖無恙，萬里遥相望。", "感嘆徑投枕，悲歡兩茫茫。"]'),
('44a1c4c5-eda8-47e0-ae27-69c7c7d9b743','初冬','陸游','宋','宋诗','song-poetry','','[]','鉏犂滿野及冬耕，時聽兒童叱犢聲。',64,'全唐诗/poet.song.129000.json','["鉏犂滿野及冬耕，時聽兒童叱犢聲。", "逐客固宜安散地，閑民何幸樂昇平。", "雪花漫漫蕎將熟，綠葉離離薺可烹。", "飯飽身閑書有課，西窗来趁夕陽明。"]'),
('338dffac-37e1-4fed-8321-45b9eeffe47d','晝寢夢一客相過若有舊者夷粹可愛既覺作絕句記之','陸游','宋','宋诗','song-poetry','','[]','夢中何許得嘉賓，對影胡床岸幅巾。',32,'全唐诗/poet.song.129000.json','["夢中何許得嘉賓，對影胡床岸幅巾。", "石鼎烹茶火煨栗，主人坦率客情真。"]'),
('3ccc7217-dd02-4674-a040-b9151eb37762','書嘆','陸游','宋','宋诗','song-poetry','','[]','多病文園苦滯留，時時浩嘆攬貂裘。',64,'全唐诗/poet.song.129000.json','["多病文園苦滯留，時時浩嘆攬貂裘。", "縱無夜雨何曾寐，不爲秋風也自愁。", "今歲頓驚絲鬢改，此生難繼錦江遊。", "欲談舊事無人共，日落鴉歸又倚樓。"]'),
('d0137cde-eca0-42b4-966c-6d9136ebc182','督下麥雨中夜歸','陸游','宋','宋诗','song-poetry','','[]','細雨闇村墟，青烟濕廬舍。',96,'全唐诗/poet.song.129000.json','["細雨闇村墟，青烟濕廬舍。", "兩兩犢竝行，陣陣鴉續下。", "紅稠水際蓼，黄落屋邊柘。", "力作不知勞，歸路忽已夜。", "犬吠闖籬隙，燈光出門罅。", "豈惟露沾衣，乃有泥沒胯。", "誰憐甫里翁，白首學耕稼。", "未言得一飽，此段已可畫。"]'),
('65275233-1f0d-4a3a-8f4a-fa3d0d99db2e','霜曉肩輿行湖上','陸游','宋','宋诗','song-poetry','','[]','去去出柴關，巾車古陌間。',48,'全唐诗/poet.song.129000.json','["去去出柴關，巾車古陌間。", "晨霜染丹葉，宿霧淡青山。", "登覽身猶健，歌呼酒每慳。", "殷勤鏡湖水，聊爲照衰顔。"]'),
('f06fae8e-f10d-42a9-9438-193b58c499e1','杜門','陸游','宋','宋诗','song-poetry','','[]','寂寞山深處，崢嶸歲暮時。',48,'全唐诗/poet.song.129000.json','["寂寞山深處，崢嶸歲暮時。", "燒灰除菜蝗，送芋謝牛醫。", "筧水晨澆藥，燈窗夜覆棋。", "杜門君勿怪，遲暮少新知。"]'),
('5c4d14ae-a145-43ff-a7ac-6e3c5023387d','横塘','陸游','宋','宋诗','song-poetry','','[]','横塘南北埭西東，拄杖飄然樂未窮。',64,'全唐诗/poet.song.129000.json','["横塘南北埭西東，拄杖飄然樂未窮。", "農事漸興人滿野，霜寒初重雁横空。", "參差樓閣高城上，寂歴村墟細雨中。", "新買一蓑苔様緑，此生端欲伴漁翁。"]'),
('47bd7629-ca05-4f23-b024-999551509efb','書事寄良長老','陸游','宋','宋诗','song-poetry','','[]','素屏烏几野人廬，山色蒼寒十月初。',64,'全唐诗/poet.song.129000.json','["素屏烏几野人廬，山色蒼寒十月初。", "雨足四郊耕欲遍，霜高萬木脫無餘。", "一尊窗下澆愁酒，數卷床頭引睡書。", "寄語住庵劉老宿，不應隨俗向人疏。"]'),
('bed96d8c-6bd9-4cb3-ac41-7fa9a09616b4','食薺十韵','陸游','宋','宋诗','song-poetry','','[]','舍東種早韭，生計似庾郎。',120,'全唐诗/poet.song.129000.json','["舍東種早韭，生計似庾郎。", "舍西種小菓，戲學蠶叢鄉。", "惟薺天所賜，青青被陵岡。", "珍美屏鹽酪，耿介凌雪霜。", "采擷無闕日，烹餁有秘方。", "候火地爐暖，加糝沙鉢香。", "尚嫌雜筍蕨，而況汙膏粱。", "炊秔及鬻餅，得此生輝光。", "吾饞實易足，捫腹喜欲狂。", "一掃萬錢食，終老稽山旁。"]'),
('7c37f599-7cc3-4280-9a84-474ceb54a42d','冬暖頗有春意追憶成都昔遊悵然有作','陸游','宋','宋诗','song-poetry','','[]','濯錦江邊罨畫樓，金鞭曾護犢車遊。',64,'全唐诗/poet.song.129000.json','["濯錦江邊罨畫樓，金鞭曾護犢車遊。", "紛紛萬事反乎覆，落落一身淹此留。", "刻燭賦詩空入夢，傾家釀酒不供愁。", "探春歌吹應如昨，亦有朋儕記我不。"]'),
('72ca1ff1-a507-42a1-9736-672d2cf6a362','忽忽','陸游','宋','宋诗','song-poetry','','[]','忽忽復悠悠，頻驚歲月遒。',48,'全唐诗/poet.song.129000.json','["忽忽復悠悠，頻驚歲月遒。", "若無船貯酒，將奈斛量愁。", "列炬燕宮夜，呼鷹漢廟秋。", "凋年莫多感，夢境付滄洲。"]'),
('9dc8ab6f-0c7b-4137-9926-317007c93956','醉書山亭壁','陸游','宋','宋诗','song-poetry','','[]','物外陽狂五百年，扁舟又繫鏡湖邊。',64,'全唐诗/poet.song.129000.json','["物外陽狂五百年，扁舟又繫鏡湖邊。", "飛昇未抵簮花樂，遊宦何如聽雨眠。", "緑蟻灔尊芳醞熟，黑蛟落紙草書顛。", "忽拈玉笛横吹去，說與傍人是地仙。"]'),
('ac907322-4c9e-4d49-96c4-b6b704133ae1','十月旦日至近村','陸游','宋','宋诗','song-poetry','','[]','鴨脚葉黄烏臼丹，草烟小店風雨寒。',64,'全唐诗/poet.song.129000.json','["鴨脚葉黄烏臼丹，草烟小店風雨寒。", "荒年人家雞黍迮，芋羮豆飯供時節。", "村童上牛踏牛鼻，吹笛聲長入雲際。", "今年雖饑却少安，縣吏不来官放稅。"]'),
('885990b3-2642-41ea-b6a8-7a7ddeb24e8d','蔬圃絕句七首  其一','陸游','宋','宋诗','song-poetry','','[]','擬種蕪菁已是遲，晚菘早韭恰當時。',32,'全唐诗/poet.song.129000.json','["擬種蕪菁已是遲，晚菘早韭恰當時。", "老夫要作齋盂備，乞得青秧趁雨移。"]'),
('bc00b11d-00bd-4202-8db9-e46870426d35','蔬圃絕句七首  其二','陸游','宋','宋诗','song-poetry','','[]','百錢新買綠蓑衣，不羨黄金带十圍。',32,'全唐诗/poet.song.129000.json','["百錢新買綠蓑衣，不羨黄金带十圍。", "枯柳坡頭風雨急，憑誰畫我荷鉏歸。"]'),
('5835c5b4-3765-4c50-8c19-dd22efee5483','蔬圃絕句七首  其三','陸游','宋','宋诗','song-poetry','','[]','青青蔬甲早寒天，想像登盤已墮涎。',32,'全唐诗/poet.song.129000.json','["青青蔬甲早寒天，想像登盤已墮涎。", "更欲鉏畦向東去，園丁来報竹行鞭。"]'),
('d7d69bc4-d089-4af1-9a2a-0b6fc0ca3518','蔬圃絕句七首  其四','陸游','宋','宋诗','song-poetry','','[]','瓦疉浮屠盆作池，池邊紅蓼両三枝。',32,'全唐诗/poet.song.129000.json','["瓦疉浮屠盆作池，池邊紅蓼両三枝。", "貪看忘却還家飯，恰似兒童放學時。"]'),
('e095aa54-6452-41e8-8a1e-2de9300de55e','蔬圃絕句七首  其五','陸游','宋','宋诗','song-poetry','','[]','小橋只在槿籬東，溝水穿籬曲折通。',32,'全唐诗/poet.song.129000.json','["小橋只在槿籬東，溝水穿籬曲折通。", "烟雨空濛最堪樂，從敎打濕敗天公。"]'),
('509e758c-5ebf-4f26-b068-824513ace84a','蔬圃絕句七首  其六','陸游','宋','宋诗','song-poetry','','[]','衝雨衝風不怕寒，晚来日出短蓑乾。',32,'全唐诗/poet.song.129000.json','["衝雨衝風不怕寒，晚来日出短蓑乾。", "遶畦拾塊真爲樂，莫作陶公運甓看。"]'),
('73d13ebd-e4fe-4b36-ae3e-a964747008c2','蔬圃絕句七首  其七','陸游','宋','宋诗','song-poetry','','[]','懶隨年少愛花狂，且伴群兒鬭草忙。',32,'全唐诗/poet.song.129000.json','["懶隨年少愛花狂，且伴群兒鬭草忙。", "行遍山南山北路，歸時新月浸横塘。"]'),
('2596301c-e888-4094-b4fc-595bc5664815','冬夜不寐至四鼓起作此詩','陸游','宋','宋诗','song-poetry','','[]','秦吴萬里車轍遍，重到故鄉如隔生。',64,'全唐诗/poet.song.129000.json','["秦吴萬里車轍遍，重到故鄉如隔生。", "歲晚酒邊身老大，夜闌枕畔書縱横。", "殘燈無焰穴鼠出，槁葉有聲村犬行。", "八十將軍能滅虜，白頭吾欲事功名。"]'),
('1d974534-2805-4553-96e3-4d1b69d2f515','蔬圃','陸游','宋','宋诗','song-poetry','','[]','山翁老學圃，自笑一何愚。',96,'全唐诗/poet.song.129000.json','["山翁老學圃，自笑一何愚。", "磽瘠財三畝，勤劬賴兩奴。", "正方畦畫局，微潤土融酥。", "翦闢荆榛盡，鉏犁磊塊無。", "過溝横略彴，聚甓起浮屠。", "隙地成瓜援，餘功及芋區。", "如絲細生菜，似鴨爛蒸壺。", "此事今真辦，東歸不爲鱸。"]'),
('1000add1-a7a5-44c3-9596-db595d48b81c','夢中作','陸游','宋','宋诗','song-poetry','','[]','拓地移屯過酒泉，第功圖像上凌烟。',64,'全唐诗/poet.song.129000.json','["拓地移屯過酒泉，第功圖像上凌烟。", "事權皂纛兼黄鉞，冨貴金貂映玉蟬。", "油築毬場飛騕褭，錦裁步障貯嬋娟。", "擁塗士女千層看，應記新豐舊少年。"]'),
('f1815314-a7c6-4b3e-8d7b-a7e0d4704c4c','村居酒熟偶無肉食煮菜羮飲酒','陸游','宋','宋诗','song-poetry','','[]','歌鳳倀倀類楚狂，畏犧齪齪笑蒙莊。',64,'全唐诗/poet.song.129000.json','["歌鳳倀倀類楚狂，畏犧齪齪笑蒙莊。", "著書幸可俟後世，對客從嗔臥大床。", "三畝青蔬了盤筯，一缸濁酒具杯觴。", "丈夫窮達皆常事，富貴何妨食萬羊。"]'),
('fc6a8042-03c6-43c6-80d4-678ad5e80c81','辛丑十月諸公餽酒偶及百榼戲題長句','陸游','宋','宋诗','song-poetry','','[]','喜事諸公尚見存，尺書時到爵羅門。',64,'全唐诗/poet.song.129000.json','["喜事諸公尚見存，尺書時到爵羅門。", "已邀風月成三友，聊對湖山倒百尊。", "醉墨淋漓動高壁，狂歌悲壯落前村。", "悠然睡起西窗黑，一點青燈又斷魂。"]'),
('b27983b4-7012-4341-bd19-5cb0abba545f','灌園','陸游','宋','宋诗','song-poetry','','[]','少攜一劍行天下，晚落空村學灌園。',32,'全唐诗/poet.song.129000.json','["少攜一劍行天下，晚落空村學灌園。", "交舊凋零身老病，輪囷肝膽與誰論。"]'),
('0ae17171-0fc6-4077-9904-cc0af4f4178e','幽居','陸游','宋','宋诗','song-poetry','','[]','破屋頽垣霧雨昏，幽人終日掩柴門。',64,'全唐诗/poet.song.129000.json','["破屋頽垣霧雨昏，幽人終日掩柴門。", "因鋤衰草通南阜，偶洗叢篁見北村。", "裋褐奇温等狐腋，寒蔬脆美敵熊蹯。", "冬来酒戸微增舊，萬事應須付一尊。"]'),
('e58c482f-e41a-43cb-9fc3-fb55d470008e','日出入行','陸游','宋','宋诗','song-poetry','','[]','吾聞開闔来，白日行長空。',126,'全唐诗/poet.song.129000.json','["吾聞開闔来，白日行長空。", "扶桑誰曾到，崦嵫不可窮。", "但見旦旦升天東，但見暮暮入地中。", "使我倐忽成老翁，鏡裏衰鬢成霜蓬。", "我願一日一百二十刻，我願一生一千二百歲。", "四海諸公常在座，緑酒金尊終日醉。", "高樓錦繡中天開，樂作畫鼓如春雷。", "歡爾白日無西頽，常行九十萬里胡爲哉。"]'),
('a63e3416-3d14-4845-bf28-325915a2cf57','午醉徑睡比覺己甲夜矣','陸游','宋','宋诗','song-poetry','','[]','自我歸城西，已復再見冬。',72,'全唐诗/poet.song.129000.json','["自我歸城西，已復再見冬。", "雖未挂衣冠，其實則老農。", "好事或餉酒，石室酒最醲。", "一醉輒至暮，臥聞湖寺鐘。", "心安病自除，衾暖夢欲重。", "化作孤鶴去，雲崦巢長松。"]'),
('8b972c31-b892-44b6-833c-483a16e3bc35','簡蘇訓直判院莊器之賢良','陸游','宋','宋诗','song-poetry','','[]','行盡天涯白髮新，槿籬竹屋著閑身。',64,'全唐诗/poet.song.129000.json','["行盡天涯白髮新，槿籬竹屋著閑身。", "讀書達旦失衰病，食菜終年安賤貧。", "正使寄聲無薛孟，不妨同里有荀陳。", "從今杖履時相過，花柳村村次第春。"]'),
('73167a00-36af-408e-91b1-79e4cd099a20','醉眠曲','陸游','宋','宋诗','song-poetry','','[]','老夫暮年少嗜好，但願無事終日眠。',160,'全唐诗/poet.song.129000.json','["老夫暮年少嗜好，但願無事終日眠。", "斜風急雨勢方横，低窗小閣且幽妍。", "爐紅酒緑足閑暇，橙黄蟹紫窮芳鮮。", "一杯一杯意忽倦，徑撥紙帳投蠻氊。", "鼻間鼾聲欲撼屋，手中書冊正墮前。", "不知校事白中聖，那惜門生嘲腹便。", "讀書萬卷晚乃悟，妙哉此訣秘不傳。", "是醒是醉人莫測，非夢非覺中了然。", "駸駸百年露電速，鼎鼎一世膏火煎。", "金丹九轉顧未暇，且向人間稱睡僊。"]'),
('1707889e-d0c1-4af7-88a6-4d9d7d76847a','冬夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','歲晚風霜惡，將如遥夜何。',48,'全唐诗/poet.song.129000.json','["歲晚風霜惡，將如遥夜何。", "殘燈挑更暗，寒犬吠偏多。", "支枕成孤詠，懷人起浩歌。", "梅花不解飲，誰伴醉顔酡。"]'),
('cf4a8e0c-fe27-43ca-8595-72e59abe8ac4','冬夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','忽忽流年恨，悠悠獨夜情。',48,'全唐诗/poet.song.129000.json','["忽忽流年恨，悠悠獨夜情。", "向人燈欲語，遶舍露如傾。", "夢每輕千里，愁偏怯五更。", "殷勤桑落酒，好爲解餘酲。"]'),
('34ca5d40-69b4-4e82-8bea-1272ac1697a3','夜話贈華師','陸游','宋','宋诗','song-poetry','','[]','少喜洛陽俠，今成衡嶽僧。',48,'全唐诗/poet.song.129000.json','["少喜洛陽俠，今成衡嶽僧。", "深培地爐火，明照佛龕燈。", "衰鬢晨霜白，禪心古澗澄。", "猶能遍參在，爲我買行縢。"]'),
('4948dc2b-d9e6-450f-9214-4bbb63acf148','臥病書懷','陸游','宋','宋诗','song-poetry','','[]','衮衮年光挽不留，即今已白五分頭。',64,'全唐诗/poet.song.129000.json','["衮衮年光挽不留，即今已白五分頭。", "病中對酒猶思醉，夢裏逢人亦說愁。", "青海戰雲臨賊壘，黑山飛雪灑貂裘。", "丈夫有志終難料，憔悴漁村死即休。"]'),
('2b5c3fab-db4d-4a14-a098-3dd395f43a1b','病中絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','酒錢自昔從人乞，詩思出門何處無。',32,'全唐诗/poet.song.129000.json','["酒錢自昔從人乞，詩思出門何處無。", "青篛織篷菅織席，此生端欲老江湖。"]'),
('ee2af86f-497e-4d94-8922-b32234cfaa0d','病中絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','半脫貂裘雪滿鞍，慣將豪舉壓儒酸。',32,'全唐诗/poet.song.129000.json','["半脫貂裘雪滿鞍，慣將豪舉壓儒酸。", "病来意氣渾非昨，一炷香烟帳底看。"]'),
('6254cd4b-b229-4e20-a706-f9924967dba9','病中絕句六首  其三','陸游','宋','宋诗','song-poetry','','[]','酒味醺人睡味濃，午時高枕到昏鐘。',32,'全唐诗/poet.song.129000.json','["酒味醺人睡味濃，午時高枕到昏鐘。", "經旬不見西窗日，世上應無懶似儂。"]'),
('bccdaede-df9d-446e-9fc5-bdfecad84e75','病中絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','造物今年憫我勞，微痾得遂閉門高。',32,'全唐诗/poet.song.129000.json','["造物今年憫我勞，微痾得遂閉門高。", "黄紬被暖青氊穩，不怕郊原雪意豪。"]'),
('bf5485a5-d729-41c5-a65d-d294d8a4a34f','病中絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','青熒猶有佛燈明，點滴時聞竹露聲。',32,'全唐诗/poet.song.129000.json','["青熒猶有佛燈明，點滴時聞竹露聲。", "欲睡不成還起坐，麗譙風順報三更。"]'),
('19d08708-4b2e-4a59-ad62-ad36e4ca0b2c','病中絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','少時談舌挾風雷，病後逢人口懶開。',32,'全唐诗/poet.song.129000.json','["少時談舌挾風雷，病後逢人口懶開。", "安得東皋隱君子，相看無語只衘杯。"]'),
('3c7b506c-94cc-41f1-8dc9-c143bfd86836','蔬園雜詠 菘','陸游','宋','宋诗','song-poetry','','[]','雨送寒聲滿背蓬，如今真是荷鋤翁。',32,'全唐诗/poet.song.129000.json','["雨送寒聲滿背蓬，如今真是荷鋤翁。", "可憐遇事常遲鈍，九月區區種晚菘。"]'),
('a99afb5f-831d-43d0-a7be-451a0c3a8d1b','蔬園雜詠 蕪菁','陸游','宋','宋诗','song-poetry','','[]','往日蕪菁不到吴，如今幽圃手親鉏。',32,'全唐诗/poet.song.129000.json','["往日蕪菁不到吴，如今幽圃手親鉏。", "憑誰爲向曹瞞道，徹底無能合種蔬。"]'),
('1a347e29-b227-4bc2-8b79-cf6c1d4d2db7','蔬園雜詠 葱','陸游','宋','宋诗','song-poetry','','[]','瓦盆麥飯伴鄰翁，黄菌青蔬放筯空。',32,'全唐诗/poet.song.129000.json','["瓦盆麥飯伴鄰翁，黄菌青蔬放筯空。", "一事尚非貧賤分，芼羮僭用大官葱。"]'),
('ef5c212a-d500-4be3-bf25-653ecadf5d6d','蔬園雜詠 巢','陸游','宋','宋诗','song-poetry','','[]','昏昏霧雨暗衡茅，兒女隨宜治酒殽。',32,'全唐诗/poet.song.129000.json','["昏昏霧雨暗衡茅，兒女隨宜治酒殽。", "便覺此身如在蜀，一盤籠餅是豌巢。"]'),
('f223871c-e19f-41fd-ba3f-d1adbb1b0c73','蔬園雜詠 芋','陸游','宋','宋诗','song-poetry','','[]','陸生晝臥腹便便，嘆息何時食萬錢。',32,'全唐诗/poet.song.129000.json','["陸生晝臥腹便便，嘆息何時食萬錢。", "莫誚蹲鴟少風味，賴渠撐拄過凶年。"]'),
('6355a483-3f46-47a3-94e8-f1400bb0b470','卯飲醉臥枕上有賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','天寒朝泥酒，熟醉臥蓬窗。',48,'全唐诗/poet.song.129000.json','["天寒朝泥酒，熟醉臥蓬窗。", "雨勢平吞野，風聲倒卷江。", "漁蓑傲狐腋，菜把美羊腔。", "常笑潮陽守，南征畏下瀧。"]'),
('fdb63f03-f254-48a3-b1ab-a037f38979ec','卯飲醉臥枕上有賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','一榻臥空舍，四山風雨聲。',48,'全唐诗/poet.song.129000.json','["一榻臥空舍，四山風雨聲。", "病多書倚閣，寒極酒施行。", "孤憤歌彌放，端憂涕易横。", "群羌滿河洛，志士若爲情。"]'),
('950db231-10a6-46f3-94d0-b2586716aa30','十月二十六日夜夢行南鄭道中既覺恍然攬筆作此詩時且五鼓矣','陸游','宋','宋诗','song-poetry','','[]','孤雲兩角不可行，望雲九井不可渡。',240,'全唐诗/poet.song.129000.json','["孤雲兩角不可行，望雲九井不可渡。", "嶓冢之山高插天，漢水滔滔日東去。", "高皇試劍石爲分，草沒苔封猶故處。", "將壇坡陀過千載，中野疑有神物護。", "我時在幕府，来往無晨暮。", "夜宿沔陽驛，朝飯長木鋪。", "雪中痛飲百榼空，蹴踏山林伐狐兔。", "躭躭北山虎，食人不知數。", "孤兒寡婦讎不報，日落風生行旅懼。", "我聞投袂起，大呼聞百步。", "奮戈直前虎人立，吼裂蒼崖血如注。", "從騎三千皆秦人，面青氣奪空相顧。", "國家未發渡遼師，落魄人間傍行路。", "對花把酒學醞藉，空辱諸公誦詩句。", "即今衰病臥在床，振臂猶思備征戍。", "南人孰謂不知兵，昔者亡秦楚三戶。"]'),
('ca88d052-3a74-44b6-9c8d-f4fb91fbb97a','雨晴步至山亭欲遂遊東村不果','陸游','宋','宋诗','song-poetry','','[]','村陋垣屋頽，歲晚風雨横。',120,'全唐诗/poet.song.129000.json','["村陋垣屋頽，歲晚風雨横。", "泥塗絕還往，飱粥養衰病。", "藥囊雜書卷，白髮滿清鏡。", "一榻臥兼旬，不踐牆下徑。", "烏鵲忽報晴，霜重節候正。", "厭供凍硯愁，頗動蠟屐興。", "山楹快遠眺，松吹愜幽聽。", "地瘦藥苖稀，葉脫木枝勁。", "東村未爲遠，脚力不濟勝。", "三嘆入荆扉，跏趺學僧定。"]'),
('2a983fb0-1358-42f3-8433-60842344eee6','喜晴','陸游','宋','宋诗','song-poetry','','[]','衡門病臥動經旬，歲晚況堪風雨頻。',64,'全唐诗/poet.song.129000.json','["衡門病臥動經旬，歲晚況堪風雨頻。", "晴日一窗殊慰眼，清霜萬瓦更宜人。", "開書頓失昏花墜，試茗初看白乳新。", "南埭東陂從此好，剩將紅蘂插烏巾。"]'),
('5c62ce99-1499-45cc-9f84-951d348b48f0','對食','陸游','宋','宋诗','song-poetry','','[]','人苦不知足，貪欲浩無窮。',125,'全唐诗/poet.song.129000.json','["人苦不知足，貪欲浩無窮。", "豹胎日饜飫，萍虀却時供。", "飲豚以人乳，萬乘亦改容。", "方其未遇時，鵝{炙火=肉}動英雄。", "哀哉王相國，計墮飯後鐘。", "所以賢達士，一視約與豐。", "我亦蹭蹬者，羈遊半生中。", "木槃飽藜莧，美與玉食同。", "口腹嗟幾何，曾是役我躬。", "放箸一笑粲，賦詩曉愚公。"]'),
('894f2850-943d-4904-9130-dea1fe6bd844','不睡','陸游','宋','宋诗','song-poetry','','[]','城遠不聞鐘鼓傳，孤村風雨夜騷然。',64,'全唐诗/poet.song.129000.json','["城遠不聞鐘鼓傳，孤村風雨夜騷然。", "但悲緑酒欺多病，敢恨青燈笑不眠。", "水冷硯蟾初薄凍，火殘香鴨尚微烟。", "虛窗忽報東方白，且復繙經繡佛前。"]'),
('b2421010-0c37-4bae-a402-c1668ca69fea','睡','陸游','宋','宋诗','song-poetry','','[]','紙帳青氊暖有餘，昏昏信脚到華胥。',64,'全唐诗/poet.song.129000.json','["紙帳青氊暖有餘，昏昏信脚到華胥。", "凍醪有力勤推挽，春茗無端苦破除。", "半熟擁衾聞急雨，乍回推枕覓殘書。", "箇中得意君知否，萬户生封未必如。"]'),
('5591aef3-220c-41c6-b0bb-488e42b416f1','憶荆州舊遊','陸游','宋','宋诗','song-poetry','','[]','書劍萬里行翩翩，度關登隴常慨然。',103,'全唐诗/poet.song.129000.json','["書劍萬里行翩翩，度關登隴常慨然。", "射麋雲夢最樂事，至今曠快思楚天。", "落筆千言不加點，班荆百榼命割鮮。", "有時憑陵呼五白，笑人辛苦作太玄。", "君不見將軍昔忍跨下辱，京兆晚爲人所憐。", "功名冨貴自古只如此，不如馳射樂飲終殘年。"]'),
('15b97d51-1a22-4913-b43a-7a3a43f92fd5','五雲門晚歸','陸游','宋','宋诗','song-poetry','','[]','高城带遠林，落日動寒砧。',48,'全唐诗/poet.song.129000.json','["高城带遠林，落日動寒砧。", "行客自朝暮，青山無古今。", "衰遲慚逸氣，憂患足危心。", "溪迮滯歸艇，何時春水深。"]'),
('4a9da939-c501-4831-b454-c51575126fff','冬暖','陸游','宋','宋诗','song-poetry','','[]','今年歲暮無風雪，塵土肺肝生客熱。',96,'全唐诗/poet.song.129000.json','["今年歲暮無風雪，塵土肺肝生客熱。", "經旬止酒臥空齋，吴蠏秦酥不容設。", "日憂疾疫被齊民，更畏螟蝗殘宿麥。", "濃霜薄霰不可得，太息何時見三白。", "老夫壯氣横九州，坐想提兵西海頭。", "萬騎吹笳行雪野，玉花亂點黑貂裘。"]'),
('ba87433f-65bf-4f43-99c8-eb7e611decf1','歲暮','陸游','宋','宋诗','song-poetry','','[]','吴中寒氣薄，歲暮亦和風。',48,'全唐诗/poet.song.129000.json','["吴中寒氣薄，歲暮亦和風。", "移樹来村北，尋僧渡港東。", "露葵收半綠，霜稻杵微紅。", "一飽無餘念，吾生正不窮。"]'),
('0d5896d6-d239-4f12-8aea-e258e08799f6','雪夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','書卷紛紛雜藥囊，擁衾時炷海南香。',32,'全唐诗/poet.song.129000.json','["書卷紛紛雜藥囊，擁衾時炷海南香。", "衰遲自笑壯心在，喜聽北風吹雪床。"]'),
('6711aa17-7a56-470f-8089-85fe771d0fbe','雪夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','村路雪泥人斷行，佛燈一點絳紗明。',32,'全唐诗/poet.song.129000.json','["村路雪泥人斷行，佛燈一點絳紗明。", "山前栖鶴歸何晚，磔磔風傳勁翮聲。"]'),
('cea7eb65-1140-4cf2-bba5-41e3064904a4','禪室','陸游','宋','宋诗','song-poetry','','[]','早誇劇飲無勍敵，晚覺安禪有宿因。',64,'全唐诗/poet.song.129000.json','["早誇劇飲無勍敵，晚覺安禪有宿因。", "赫赫心光誰障礙，緜緜鼻息自輕勻。", "蒲龕紙帳藏身穏，香椀燈籠作夢新。", "勿爲霜寒憶溫暖，少林立雪彼何人。"]'),
('c08f8dca-d44f-471b-b8d2-b20359c35543','炭盡地爐危坐至夜分戲作','陸游','宋','宋诗','song-poetry','','[]','短景窗易黑，長宵爐少紅。',48,'全唐诗/poet.song.129000.json','["短景窗易黑，長宵爐少紅。", "直令貧到骨，未害氣如虹。", "志士元謀道，儒生敢諱窮。", "霜嚴雞喔喔，但愧讀書功。"]'),
('06a60be8-ff57-4920-90b6-31e2a392ace3','夜汲井水煮茶','陸游','宋','宋诗','song-poetry','','[]','病起罷觀書，袖手清夜永。',72,'全唐诗/poet.song.129000.json','["病起罷觀書，袖手清夜永。", "四鄰悄無語，燈火正凄冷。", "山童亦睡熟，汲水自煎茗。", "鏘然轆轤聲，百尺鳴古井。", "肺腑凛清寒，毛骨亦蘇省。", "歸来月滿廊，惜踏疏梅影。"]'),
('60fbfd52-aade-45b5-a7aa-c72fc87a174c','雪後尋梅偶得絕句十首  其一','陸游','宋','宋诗','song-poetry','','[]','雪晴蕭散曳笻枝，小塢尋梅正及時。',32,'全唐诗/poet.song.129000.json','["雪晴蕭散曳笻枝，小塢尋梅正及時。", "臨水登山一年恨，十分說似要渠知。"]'),
('38505842-ac95-4c75-8855-0de86c646d0d','雪後尋梅偶得絕句十首  其二','陸游','宋','宋诗','song-poetry','','[]','青帝宮中第一妃，寶香熏徹素綃衣。',32,'全唐诗/poet.song.129000.json','["青帝宮中第一妃，寶香熏徹素綃衣。", "定知謫墮不容久，萬斛玉塵来聘歸。"]'),
('2e2f71de-188e-493e-978d-f8dd0be22525','雪後尋梅偶得絕句十首  其三','陸游','宋','宋诗','song-poetry','','[]','銀燭檀槽醉海棠，老来非復錦城狂。',32,'全唐诗/poet.song.129000.json','["銀燭檀槽醉海棠，老来非復錦城狂。", "疏梅對影太清淡，爲拂焦桐彈履霜。"]'),
('b8db94ac-43c5-417b-a0e2-3e7d4f50c5c7','雪後尋梅偶得絕句十首  其四','陸游','宋','宋诗','song-poetry','','[]','雪裏芬芳亦偶然，世人便謂占春前。',32,'全唐诗/poet.song.129000.json','["雪裏芬芳亦偶然，世人便謂占春前。", "飽知桃李俗到骨，何至與渠爭著鞭。"]'),
('de1e0614-370e-40c0-8296-1505523b2fc7','雪後尋梅偶得絕句十首  其五','陸游','宋','宋诗','song-poetry','','[]','雙鵲飛来噪午晴，一枝梅影向窗横。',32,'全唐诗/poet.song.129000.json','["雙鵲飛来噪午晴，一枝梅影向窗横。", "幽人宿醉閑欹枕，不待聞香已觧酲。"]'),
('f516323a-6145-407a-8ef9-fbed15f96bf8','雪後尋梅偶得絕句十首  其六','陸游','宋','宋诗','song-poetry','','[]','竹籬曲曲水邊村，月澹霜清欲斷魂。',32,'全唐诗/poet.song.129000.json','["竹籬曲曲水邊村，月澹霜清欲斷魂。", "商略前身是飛燕，玉肌無粟立黄昏。"]'),
('5fc27d58-7025-4177-b1b5-d432fd43680a','雪後尋梅偶得絕句十首  其七','陸游','宋','宋诗','song-poetry','','[]','相逢未易可疏親，不是登牆宋玉鄰。',32,'全唐诗/poet.song.129000.json','["相逢未易可疏親，不是登牆宋玉鄰。", "林下風標許誰比，直須江左謝夫人。"]'),
('4d77dda3-82aa-4860-944c-a0758458d446','雪後尋梅偶得絕句十首  其八','陸游','宋','宋诗','song-poetry','','[]','春近山中日漸長，重重門崦閟幽香。',32,'全唐诗/poet.song.129000.json','["春近山中日漸長，重重門崦閟幽香。", "神仙不飲塵凡酒，素面看人醉後狂。"]'),
('636e3d42-7262-487a-a50b-ad5334b4123c','雪後尋梅偶得絕句十首  其九','陸游','宋','宋诗','song-poetry','','[]','蘂殿仙姝下界遊，偶来税駕剡溪頭。',32,'全唐诗/poet.song.129000.json','["蘂殿仙姝下界遊，偶来税駕剡溪頭。", "君看月裏横枝影，盡是蒼龍與翠虬。"]'),
('937231e4-5b1a-40a7-9b64-ee5d5b51cc1e','雪後尋梅偶得絕句十首  其一○','陸游','宋','宋诗','song-poetry','','[]','清霜夜夜奈寒何，賴是知心有素娥。',32,'全唐诗/poet.song.129000.json','["清霜夜夜奈寒何，賴是知心有素娥。", "枉道疏枝不禁笑，主人歡意自無多。"]'),
('ff49585a-5e00-4420-b265-f27c68b0a641','寄朱元晦提舉','陸游','宋','宋诗','song-poetry','','[]','市聚蕭條極，村墟凍餒稠。',48,'全唐诗/poet.song.129000.json','["市聚蕭條極，村墟凍餒稠。", "勸分無積粟，告糴未通流。", "民望甚饑渇，公行胡滯留。", "徴科得寛否，尚及麥禾秋。"]'),
('16d6a14b-6d14-4397-8014-f2b53c2623b5','村居冬日','陸游','宋','宋诗','song-poetry','','[]','溪轉樵風路，林藏禹會村。',48,'全唐诗/poet.song.129000.json','["溪轉樵風路，林藏禹會村。", "簷冰垂玉塔，山月涌金盆。", "畏客常稱疾，躭書不出門。", "尚嫌城市近，更擬卜雲根。"]'),
('47f1323d-6e6e-4143-a6d1-8eddf4251371','寓天慶觀有林使君年八十七方燒丹云一黍米大可化汞一斤爲黄金梅道人年八十五善醫','陸游','宋','宋诗','song-poetry','','[]','世路崎嶇久已忘，道腴禪悦度年光。',64,'全唐诗/poet.song.129000.json','["世路崎嶇久已忘，道腴禪悦度年光。", "故攜開士降龍鉢，来寄高人夢蝶床。", "只道燒金有劉向，不知賣藥是韓康。", "日長坐覺非塵世，庭檜花開蜂蜜香。"]'),
('8732e24a-3278-428c-aca2-0f0aeeb17b61','宿天慶道院','陸游','宋','宋诗','song-poetry','','[]','衰病厭多事，清遊諧夙心。',48,'全唐诗/poet.song.129000.json','["衰病厭多事，清遊諧夙心。", "夜深樓突兀，歲晚柏蕭森。", "汲井洗靈藥，焚香横素琴。", "身閑境自勝，城市亦山林。"]'),
('b16eb179-02e4-4370-b876-16b4409fc8e2','贈林使君二首  其一','陸游','宋','宋诗','song-poetry','','[]','使君物外閱年華，厭聽奴兵早暮衙。',64,'全唐诗/poet.song.129000.json','["使君物外閱年華，厭聽奴兵早暮衙。", "雙履踏雲呼野渡，一瓢邀月醉梅花。", "紅爐點汞閑消日，烏几繙經不憶家。", "我亦岷山有歸處，約君同載泝三巴。"]'),
('ab0d7dc9-403a-4899-8861-0e9423586b98','贈林使君二首  其二','陸游','宋','宋诗','song-poetry','','[]','松檜陰中百步廊，我来剝啄叩琳房。',64,'全唐诗/poet.song.129000.json','["松檜陰中百步廊，我来剝啄叩琳房。", "魚腸寶劍餘蛟血，鴉嘴金鋤带藥香。", "弱水蓬莱風浩浩，赤明龍漢劫茫茫。", "何妨付與神丹訣，敎跨青鸞到帝鄉。"]'),
('e489a9bd-5524-44f9-a7d0-50ee9b16e018','冬夜','陸游','宋','宋诗','song-poetry','','[]','窮巷蕭條早閉門，北窗燈火夜昏昏。',64,'全唐诗/poet.song.129000.json','["窮巷蕭條早閉門，北窗燈火夜昏昏。", "老于俗事不挂眼，愁憶故人空斷魂。", "急雪打窗飛礫細，狂風卷野怒濤翻。", "土床紙帳寒無寐，彊把村醅不厭渾。"]'),
('aa9d1942-5c64-4d58-8ca1-794727ada83a','宴坐','陸游','宋','宋诗','song-poetry','','[]','身窮寄山裏，心安一事無。',48,'全唐诗/poet.song.129000.json','["身窮寄山裏，心安一事無。", "新傳小止觀，漸觧半跏趺。", "急雪鳴窗紙，孤燈耿地爐。", "老来元少睡，且復兀枯株。"]'),
('e234bb11-2c61-4ff0-880b-49af7db6caab','夢中作','陸游','宋','宋诗','song-poetry','','[]','路平沙軟淨無泥，香草丰茸沒馬蹄。',32,'全唐诗/poet.song.129000.json','["路平沙軟淨無泥，香草丰茸沒馬蹄。", "擣紙聲中春日晚，怳然重到浣花溪。"]'),
('a802233c-cd2c-4744-b255-a099d8e82038','夜寒遣興','陸游','宋','宋诗','song-poetry','','[]','道人頽然寄北窗，愁魔百萬一笑降。',64,'全唐诗/poet.song.129000.json','["道人頽然寄北窗，愁魔百萬一笑降。", "夜闌酒渇有奇夢，吞楚七澤吴三江。", "孤村蕭蕭雨觧雪，寒犬噤臥饑鼠齧。", "擁衾危坐待天明，白首忍窮心似鐵。"]'),
('368a6d92-3fac-483e-ac8c-160b45044da9','雪後出遊戲作','陸游','宋','宋诗','song-poetry','','[]','小巘平岡雪陸離，幽人又賦探春詩。',64,'全唐诗/poet.song.129000.json','["小巘平岡雪陸離，幽人又賦探春詩。", "典琴沽酒元非俗，著屐觀碑又一奇。", "大度乾坤容落托，多情風月笑衰遲。", "吾生也似梅花淡，燕未歸来蝶不知。"]'),
('d2de9f74-715c-4848-b940-e003fc017b3a','歲暮','陸游','宋','宋诗','song-poetry','','[]','半生浪走跨秦吴，白首還如筮仕初。',64,'全唐诗/poet.song.129000.json','["半生浪走跨秦吴，白首還如筮仕初。", "凍芋濁醪邀里巷，昏烟濕雪暗郊墟。", "窮空敢恨寒無褐，憂患元因出有車。", "笑掩陳編聊自慰，古来冨貴羨樵漁。"]'),
('dd9450df-4ba1-4819-8743-ca4feacc75a2','記夢','陸游','宋','宋诗','song-poetry','','[]','世事紛紛觸眼新，何由常作夢中身。',64,'全唐诗/poet.song.129000.json','["世事紛紛觸眼新，何由常作夢中身。", "遠遊萬里纔移刻，豪飲千場不忤人。", "鼓吹滿城壺日晚，鶯花如海洞天春。", "是間可老君知否，莫信人言想與因。"]'),
('89c8d7bf-71cd-48f4-93e8-28f165b9ae5f','立春後三日作','陸游','宋','宋诗','song-poetry','','[]','拂面毿毿巷柳黄，穿簾細細野梅香。',64,'全唐诗/poet.song.129000.json','["拂面毿毿巷柳黄，穿簾細細野梅香。", "春回江表常年早，日向山中特地長。", "千古事終輸釣艇，一毫憂不到禪房。", "緑尊掩罷惟須睡，高枕看人舉世忙。"]'),
('b4652724-2e81-4608-87a5-447efb0ed596','短景','陸游','宋','宋诗','song-poetry','','[]','短景迫窮冬，日月如鳥過。',72,'全唐诗/poet.song.129000.json','["短景迫窮冬，日月如鳥過。", "衡門窘風雨，衰病不可那。", "疏疏屋茅漏，獵獵窗紙破。", "鼠豪冒燈出，人倦掩屏臥。", "中都舊朋儕，零落今幾箇。", "弄筆欲遣愁，孤吟誰與和。"]'),
('abe30ea3-3046-4074-8202-b6a9440fd14a','風雨旬日春後始晴','陸游','宋','宋诗','song-poetry','','[]','風吹過雁作斜行，雨洗殘梅只淡香。',64,'全唐诗/poet.song.129000.json','["風吹過雁作斜行，雨洗殘梅只淡香。", "南浦春回波漸綠，東庵睡起日初長。", "詩囊屬稿慚新思，博齒爭豪悔昔狂。", "莫向晴窗對明鏡，朱顔減盡鬢蒼蒼。"]'),
('36c9bb30-28ac-41b1-922f-7d40cfba1d7f','乍晴風日已和泛舟至扶桑埭徘徊西村久之','陸游','宋','宋诗','song-poetry','','[]','十日風雨今日晴，衰病忽減思閑行。',96,'全唐诗/poet.song.129000.json','["十日風雨今日晴，衰病忽減思閑行。", "接䍦一幅烟霧薄，舴艋八尺鳬鷖輕。", "亭亭孤塔遠天碧，曲曲深巷斜陽明。", "數家茅屋門晝掩，不聞人聲聞碓聲。", "身似龐公不入城，東阡南陌餞餘生。", "新年倘有豐年喜，買酒漁村看太平。"]'),
('408b2e16-f23d-4cd5-8101-91f3725c1032','晨起南窗晴日可愛戲作一絕','陸游','宋','宋诗','song-poetry','','[]','蕭散山林一幅巾，天公乞與自由身。',32,'全唐诗/poet.song.129000.json','["蕭散山林一幅巾，天公乞與自由身。", "茅簷不似宮塼暖，日滿南窗也可人。"]'),
('bb696958-5f2e-433f-842c-c00657ccae37','攜癭尊醉梅花下','陸游','宋','宋诗','song-poetry','','[]','楠癭作尊容斗許，擁腫輪囷元媚嫵。',128,'全唐诗/poet.song.129000.json','["楠癭作尊容斗許，擁腫輪囷元媚嫵。", "肻從放翁来住山，誰云置身不得所。", "山房寂寞久不飲，作意欲就梅花語。", "我病鮮歡花更甚，日暮凄涼泣殘雨。", "人生萬事雲茫茫，一醉常恐俗物妨。", "正須仙人冰雪膚，来伴老子鐵石腸。", "花前起舞花底臥，花影漸東山月墮。", "癭尊未竭狂未休，笑起題詩識吾過。"]'),
('e6a4695e-8826-4a9f-877e-0e00fb87d002','城西接待院後竹下作','陸游','宋','宋诗','song-poetry','','[]','水邊小丘因古城，上有巨竹數百箇。',96,'全唐诗/poet.song.129000.json','["水邊小丘因古城，上有巨竹數百箇。", "一徑蛇蟠不容脚，平處乃可十客坐。", "裊裊共看風枝舞，簌簌時聽春籜墮。", "古佛不粧香火冷，瘦僧如腊袈裟破。", "門前西去長安路，日夜舳艫衘尾過。", "老夫本乏臺省姿，且就清陰曲肱臥。"]'),
('47ae8101-88a8-4e2b-a41a-724d7227c695','夜飲示坐中','陸游','宋','宋诗','song-poetry','','[]','胡雁叫群寒夜長，崢嶸北斗天中央。',64,'全唐诗/poet.song.129000.json','["胡雁叫群寒夜長，崢嶸北斗天中央。", "達人大觀眇萬物，烈士壯心懷四方。", "縱酒長鯨渇吞海，草書瘦蔓飽經霜。", "付君詩卷好收拾，後五百年無此狂。"]'),
('623abc3f-09dd-48b7-bfc6-4f911433a743','夜從父老飲酒村店作','陸游','宋','宋诗','song-poetry','','[]','旗亭濁酒典衣沽，蠏舍老翁折簡呼。',64,'全唐诗/poet.song.129000.json','["旗亭濁酒典衣沽，蠏舍老翁折簡呼。", "夜中醉歸騎草驢，嵬昻不須宗武扶。", "丹徒布衣有籌略，漁陽突騎莫枝梧。", "床頭金盡何足道，肝膽輪囷横九區。"]'),
('60b94b95-77da-49b9-8a1d-85111c6bd8d4','壬寅新春','陸游','宋','宋诗','song-poetry','','[]','半生常是道邊人，歲晚初收事外身。',64,'全唐诗/poet.song.129000.json','["半生常是道邊人，歲晚初收事外身。", "濁酒一杯聊永日，小園三畝亦新春。", "尚無枕寄邯鄲夢，那有衣沾京洛塵。", "門外烟波三百里，此心惟與白鷗親。"]'),
('1ca58894-4478-49e9-ae70-c2afc1e801c2','幽居春夜','陸游','宋','宋诗','song-poetry','','[]','暮景催人雪鬢雙，十年始復反吾邦。',64,'全唐诗/poet.song.129000.json','["暮景催人雪鬢雙，十年始復反吾邦。", "雲逢佳月每避舍，酒壓閑愁如受降。", "三弄笛聲初到枕，一枝梅影正横窗。", "要知清夢遊何許，不釣桐江即錦江。"]'),
('eed53823-1990-436d-84c2-3ccdad04c223','讀書','陸游','宋','宋诗','song-poetry','','[]','放翁白首歸剡曲，寂寞衡門書滿屋。',112,'全唐诗/poet.song.129000.json','["放翁白首歸剡曲，寂寞衡門書滿屋。", "藜羮麥飯冷不嘗，要足平生五車讀。", "校讎心苦謹塗乙，吟諷聲悲雜歌哭。", "三蒼奇字已殺青，九譯旁行方著錄。", "有時達旦不滅燈，急雪打窗聞簌簌。", "倘年七十尚一紀，墜典斷編真可續。", "客来不怕笑書癡，終勝牙籖新未觸。"]'),
('6005812d-bfad-47b7-a983-c10da0070387','晨起','陸游','宋','宋诗','song-poetry','','[]','小雨濕清曉，新鶯啼早春。',48,'全唐诗/poet.song.129000.json','["小雨濕清曉，新鶯啼早春。", "年光驚病眼，節物屬閑身。", "巴硤東連楚，嶓山北控秦。", "遠遊端可繼，敢恨素衣塵。"]'),
('a19e3c09-8524-4622-b8e7-ca00ee522268','昔在成都正月七日聖壽寺麻子市初春行樂處也偶晨興聞鄰村守麻有感','陸游','宋','宋诗','song-poetry','','[]','樂事新年入錦城，城南麻市試春行。',32,'全唐诗/poet.song.129000.json','["樂事新年入錦城，城南麻市試春行。", "如今老病茅簷底，臥聽兒童嚇雀聲。"]'),
('0c81e0fb-1c15-4214-8af0-6c1d32d45326','獨孤生策字景略河中人工文善射喜擊劍一世奇士也有自峽中来者言其死于忠涪間感涕賦詩','陸游','宋','宋诗','song-poetry','','[]','憶昨騎驢入蜀關，旗亭邂逅一開顔。',64,'全唐诗/poet.song.129000.json','["憶昨騎驢入蜀關，旗亭邂逅一開顔。", "氣鍾太華中條秀，文在先秦兩漢間。", "寶劍憑誰占斗氣，名駒竟失養天閑。", "身今老病投空谷，回首東風涕自澘。"]'),
('6e628717-4335-4e7f-8445-234c62cfbec5','早春對酒感懷','陸游','宋','宋诗','song-poetry','','[]','探花疇昔喜春回，老大空驚節物催。',64,'全唐诗/poet.song.129000.json','["探花疇昔喜春回，老大空驚節物催。", "芳瓮旋開新壓酒，好枝猶把未殘梅。", "書生歲惡甘藜莧，志士時平死草莱。", "欲豁孤懷誰晤語，夜彈長劍有餘哀。"]'),
('6c08aec3-9a18-4fcf-8123-6adec2d6021f','曉出湖邊摘野蔬','陸游','宋','宋诗','song-poetry','','[]','浩歌振履出茅堂，翠蔓丹芽采擷忙。',64,'全唐诗/poet.song.129000.json','["浩歌振履出茅堂，翠蔓丹芽采擷忙。", "且勝堆盤供苜蓿，未言滿斛進檳榔。", "行迎風露衣巾爽，淨洗羶葷匕筯香。", "著句誇張君勿笑，故人方厭太官羊。"]'),
('39fa8646-d851-4e98-b69e-1f324bc35fa8','洊饑之餘復苦久雨感嘆有作','陸游','宋','宋诗','song-poetry','','[]','道傍襁負去何之，積雨仍愁麥不支。',64,'全唐诗/poet.song.129000.json','["道傍襁負去何之，積雨仍愁麥不支。", "爲國憂民空激烈，殺身報主已差池。", "屬饜糠麧猶多愧，徙倚柴荆只自悲。", "十載西遊無惡歲，羨他村野足蹲鴟。"]'),
('9c17e809-fe45-4c66-9c5b-4b5a02cdbe87','春晴泛舟','陸游','宋','宋诗','song-poetry','','[]','兒童莫笑是陳人，湖海春回發興新。',64,'全唐诗/poet.song.129000.json','["兒童莫笑是陳人，湖海春回發興新。", "雷動風行驚蟄戸，天開地闢轉鴻鈞。", "鱗鱗江色漲石黛，嫋嫋柳絲揺麴塵。", "欲上蘭亭却回棹，笑談終覺愧清真。"]'),
('b9b447a7-ba73-46bf-aae9-a8df0c341bcb','攜一尊尋春湖上','陸游','宋','宋诗','song-poetry','','[]','酒裏真須勉策勳，百年何啻是中分。',64,'全唐诗/poet.song.129000.json','["酒裏真須勉策勳，百年何啻是中分。", "花梢已點猩猩血，水面初生瑟瑟紋。", "一世極知均腐骨，萬鍾元自付浮雲。", "浩歌不恨無人和，但惜驚飛白鷺群。"]'),
('6fc088dd-ba3b-470e-8410-bd7fc2590c8a','晦前二日夜欲曉自湖上歸對殘月獨酌','陸游','宋','宋诗','song-poetry','','[]','小閣對寒蟾，山尊盡更添。',48,'全唐诗/poet.song.129000.json','["小閣對寒蟾，山尊盡更添。", "方看一輪滿，又嘆兩頭纖。", "脉脉離雲嶠，姢姢傍畫簷。", "五更清露下，不恨客衣霑。"]'),
('4c5d05a5-744f-4055-a7b3-98f9be4ae205','春曉有感','陸游','宋','宋诗','song-poetry','','[]','山杏溪桃續續開，緩歌誰與共傳杯。',32,'全唐诗/poet.song.129000.json','["山杏溪桃續續開，緩歌誰與共傳杯。", "年来只有追歡夢，百舌無情又喚回。"]'),
('53ff5999-e341-4f00-ab26-6ece33b5d530','夜觀秦蜀地圖','陸游','宋','宋诗','song-poetry','','[]','往者行省臨秦中，我亦急服叨從戎。',160,'全唐诗/poet.song.129000.json','["往者行省臨秦中，我亦急服叨從戎。", "散關摩雲俯賊壘，清渭如带陳軍容。", "高旌縹緲嚴玉帳，畫角悲壯傳霜風。", "咸陽不勞三日到，幽州正可一炬空。", "意氣已無雞鹿塞，單于合入蒲萄宮。", "燈前此圖忽到眼，白首流落悲塗窮。", "吾皇英武同世祖，諸將行策雲臺功。", "孤臣昧死欲自薦，君門萬里無由通。", "正令選壯不爲用，筆墨尚可輸微忠。", "何當勒銘紀北伐，更擬草奏祈東封。"]'),
('a442a0a5-a086-466b-9740-860c56070dfe','久雨小飲','陸游','宋','宋诗','song-poetry','','[]','春来日日風雨横，老去時時衰病攻。',64,'全唐诗/poet.song.129000.json','["春来日日風雨横，老去時時衰病攻。", "門外回塘初漲緑，尊前槁面蹔生紅。", "未除豪氣每自笑，欲吐狂言無與同。", "安得并刀剪簷溜，憑高萬里望晴空。"]'),
('cc81256c-87fb-4c14-b3f8-c88810267f54','有懷獨孤景略','陸游','宋','宋诗','song-poetry','','[]','富貴世間元不乏，此君才大獨難成。',64,'全唐诗/poet.song.129000.json','["富貴世間元不乏，此君才大獨難成。", "喑嗚意氣千人廢，嫻雅風流一座傾。", "韜略豈勞平大敵，文章亦足主齊盟。", "荒山野水涪州路，腸斷西風薤露聲。"]'),
('7695c783-2745-4728-8ec9-66b828ec80fc','春雨復寒遣懷','陸游','宋','宋诗','song-poetry','','[]','去日堂堂挽不回，新年又傍鬢邊来。',64,'全唐诗/poet.song.129000.json','["去日堂堂挽不回，新年又傍鬢邊来。", "雨聲欲作海棠祟，書卷只爲春睡媒。", "村舍瘦蔬供薄酒，地爐微火伴殘灰。", "浩然忽起金鞭興，漾水嶓山安在哉。"]'),
('256311eb-aa91-4954-8724-17306414c839','春遊','陸游','宋','宋诗','song-poetry','','[]','平生樂行役，不耐常閉户。',96,'全唐诗/poet.song.129000.json','["平生樂行役，不耐常閉户。", "今朝新雨霽，一笑整巾屨。", "青猿導幽蹊，春草伴微步。", "雖云尊酒薄，蔬果亦略具。", "辛夷發高枝，楊柳吹墮絮。", "行歌不知遠，落日呼野渡。", "横林已棲鴉，淺水猶立鷺。", "歸来意頗豪，古錦有新句。"]'),
('e1306df4-c685-4d5d-b6f1-0066bbccfb5f','海棠','陸游','宋','宋诗','song-poetry','','[]','今日春已半，風雨停出遊。',120,'全唐诗/poet.song.129000.json','["今日春已半，風雨停出遊。", "缾中海棠花，數酌相獻酬。", "尚想錦官城，花時樂事稠。", "金鞭過南市，紅燭宴西樓。", "千林誇盛麗，一枝賞纖柔。", "狂吟恨未工，爛醉死即休。", "那知茅簷底，白髮見花愁。", "花亦如病姝，掩抑向客羞。", "尤物終動人，要非桃杏儔。", "東風萬里恨，浩蕩不可收。"]'),
('4902f520-0404-40ba-8db4-fb0f5aec7b3f','寄仗錫平老借用其聽琴詩韵','陸游','宋','宋诗','song-poetry','','[]','放翁久矣無此客，闖户兒童皆動色。',128,'全唐诗/poet.song.129000.json','["放翁久矣無此客，闖户兒童皆動色。", "寒泉不食人暍死，素綆銀瓶我心惻。", "千金易得一士難，晚途淹泊眼愈寒。", "豈知一旦乃見子，傑語豪筆無僧酸。", "門前清溪天作底，細細風吹縠紋起。", "倚欄一笑誰得知，愛子數詩如此水。", "江湖安得常相從，浩歌相踏臥短篷。", "功名渠自有人了，留我鏡中雙頰紅。"]'),
('149fe9cc-d4e9-4b8d-97dd-96c579678f8d','五月十四日夜夢一僧持詩編過予有暴雨詩語頗壯予欣然和之聮巨軸欲書未落筆而覺追作此篇','陸游','宋','宋诗','song-poetry','','[]','黑雲塞空萬馬屯，轉盼白雨如傾盆。',96,'全唐诗/poet.song.129000.json','["黑雲塞空萬馬屯，轉盼白雨如傾盆。", "狂風疾雷撼乾坤，壯哉澗壑相吐吞。", "老龍騰拏下天閽，鱗間火作電脚奔。", "巨松拔起千年根，浮槎斷梗何足論。", "我詩欲成醉墨翻，安得此雨洗中原。", "長河衮衮来崑崙，鸛鵲下看黄流渾。"]'),
('70338ae7-842a-4fde-8a18-255078813149','新塘觀月','陸游','宋','宋诗','song-poetry','','[]','攜酒新塘南，中夜欲忘歸。',72,'全唐诗/poet.song.129000.json','["攜酒新塘南，中夜欲忘歸。", "貪看月滿湖，不覺露濕衣。", "天高鶴聲厲，風急螢火稀。", "此夕不一醉，行嘆破鏡飛。", "漁家亦喜事，未掩水際扉。", "皇天有公道，處處皆清暉。"]'),
('d27efe13-458d-4f11-be81-3d6a8d47685d','觀張提刑周鼎','陸游','宋','宋诗','song-poetry','','[]','他人冨貴堆金璧，曼舞妖歌誇坐客。',128,'全唐诗/poet.song.129000.json','["他人冨貴堆金璧，曼舞妖歌誇坐客。", "清心好古誰似公，漢庭諸人推博識。", "一朝得此周廟器，買不論貲空四壁。", "苔痕洗盡銅色見，坐臥摩挲欲忘食。", "蠻童捧出客爲起，恍如清廟陪劍履。", "腹中奇字粲蟲魚，嶧山之碑那得比。", "知公原是功名人，看罷握手同悲辛。", "鎬京洛邑在何許，漠漠秋風吹戰塵。"]'),
('07d3a611-ad97-47b7-bea0-350148726874','口占送巖師還大梅護聖','陸游','宋','宋诗','song-poetry','','[]','放翁白髮已蕭然，黄紙新除玉局仙。',32,'全唐诗/poet.song.129000.json','["放翁白髮已蕭然，黄紙新除玉局仙。", "寄語山頭老師叔，欲分茅舍度殘年。"]'),
('83a94b13-a8b1-47a4-bb1a-5513d493d3c1','八月十四日夜湖山觀月','陸游','宋','宋诗','song-poetry','','[]','長空露洗玻璃碧，紫金之盤徑三尺。',96,'全唐诗/poet.song.129000.json','["長空露洗玻璃碧，紫金之盤徑三尺。", "忽看擘地出人間，桂樹扶疏如淡墨。", "攬衣獨立鏡湖邊，風露萬頃秋渺然。", "開帆詎必入東海，騎鯨便可追飛仙。", "冰壺玉瀣侵骨冷，醉看孤鸞舞清影。", "夜闌歸舍人已眠，却倩天風爲吹醒。"]'),
('f3e12827-8eee-48cc-bcb9-04edc54cb125','十五夜月色皦然有頃雲生遂不復見','陸游','宋','宋诗','song-poetry','','[]','北望但空濶，南望横群山。',92,'全唐诗/poet.song.129000.json','["北望但空濶，南望横群山。", "青天無翳行素月，寥寥永夜非人間。", "九醞漿成老仙醉，六銖衣薄天宮寒。", "翠眉真人不火食，小立環佩風珊珊。", "横空邀我海山去，縹緲萬里驂青鸞。", "相攜一笑在雲表，徐看玉宇飛金盤。"]'),
('898ce6cd-66db-47f0-876c-bc3572f8b8d1','夜聞秋風感懷','陸游','宋','宋诗','song-poetry','','[]','西風一夜號庭樹，起攬戎衣泪濺襟。',64,'全唐诗/poet.song.129000.json','["西風一夜號庭樹，起攬戎衣泪濺襟。", "殘角聲催關月墮，斷鴻影隔塞雲深。", "數篇零落從軍作，一寸凄涼報國心。", "莫倚壯圖思冨貴，英豪何限死山林。"]'),
('46f21f05-0ffb-4c9b-ac51-b4aa20ab2c51','玉局歌','陸游','宋','宋诗','song-poetry','','[]','玉局祠官殊不惡，衘如冰清俸如鶴。',98,'全唐诗/poet.song.129000.json','["玉局祠官殊不惡，衘如冰清俸如鶴。", "酒壺釣具常自隨，五尺新篷織青篛。", "倚樓看鏡待功名，半世兒癡晚方覺。", "何如醉裏泛桐江，長笛一聲吹月落。", "蔣公新冢石馬高，謝公飛旐凌秋濤。", "微霜莫遣侵鬢綠，從今二十四考書玉局。"]'),
('7f0ffb14-fb28-46ad-87c9-4d10d4fa2eb2','醉歌','陸游','宋','宋诗','song-poetry','','[]','往時一醉論斗石，坐人飲水不能敵。',128,'全唐诗/poet.song.129000.json','["往時一醉論斗石，坐人飲水不能敵。", "横戈擊劍未足豪，落筆縱横風雨疾。", "雪中會獵南山下，清曉嶙峋玉千尺。", "道邊狐兔何曾問，馳過西村尋虎跡。", "貂裘半脫馬如龍，舉鞭指麾氣吐虹。", "不須分弓守近塞，傳檄可使腥膻空。", "小冦逋誅六十載，狺狺猘子勢已窮。", "聖朝好生貸孥戮，還爾舊穴去天東。"]'),
('578e3a62-1b57-4d0f-ba62-7298f59eb37e','閉門','陸游','宋','宋诗','song-poetry','','[]','寂寂雲山千萬重，閉門不忍嘆塗窮。',64,'全唐诗/poet.song.129000.json','["寂寂雲山千萬重，閉門不忍嘆塗窮。", "高秋酒熟雪浮瓮，中夜劍歸雷吼空。", "近報冦戎迯漠北，豈無貔虎定關中。", "君王猶記孤忠在，安得英豪共此功。"]'),
('28b94e37-5699-44f1-930a-7b9bb4b1cd52','草書歌','陸游','宋','宋诗','song-poetry','','[]','傾家釀酒三千石，閑愁萬斛酒不敵。',96,'全唐诗/poet.song.129000.json','["傾家釀酒三千石，閑愁萬斛酒不敵。", "今朝醉眼爛巖電，提筆四顧天地窄。", "忽然揮掃不自知，風雲入懷天借力。", "神龍戰野昏霧腥，奇鬼摧山太陰黑。", "此時驅盡胸中愁，槌床大叫狂墮幘。", "吴牋蜀素不快人，付與高堂三丈壁。"]'),
('174d0d94-802b-4175-88a9-4d3b66c38e1a','野飲夜歸戲作','陸游','宋','宋诗','song-poetry','','[]','青海天山戰未鏖，即今塵暗舊戎袍。',64,'全唐诗/poet.song.129000.json','["青海天山戰未鏖，即今塵暗舊戎袍。", "風高乍覺弓聲勁，霜冷初增酒興豪。", "未辦大名垂宇宙，空成慟哭向蓬蒿。", "灞亭老將歸常夜，無奈人間兒女曹。"]'),
('a292c8ff-4eb7-46b0-af9c-70537fc33f2b','夜泊水村','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u611f\u53f9", "\u5c81\u6708", "\u58ee\u5fd7"]','腰間羽箭久凋零，太息燕然未勒銘。',64,'全唐诗/poet.song.129000.json','["腰間羽箭久凋零，太息燕然未勒銘。", "老子猶堪絕大漠，諸君何至泣新亭。", "一身報國有萬死，雙鬢向人無再青。", "記取江湖泊船處，臥聞新雁落寒汀。"]'),
('31dab238-1167-4afb-83e8-d9a5c955d824','幽居','陸游','宋','宋诗','song-poetry','','[]','遶屋巉巉碧玉峰，箇中天遣養疏慵。',64,'全唐诗/poet.song.129000.json','["遶屋巉巉碧玉峰，箇中天遣養疏慵。", "捐書已嘆空虛腹，得酒還澆壘塊胸。", "曲几坐看窺戸月，短篷臥聽隔城鐘。", "柴桑自有歸来意，枉道人間不見容。"]'),
('4c42f46d-7fbf-4f87-bdd1-7a1b9eb6dd2c','與鄰翁登山亭','陸游','宋','宋诗','song-poetry','','[]','數掩槿籬圍夕照，一間茅舍背陰崖。',64,'全唐诗/poet.song.129000.json','["數掩槿籬圍夕照，一間茅舍背陰崖。", "吾生擾擾實無樂，人事悠悠那可諧。", "憂患向来侵綠鬢，登臨此日費青鞋。", "京華舊友凋零盡，野老逢迎一散懷。"]'),
('5b157bae-75ee-4ac8-b624-5279d14337c5','無題','陸游','宋','宋诗','song-poetry','','[]','轣轆氊車赴密期，追歡最數牡丹時。',64,'全唐诗/poet.song.129000.json','["轣轆氊車赴密期，追歡最數牡丹時。", "新春欲近猶貪喜，舊愛濳移不自知。", "寶鏡塵生鸞悵望，鈿箏弦絕雁參差。", "玉壺莫貯臙脂泪，從濕泥金带上詩。"]'),
('372b2916-313c-45c0-b399-90abfd5a6f32','遣興','陸游','宋','宋诗','song-poetry','','[]','平生與俗馬牛風，落魄人間亦未窮。',64,'全唐诗/poet.song.129000.json','["平生與俗馬牛風，落魄人間亦未窮。", "綠綺奏終香縷碧，烏絲書罷燭花紅。", "夢中吴蜀山川近，醉後周秦戰伐空。", "投老飄然君勿笑，也勝魚鳥在池籠。"]'),
('ad5d252e-3ce7-4532-916a-e5248eae381f','夢宴客大樓上命筆作詩既覺續成之','陸游','宋','宋诗','song-poetry','','[]','表裏江山亦樂哉，華纓滿座敵鄒枚。',64,'全唐诗/poet.song.129000.json','["表裏江山亦樂哉，華纓滿座敵鄒枚。", "歌從郢客樓中聽，獵向樊姬墓上回。", "梅蘂香清篸寶髻，熊蹯味美按新醅。", "眼邊歴歴興亡事，欲賦章華恐過哀。"]'),
('26a5afa6-9472-46e9-a106-1e43a2437670','新塘夜歸','陸游','宋','宋诗','song-poetry','','[]','烟月茫茫十里堤，數聲漁唱埭東西。',32,'全唐诗/poet.song.129000.json','["烟月茫茫十里堤，數聲漁唱埭東西。", "旋燒新兔傾村酒，扶得歸来醉似泥。"]'),
('a7365440-cc72-4bee-8d42-7cd863eb2f9e','古風三首  其一','陸游','宋','宋诗','song-poetry','','[]','少年暮黄老，雅志在山林。',72,'全唐诗/poet.song.129000.json','["少年暮黄老，雅志在山林。", "火食亦彊勉，寧有婚宦心。", "失脚墮世網，衰病忽侵尋。", "放逐適天幸，獨恨山未深。", "一床元不睡，翛然横素琹。", "開門毛髮冷，湖濶月欲沈。"]'),
('5f2525ad-a18f-4097-945c-4bb7db4d7956','古風三首  其二','陸游','宋','宋诗','song-poetry','','[]','賀監未嘗死，江天醉初醒。',72,'全唐诗/poet.song.129000.json','["賀監未嘗死，江天醉初醒。", "逸少亦度世，弭節過蘭亭。", "吾本淡蕩人，轉徙如蓬萍。", "聊憑一杯綠，駐此雙鬢青。", "邂逅兩仙翁，笙鶴遊青冥。", "還家不能食，濁世紛羶腥。"]'),
('e8d124a8-a6b0-4839-a55f-58d40571a392','古風三首  其三','陸游','宋','宋诗','song-poetry','','[]','功名如博戲，大叫或作盧。',72,'全唐诗/poet.song.129000.json','["功名如博戲，大叫或作盧。", "文辭組繡耳，初不繫賢愚。", "負恃已可笑，憎嫉真區區。", "平生學金丹，我豈斯人徒。", "嘯歌醉自和，顔鬢老不枯。", "却後五百年，烟雨釣鏡湖。"]'),
('74eb4f5c-9202-4397-93da-053a623c723c','累日無酒亦不肉食戲作此詩','陸游','宋','宋诗','song-poetry','','[]','小築精廬剡曲傍，枵然蟬腹與龜腸。',64,'全唐诗/poet.song.129000.json','["小築精廬剡曲傍，枵然蟬腹與龜腸。", "酒錢覓處無司業，齋日多来似太常。", "雲碓旋舂菰米滑，風爐親候藥苖香。", "明年更入南山去，要試囊中服玉方。"]'),
('ac56cb13-ef39-4a5d-90b4-5d3f9cf19aa6','讀書','陸游','宋','宋诗','song-poetry','','[]','讀書四更燈欲盡，胸中太華蟠千仞。',131,'全唐诗/poet.song.129000.json','["讀書四更燈欲盡，胸中太華蟠千仞。", "仰呼青天那得聞，窮到白頭猶自信。", "策名委質本爲國，豈但空取黄金印。", "故都即今不忍說，空宮夜夜飛秋燐。", "士初許身輩稷契，歲晚所立慚廉藺。", "正看憤切詭成功，已復雍容託觀釁。", "雖然知人要未易，詎可例輕天下士。", "君不見長松臥壑困風霜，時来屹立扶明堂。"]'),
('178b1d33-d05c-4ca1-a215-f38e3d39bdfa','自妙相歸將至杜浦堰舟中作','陸游','宋','宋诗','song-poetry','','[]','斜陽發東郭，初夜轉西城。',48,'全唐诗/poet.song.129000.json','["斜陽發東郭，初夜轉西城。", "寺閣疏鐘動，漁村遠火明。", "蒼茫林靄滅，撲漉水禽驚。", "漸喜吾廬近，遥聞過埭聲。"]'),
('adbf0141-4c90-42ba-a945-f16011039485','秋興','陸游','宋','宋诗','song-poetry','','[]','樵風溪上弄扁舟，濯錦江邊憶舊遊。',64,'全唐诗/poet.song.129000.json','["樵風溪上弄扁舟，濯錦江邊憶舊遊。", "豪竹哀絲真昨夢，爽砧繁杵又驚秋。", "墜枝橘熟初堪剪，浮瓮醅香恰受篘。", "莫道身閑總無事，孤燈夜夜寫清愁。"]'),
('6f88630e-917e-4cc2-bf6a-c07a0114341d','哀北','陸游','宋','宋诗','song-poetry','','[]','太行天下脊，黄河出崑崙。',96,'全唐诗/poet.song.129000.json','["太行天下脊，黄河出崑崙。", "山川形勝地，歴世多名臣。", "哀哉六十年，左衽淪胡塵。", "抱負雖奇偉，没齒不得伸。", "老夫實好義，北望常酸辛。", "何當擁黄旗，徑涉白馬津。", "窮追殄犬羊，旁招出鳳麟。", "努力待傳檄，勿謂吳無人。"]'),
('8947a2fc-ffa0-4744-84d0-b5e28784c836','琵琶','陸游','宋','宋诗','song-poetry','','[]','西蜀琵琶邏逤槽，梨園舊譜鬱輪袍。',32,'全唐诗/poet.song.129000.json','["西蜀琵琶邏逤槽，梨園舊譜鬱輪袍。", "繡筵銀燭燕宮夜，一飲千鍾未足豪。"]'),
('e7367653-1c91-4474-9b4f-aff6c2c956b5','三江舟中大醉作','陸游','宋','宋诗','song-poetry','','[]','志欲冨天下，一身常苦饑。',96,'全唐诗/poet.song.129000.json','["志欲冨天下，一身常苦饑。", "氣可吞匈奴，束带向小兒。", "天公無由問，世俗那得知。", "揮手散醉髮，去隱雲海涯。", "風息天鏡平，濤起雪山傾。", "輕帆入浩蕩，百怪不可名。", "虹竿秋月鈎，巨鰲倘可求。", "滅迹從今逝，回看隘九州。"]'),
('dc6c549e-82e5-4852-88a8-25474f441f97','短歌行','陸游','宋','宋诗','song-poetry','','[]','百年鼎鼎世共悲，晨鐘暮鼓無休時。',96,'全唐诗/poet.song.129000.json','["百年鼎鼎世共悲，晨鐘暮鼓無休時。", "碧桃紅杏易零落，翠眉玉頰多别離。", "涉江采菱風敗意，登樓待月雲爲祟。", "功名常畏謗讒興，冨貴毎同衰病至。", "人生可嘆十八九，自古危機無妙手。", "正令插翮上青雲，不如得錢即沽酒。"]'),
('27243208-96b7-4c42-b4c7-6ec6b9bcb1e6','悲秋','陸游','宋','宋诗','song-poetry','','[]','秋燈如孤螢，熠熠耿窗户。',72,'全唐诗/poet.song.129000.json','["秋燈如孤螢，熠熠耿窗户。", "秋雨如漏壺，點滴連早暮。", "我豈楚逐臣，慘愴出怨句。", "逢秋未免悲，直以憂國故。", "三軍老不戰，比屋困征賦。", "可使江淮間，歲歲常列戍。"]'),
('339103e2-69c5-40fc-ba16-554d237221e7','步至西村','陸游','宋','宋诗','song-poetry','','[]','一飽無餘事，西村偶獨行。',48,'全唐诗/poet.song.129000.json','["一飽無餘事，西村偶獨行。", "榰笻息微倦，汲井潄餘酲。", "川濶雁平度，谷虛雲亂生。", "絕知豐歲樂，笑語隔柴荆。"]'),
('bf9ba4ce-4820-452b-b60b-e6ae8bfc782c','題接待院壁','陸游','宋','宋诗','song-poetry','','[]','笙歌凄咽離亭晚，回首高城半掩門。',64,'全唐诗/poet.song.129000.json','["笙歌凄咽離亭晚，回首高城半掩門。", "疉疉遠山横翠靄，姢姢新月耿黄昏。", "未嫌雙櫓妨欹枕，自是孤舟易斷魂。", "遥想柯橋落帆處，隔江微火認漁村。"]'),
('b5e3c1e8-b4d4-4ac9-a346-d45490cb0620','九月晦日作四首  其一','陸游','宋','宋诗','song-poetry','','[]','菊枝傾倒不成叢，桐葉凋零已半空。',32,'全唐诗/poet.song.129000.json','["菊枝傾倒不成叢，桐葉凋零已半空。", "自是老来多感慨，不應蕭瑟爲秋風。"]'),
('eab1506f-e0d9-4dbf-8a79-0daad4d1ebcb','九月晦日作四首  其二','陸游','宋','宋诗','song-poetry','','[]','山路清寒近探梅，振衣高處興悠哉。',32,'全唐诗/poet.song.129000.json','["山路清寒近探梅，振衣高處興悠哉。", "飛鴻杳杳江天濶，一片愁從萬里来。"]'),
('df623cae-07ec-478e-bc08-633ba1a83031','九月晦日作四首  其三','陸游','宋','宋诗','song-poetry','','[]','錦城誰與寄音塵，望斷秋江六六鱗。',32,'全唐诗/poet.song.129000.json','["錦城誰與寄音塵，望斷秋江六六鱗。", "正使傾家供麴蘖，定知不解醉愁人。"]'),
('48ae3c36-09a4-4838-ba7e-14233aac196e','九月晦日作四首  其四','陸游','宋','宋诗','song-poetry','','[]','炊烟漠漠衡門寂，寒日昏昏倦鳥還。',32,'全唐诗/poet.song.129000.json','["炊烟漠漠衡門寂，寒日昏昏倦鳥還。", "數樹丹楓映蒼檜，天工觧作范寛山。"]'),
('c08899c8-875b-4eab-a9a9-158fc2574b0f','陶山遇雪覺林遷庵主見招不果往','陸游','宋','宋诗','song-poetry','','[]','山中大雪二尺彊，道邊虎跡如椀大。',64,'全唐诗/poet.song.129000.json','["山中大雪二尺彊，道邊虎跡如椀大。", "衰翁畏虎復畏寒，招喚不来公勿怪。", "梨花開時好風日，走馬尋公作寒食。", "不須沽酒飲陶濳，箭筍蕨芽如蜜甜。"]'),
('6bb6cc59-5022-4cb9-bc3f-0b7e080fce1c','哭王季夷','陸游','宋','宋诗','song-poetry','','[]','超遥天馬渥洼来，萬里修途忍勒回。',64,'全唐诗/poet.song.129000.json','["超遥天馬渥洼来，萬里修途忍勒回。", "爽氣即今猶可想，舊遊何處不堪哀。", "夢中有客徴殘錦，地下無爐鑄横財。", "欲酹一尊身尚病，鬛封春露濕蒼苔。"]'),
('c3976ee6-d3d1-4ea1-8b74-b25683c62072','樊江晚泊','陸游','宋','宋诗','song-poetry','','[]','碧雲吞日天欲暮，城西捩柁城東路。',64,'全唐诗/poet.song.129000.json','["碧雲吞日天欲暮，城西捩柁城東路。", "蓴羮菰飯香滿船，正是江頭落帆處。", "荻洲漁火遠更明，烟水蒼茫聞雁聲。", "不是綠尊能破悶，白頭客路若爲情。"]'),
('0cbbf594-0357-4f88-b7d2-4a30607fa26f','蛾眉村旅舍作','陸游','宋','宋诗','song-poetry','','[]','小雨初收景氣和，青苔狼藉落梅多。',64,'全唐诗/poet.song.129000.json','["小雨初收景氣和，青苔狼藉落梅多。", "曲肱野店睡斜日，濯足溪橋鳴細波。", "久厭俗情生眼白，近承天詔賜顔酡。", "騎鯨未返蓬壺去，此路猶須幾浩歌。"]'),
('ac55b8fc-7948-43d5-b05d-e49b3620291e','娥江野飲贈劉道士','陸游','宋','宋诗','song-poetry','','[]','春光盎盎催官柳，柳色黄如醆中酒。',96,'全唐诗/poet.song.129000.json','["春光盎盎催官柳，柳色黄如醆中酒。", "橋邊微逕愜幽尋，世外高人共攜手。", "參差茅舍出木末，隱映酒旗當浦口。", "插花處處引村童，失道時時問耕叟。", "客堪共醉百無一，事不諧心十常九。", "日斜潮落不可留，孤舟欲上頻搔首。"]'),
('1d18ffb0-9781-4cb1-9bc4-9e06da4b0539','丈亭遇老人長眉及肩欲就之語忽已張帆吹笛而去','陸游','宋','宋诗','song-poetry','','[]','颯颯長眉緑覆肩，欲推壽數意茫然。',64,'全唐诗/poet.song.129000.json','["颯颯長眉緑覆肩，欲推壽數意茫然。", "若非楚國庚寅歲，定是堯時丙子年。", "銅笛一聲驚宿鷺，蒲帆數幅破晴烟。", "遥知乘醉江湖去，黄鶴樓頭又放顛。"]'),
('6501bb27-56b0-4fdf-9c4a-5baa0bce6d07','寓舍聞禽聲','陸游','宋','宋诗','song-poetry','','[]','日暖林梢鵯鵊鳴，稻陂無處不青青。',32,'全唐诗/poet.song.129000.json','["日暖林梢鵯鵊鳴，稻陂無處不青青。", "老農睡足猶慵起，支枕東窗盡意聽。"]'),
('9dbe0ae9-92b5-4258-a111-656102f9ca52','春晚','陸游','宋','宋诗','song-poetry','','[]','雨足人家插稻秧，蠶生鄰女采桑黄。',64,'全唐诗/poet.song.129000.json','["雨足人家插稻秧，蠶生鄰女采桑黄。", "萬花掃迹春將暮，百草吹香日正長。", "閑覓啼鶯穿北崦，戲隨飛蝶過東岡。", "飄然且喜身彊健，不怪兒曹笑老狂。"]'),
('53ecb1b0-20d7-417a-8eda-f8376b5d5a4e','題瑩師釣臺圖','陸游','宋','宋诗','song-poetry','','[]','羊裘老子釣魚處，開卷令人雙眼明。',32,'全唐诗/poet.song.129000.json','["羊裘老子釣魚處，開卷令人雙眼明。", "未可怱怱便持去，夜窗吾欲聽灘聲。"]'),
('a3ce85f2-5df2-48fe-adba-7606a5d7e37d','仗錫平老具舟車迎前天衣印老印悉遣還策杖訪之作二絕句奉送兼簡平  其一','陸游','宋','宋诗','song-poetry','','[]','畫舫籃輿不許前，白頭行脚意超然。',32,'全唐诗/poet.song.129000.json','["畫舫籃輿不許前，白頭行脚意超然。", "舜江禹穴千山水，盡在高人拄杖邊。"]'),
('bc75f028-1a3d-43b0-b683-00cf8324594b','仗錫平老具舟車迎前天衣印老印悉遣還策杖訪之作二絕句奉送兼簡平  其二','陸游','宋','宋诗','song-poetry','','[]','魚鼓聲中白氎巾，南山筍蕨一番新。',32,'全唐诗/poet.song.129000.json','["魚鼓聲中白氎巾，南山筍蕨一番新。", "長安不是無卿相，林下平津獨可人。"]'),
('6d0ad419-99b8-44f0-ae6e-a2ce88c4cd3a','湖邊曉行','陸游','宋','宋诗','song-poetry','','[]','蹇驢清曉掠湖堤，緩轡迎涼帽影低。',64,'全唐诗/poet.song.129000.json','["蹇驢清曉掠湖堤，緩轡迎涼帽影低。", "露拆渚蓮紅漸閙，雨催陂稻緑初齊。", "先秋葉已時時墮，失旦雞猶續續啼。", "不是老来忘睡美，戴星南畝慣扶犁。"]'),
('d7f19a01-392b-422f-9079-60ce3349fd5f','久雨杜門遣懷','陸游','宋','宋诗','song-poetry','','[]','風雨蕭蕭臥掩關，經旬登覽負溪山。',64,'全唐诗/poet.song.129000.json','["風雨蕭蕭臥掩關，經旬登覽負溪山。", "也知解送豐年喜，無奈難消永日閑。", "平野横吹看凌厲，畫簷高瀉聽淙潺。", "城闉路斷吾何恨，濁酒枯魚亦破顔。"]'),
('b358bff3-8c74-4a03-8280-a3b649bce7e2','梅雨陂澤皆滿','陸游','宋','宋诗','song-poetry','','[]','雨暗迷行路，溪深沒舊痕。',48,'全唐诗/poet.song.129000.json','["雨暗迷行路，溪深沒舊痕。", "汪汪牛湩白，盎盎酒醅渾。", "暖浸千畦稻，横通十里村。", "群蛙更堪笑，鼓吹鬧黄昏。"]'),
('38368911-7061-4e56-8cd1-50fc26b3c1d4','夜意二首  其一','陸游','宋','宋诗','song-poetry','','[]','幌外燈青見鼠行，林梢月黑有梟鳴。',32,'全唐诗/poet.song.129000.json','["幌外燈青見鼠行，林梢月黑有梟鳴。", "只言中夏夜偏短，萬里夢回天未明。"]'),
('1a5feb5b-bd81-429e-b823-d348cdf6a264','夜意二首  其二','陸游','宋','宋诗','song-poetry','','[]','睡覺鄰雞已再啼，蓬窗燈暗雨凄凄。',32,'全唐诗/poet.song.129000.json','["睡覺鄰雞已再啼，蓬窗燈暗雨凄凄。", "東家蹇驢不用借，明日門前一尺泥。"]'),
('6727abef-c3c1-4b08-811f-ab05a2132316','幽事','陸游','宋','宋诗','song-poetry','','[]','老境俗緣減，閑居幽事多。',48,'全唐诗/poet.song.129000.json','["老境俗緣減，閑居幽事多。", "去沙通斷澗，插援護新荷。", "棋罷看山臥，釣歸揺檝歌。", "餘年端有幾，風月且婆娑。"]'),
('578e65c3-d7eb-4b5a-ab59-5b0344513dad','對酒戲作','陸游','宋','宋诗','song-poetry','','[]','去日奔輪不啻過，凌烟勲業已蹉跎。',64,'全唐诗/poet.song.129000.json','["去日奔輪不啻過，凌烟勲業已蹉跎。", "只言一寸丹心在，無奈千莖白髮何。", "色比鵝雛京口酒，聲如珠貫渭城歌。", "身閑取醉真當勉，莫學癡人夢螘窠。"]'),
('e16610ff-c0e7-480a-bf66-4bb4c5d97682','夏雨','陸游','宋','宋诗','song-poetry','','[]','清風起湖濱，急雨来天末。',48,'全唐诗/poet.song.129000.json','["清風起湖濱，急雨来天末。", "蚊蠅遽退聽，松竹例蘇活。", "奇聲集空庭，爽氣生細葛。", "素秋雖尚遥，聊喜寛肺渇。"]'),
('4d12321b-89e2-4d56-89e1-b0ea69b80f20','軍中雜歌八首  其一','陸游','宋','宋诗','song-poetry','','[]','三受降城無壅城，賊来殺盡始還營。',32,'全唐诗/poet.song.129000.json','["三受降城無壅城，賊来殺盡始還營。", "漠南漠北靜如掃，清夜不聞胡馬聲。"]'),
('f98a09c6-2d66-4636-85b8-66514d368a14','軍中雜歌八首  其二','陸游','宋','宋诗','song-poetry','','[]','秦人萬里築長城，不如壯士守北平。',32,'全唐诗/poet.song.129000.json','["秦人萬里築長城，不如壯士守北平。", "曉来磧中雪一丈，洗盡烟塵春草生。"]'),
('1dd8b7d3-e23a-476d-8e1a-22f0d26fabee','軍中雜歌八首  其三','陸游','宋','宋诗','song-poetry','','[]','匈奴莫復倚長戈，来欵軍門早乞和。',32,'全唐诗/poet.song.129000.json','["匈奴莫復倚長戈，来欵軍門早乞和。", "鐵騎如山尚可避，飛將軍来汝奈何。"]'),
('6c2bae05-4f0e-4c30-8814-3aae97ac50d1','軍中雜歌八首  其四','陸游','宋','宋诗','song-poetry','','[]','名王金冠玉蹀躞，面縳纛下聲呱呱。',32,'全唐诗/poet.song.129000.json','["名王金冠玉蹀躞，面縳纛下聲呱呱。", "稿街未遽要汝首，賣與酒家鉗作奴。"]'),
('a8f998ca-1561-4179-a783-e117895c8f3d','軍中雜歌八首  其五','陸游','宋','宋诗','song-poetry','','[]','三月未春冰塞川，冬月苦寒雪闇天。',32,'全唐诗/poet.song.129000.json','["三月未春冰塞川，冬月苦寒雪闇天。", "紫髯將軍曉射虎，嚇殺胡兒箭似椽。"]'),
('5ce7eb89-cb92-41e2-b31e-3ceae940c451','軍中雜歌八首  其六','陸游','宋','宋诗','song-poetry','','[]','北面行臺號令新，繡旗豹尾渡河津。',32,'全唐诗/poet.song.129000.json','["北面行臺號令新，繡旗豹尾渡河津。", "檄書纔下降書至，不用兒郎打女真。"]'),
('264d1717-b3a6-4c18-9df1-c6b7c9c5faed','軍中雜歌八首  其七','陸游','宋','宋诗','song-poetry','','[]','漁陽兒女美如花，春風樓上學琵琶。',32,'全唐诗/poet.song.129000.json','["漁陽兒女美如花，春風樓上學琵琶。", "如今便死知無恨，不屬番家屬漢家。"]');
